def load_local_env() -> None:
    """Load workspace .env files without overriding the live Codex environment."""

    for env_path in (ROOT / ".env.local", ROOT / ".env"):
        if not env_path.exists():
            continue
        for raw_line in env_path.read_text(encoding="utf-8", errors="replace").splitlines():
            line = raw_line.strip()
            if not line or line.startswith("#") or "=" not in line:
                continue
            key, value = line.split("=", 1)
            key = key.strip()
            if not key:
                continue
            value = value.strip().strip('"').strip("'")
            if not value:
                continue
            if key in os.environ and os.environ.get(key, "").strip():
                continue
            os.environ[key] = value


load_local_env()


def apply_public_provider_aliases() -> None:
    """Map public OpenAI-compatible env names onto the default route.

    Historical local installs still use provider-specific variable names. The
    clean public setup can use GAOTAI_* or OPENAI_COMPAT_* without changing the
    rest of the server internals.
    """

    aliases = {
        "DEEPSEEK_API_KEY": ("GAOTAI_API_KEY", "OPENAI_COMPAT_API_KEY", "MODEL_API_KEY"),
        "DEEPSEEK_BASE_URL": ("GAOTAI_BASE_URL", "OPENAI_COMPAT_BASE_URL", "MODEL_BASE_URL"),
        "DEEPSEEK_MODEL": ("GAOTAI_MODEL", "OPENAI_COMPAT_MODEL", "MODEL_NAME"),
        "DEEPSEEK_THINKING": ("GAOTAI_THINKING", "OPENAI_COMPAT_THINKING"),
        "DEEPSEEK_REASONING_EFFORT": ("GAOTAI_REASONING_EFFORT", "OPENAI_COMPAT_REASONING_EFFORT"),
        "DEEPSEEK_REWRITE_MODEL": ("GAOTAI_REWRITE_MODEL", "OPENAI_COMPAT_REWRITE_MODEL"),
        "DEEPSEEK_REWRITE_THINKING": ("GAOTAI_REWRITE_THINKING", "OPENAI_COMPAT_REWRITE_THINKING"),
        "DEEPSEEK_REWRITE_REASONING_EFFORT": (
            "GAOTAI_REWRITE_REASONING_EFFORT",
            "OPENAI_COMPAT_REWRITE_REASONING_EFFORT",
        ),
        "DEEPSEEK_SUPPORT_THINKING": ("GAOTAI_SUPPORT_THINKING", "OPENAI_COMPAT_SUPPORT_THINKING"),
        "DEEPSEEK_SUPPORT_REASONING_EFFORT": (
            "GAOTAI_SUPPORT_REASONING_EFFORT",
            "OPENAI_COMPAT_SUPPORT_REASONING_EFFORT",
        ),
        "DEEPSEEK_REVIEW_THINKING": ("GAOTAI_REVIEW_THINKING", "OPENAI_COMPAT_REVIEW_THINKING"),
        "DEEPSEEK_REVIEW_REASONING_EFFORT": (
            "GAOTAI_REVIEW_REASONING_EFFORT",
            "OPENAI_COMPAT_REVIEW_REASONING_EFFORT",
        ),
    }
    for target, sources in aliases.items():
        if os.environ.get(target, "").strip():
            continue
        for source in sources:
            value = os.environ.get(source, "").strip()
            if value:
                os.environ[target] = value
                break


apply_public_provider_aliases()

