def log_ai_latency(
    *,
    lane: str,
    provider: str,
    model: str,
    thinking: str = "",
    timeout_seconds: int | float | None = None,
    started_at: float,
    status: str,
    error: str = "",
    extra: dict[str, Any] | None = None,
) -> None:
    """Record model-call latency for debugging perceived AI connection speed."""

    try:
        elapsed_ms = int((time.monotonic() - started_at) * 1000)
        record: dict[str, Any] = {
            "ts": utc_now(),
            "lane": lane,
            "provider": provider,
            "model": model,
            "thinking": thinking,
            "timeoutSeconds": timeout_seconds,
            "elapsedMs": elapsed_ms,
            "status": status,
        }
        if error:
            record["error"] = error[:500]
        if extra:
            record["extra"] = extra
        AI_LATENCY_LOG.parent.mkdir(parents=True, exist_ok=True)
        with AI_LATENCY_LOG_LOCK:
            with AI_LATENCY_LOG.open("a", encoding="utf-8") as handle:
                handle.write(json.dumps(record, ensure_ascii=False) + "\n")
    except Exception:
        return


