def utc_now() -> str:
    return dt.datetime.now(dt.timezone.utc).replace(microsecond=0).isoformat()


def send_cors_headers(handler: BaseHTTPRequestHandler) -> None:
    handler.send_header("Access-Control-Allow-Origin", "*")
    handler.send_header("Access-Control-Allow-Methods", "GET, POST, HEAD, OPTIONS")
    handler.send_header("Access-Control-Allow-Headers", "Content-Type")


def json_response(handler: BaseHTTPRequestHandler, status: int, payload: dict[str, Any] | list[Any]) -> None:
    body = json.dumps(payload, ensure_ascii=False, indent=2).encode("utf-8")
    try:
        handler.send_response(status)
        send_cors_headers(handler)
        handler.send_header("Content-Type", "application/json; charset=utf-8")
        handler.send_header("Cache-Control", "no-store")
        handler.send_header("Content-Length", str(len(body)))
        handler.end_headers()
        handler.wfile.write(body)
    except (BrokenPipeError, ConnectionResetError):
        return


def update_full_draft_job(job_id: str, **updates: Any) -> None:
    with FULL_DRAFT_JOBS_LOCK:
        job = FULL_DRAFT_JOBS.setdefault(job_id, {})
        job.update(updates)
        job["updatedAt"] = utc_now()


def read_full_draft_job(job_id: str) -> dict[str, Any]:
    with FULL_DRAFT_JOBS_LOCK:
        job = FULL_DRAFT_JOBS.get(job_id)
        if not job:
            raise FileNotFoundError(f"job not found: {job_id}")
        if job.get("status") in {"queued", "running"}:
            timeout_seconds = int(os.environ.get("FULL_DRAFT_JOB_TIMEOUT_SECONDS", str(DEFAULT_FULL_DRAFT_JOB_TIMEOUT_SECONDS)))
            timestamp = str(job.get("startedAt") or job.get("createdAt") or "")
            try:
                started_at = dt.datetime.fromisoformat(timestamp)
                if started_at.tzinfo is None:
                    started_at = started_at.replace(tzinfo=dt.timezone.utc)
                age = (dt.datetime.now(dt.timezone.utc) - started_at).total_seconds()
            except Exception:
                age = 0
            if age > timeout_seconds:
                job.update(
                    status="error",
                    error=f"全文生成超过 {timeout_seconds} 秒，已停止前端等待。请重试或缩短材料。",
                    finishedAt=utc_now(),
                    updatedAt=utc_now(),
                )
        return dict(job)


def update_final_review_job(job_id: str, **updates: Any) -> None:
    with FINAL_REVIEW_JOBS_LOCK:
        job = FINAL_REVIEW_JOBS.setdefault(job_id, {})
        job.update(updates)
        job["updatedAt"] = utc_now()


def read_final_review_job(job_id: str) -> dict[str, Any]:
    with FINAL_REVIEW_JOBS_LOCK:
        job = FINAL_REVIEW_JOBS.get(job_id)
        if not job:
            raise FileNotFoundError(f"job not found: {job_id}")
        if job.get("status") in {"queued", "running"}:
            timeout_seconds = int(os.environ.get("FINAL_REVIEW_JOB_TIMEOUT_SECONDS", str(DEFAULT_FINAL_REVIEW_JOB_TIMEOUT_SECONDS)))
            timestamp = str(job.get("startedAt") or job.get("createdAt") or "")
            try:
                started_at = dt.datetime.fromisoformat(timestamp)
                if started_at.tzinfo is None:
                    started_at = started_at.replace(tzinfo=dt.timezone.utc)
                age = (dt.datetime.now(dt.timezone.utc) - started_at).total_seconds()
            except Exception:
                age = 0
            if age > timeout_seconds:
                job.update(
                    status="error",
                    error=f"Codex 收稿超过 {timeout_seconds} 秒，已停止前端等待。可以稍后重试或先缩短正文。",
                    finishedAt=utc_now(),
                    updatedAt=utc_now(),
                )
        return dict(job)


def start_full_draft_job(payload: dict[str, Any], *, host: str, port: int) -> dict[str, Any]:
    job_id = f"full_draft_{dt.datetime.now().strftime('%Y%m%d_%H%M%S')}_{uuid.uuid4().hex[:8]}"
    update_full_draft_job(
        job_id,
        jobId=job_id,
        status="queued",
        createdAt=utc_now(),
        title=normalize_space(str(payload.get("title", ""))) or "未命名稿件",
        result=None,
        error="",
    )

    def worker() -> None:
        update_full_draft_job(job_id, status="running", startedAt=utc_now())
        request_payload = dict(payload)
        request_payload["deferCodexGate"] = True
        request_payload["jobId"] = job_id
        body = json.dumps(request_payload, ensure_ascii=False).encode("utf-8")
        request = urllib_request.Request(
            f"http://{host}:{port}/api/full-draft",
            data=body,
            headers={"Content-Type": "application/json"},
            method="POST",
        )
        try:
            timeout_seconds = int(os.environ.get("FULL_DRAFT_JOB_TIMEOUT_SECONDS", str(DEFAULT_FULL_DRAFT_JOB_TIMEOUT_SECONDS)))
            with urllib_request.urlopen(request, timeout=timeout_seconds) as response:
                result = json.loads(response.read().decode("utf-8"))
            update_full_draft_job(
                job_id,
                status="done",
                finishedAt=utc_now(),
                result=result,
                codexGateStatus=((result.get("codexGate") or {}).get("status") if isinstance(result, dict) else ""),
            )
            if (
                isinstance(result, dict)
                and normalize_space(str((result.get("codexGate") or {}).get("status") or "")) == "pending"
                and normalize_space(str((result.get("qualityGate") or {}).get("status") or "")) == "allow"
            ):
                threading.Thread(
                    target=finalize_deferred_codex_gate,
                    args=(result,),
                    kwargs={"job_id": job_id},
                    name=f"codex-gate-{job_id}",
                    daemon=True,
                ).start()
        except urllib_error.HTTPError as exc:
            detail = exc.read().decode("utf-8", errors="replace")[:1200]
            update_full_draft_job(job_id, status="error", finishedAt=utc_now(), error=f"HTTP {exc.code}: {detail}")
        except Exception as exc:
            update_full_draft_job(job_id, status="error", finishedAt=utc_now(), error=str(exc))

    threading.Thread(target=worker, name=f"full-draft-job-{job_id}", daemon=True).start()
    return read_full_draft_job(job_id)


def start_final_review_job(payload: dict[str, Any], style_store: StyleMemoryStore) -> dict[str, Any]:
    title = normalize_space(str(payload.get("title", ""))) or "未命名稿件"
    body = str(payload.get("body", "")).strip()
    if not body:
        raise ValueError("body is required")
    job_id = f"final_review_{dt.datetime.now().strftime('%Y%m%d_%H%M%S')}_{uuid.uuid4().hex[:8]}"
    update_final_review_job(
        job_id,
        jobId=job_id,
        status="queued",
        createdAt=utc_now(),
        title=title,
        result=None,
        error="",
    )

    def worker() -> None:
        update_final_review_job(job_id, status="running", startedAt=utc_now())
        try:
            codex_timeout = int(os.environ.get("FINAL_REVIEW_JOB_CODEX_TIMEOUT_SECONDS", "600"))
            result = final_review(title, body, style_store, codex_timeout=codex_timeout)
            update_final_review_job(
                job_id,
                status="done",
                finishedAt=utc_now(),
                result=result,
                codexReview=result.get("codexReview") if isinstance(result, dict) else None,
            )
        except Exception as exc:
            update_final_review_job(job_id, status="error", finishedAt=utc_now(), error=str(exc)[:1200])

    threading.Thread(target=worker, name=f"final-review-job-{job_id}", daemon=True).start()
    return read_final_review_job(job_id)


def text_response(handler: BaseHTTPRequestHandler, status: int, body: bytes, content_type: str) -> None:
    try:
        handler.send_response(status)
        send_cors_headers(handler)
        handler.send_header("Content-Type", content_type)
        handler.send_header("Cache-Control", "no-store")
        handler.send_header("Content-Length", str(len(body)))
        handler.end_headers()
        handler.wfile.write(body)
    except (BrokenPipeError, ConnectionResetError):
        return


def binary_response(
    handler: BaseHTTPRequestHandler,
    status: int,
    body: bytes,
    content_type: str,
    *,
    filename: str = "download.bin",
) -> None:
    try:
        safe_name = re.sub(r"[\r\n/\\]+", "-", normalize_space(filename) or "download.bin")
        handler.send_response(status)
        send_cors_headers(handler)
        handler.send_header("Content-Type", content_type)
        handler.send_header("Cache-Control", "no-store")
        ascii_name = safe_name.encode("ascii", errors="ignore").decode("ascii") or "download.bin"
        handler.send_header("Content-Disposition", f"attachment; filename=\"{ascii_name}\"; filename*=UTF-8''{quote(safe_name)}")
        handler.send_header("Content-Length", str(len(body)))
        handler.end_headers()
        handler.wfile.write(body)
    except (BrokenPipeError, ConnectionResetError):
        return


def inline_file_response(
    handler: BaseHTTPRequestHandler,
    status: int,
    body: bytes,
    content_type: str,
    *,
    filename: str,
    disposition: str = "inline",
) -> None:
    try:
        safe_name = re.sub(r"[\r\n/\\]+", "-", normalize_space(filename) or "download.bin")
        disposition_type = "attachment" if disposition == "attachment" else "inline"
        handler.send_response(status)
        send_cors_headers(handler)
        handler.send_header("Content-Type", content_type)
        handler.send_header("Cache-Control", "no-store")
        ascii_name = safe_name.encode("ascii", errors="ignore").decode("ascii") or "download.bin"
        handler.send_header("Content-Disposition", f"{disposition_type}; filename=\"{ascii_name}\"; filename*=UTF-8''{quote(safe_name)}")
        handler.send_header("Content-Length", str(len(body)))
        handler.end_headers()
        handler.wfile.write(body)
    except (BrokenPipeError, ConnectionResetError):
        return


def static_file_for_path(request_path: str) -> tuple[Path, Path] | None:
    if request_path in {"/video-analysis", "/video-analysis/"}:
        return STATIC_VIDEO_DIR / "index.html", STATIC_VIDEO_DIR
    if request_path.startswith("/video-analysis/"):
        return STATIC_VIDEO_DIR / request_path.removeprefix("/video-analysis/"), STATIC_VIDEO_DIR
    if request_path in {"/", "/index.html"}:
        return STATIC_V2_DIR / "index.html", STATIC_V2_DIR
    if request_path in {"/app.js", "/styles.css"}:
        return STATIC_V2_DIR / request_path.lstrip("/"), STATIC_V2_DIR
    if request_path in {"/v2", "/v2/"}:
        return STATIC_V2_DIR / "index.html", STATIC_V2_DIR
    if request_path.startswith("/v2/"):
        return STATIC_V2_DIR / request_path.removeprefix("/v2/"), STATIC_V2_DIR
    path = "/index.html" if request_path == "/" else request_path
    return STATIC_DIR / path.lstrip("/"), STATIC_DIR


def static_content_type(file_path: Path) -> str:
    if file_path.suffix == ".html":
        return "text/html; charset=utf-8"
    if file_path.suffix == ".css":
        return "text/css; charset=utf-8"
    if file_path.suffix == ".js":
        return "application/javascript; charset=utf-8"
    if file_path.suffix == ".svg":
        return "image/svg+xml"
    if file_path.suffix.lower() in {".jpg", ".jpeg"}:
        return "image/jpeg"
    if file_path.suffix.lower() == ".png":
        return "image/png"
    if file_path.suffix.lower() == ".webp":
        return "image/webp"
    if file_path.suffix.lower() == ".mp4":
        return "video/mp4"
    if file_path.suffix.lower() == ".webm":
        return "video/webm"
    if file_path.suffix.lower() == ".mov":
        return "video/quicktime"
    if file_path.suffix.lower() == ".m4a":
        return "audio/mp4"
    if file_path.suffix.lower() == ".mp3":
        return "audio/mpeg"
    if file_path.suffix.lower() == ".json":
        return "application/json; charset=utf-8"
    if file_path.suffix.lower() in {".md", ".txt", ".vtt"}:
        return "text/plain; charset=utf-8"
    return "text/plain; charset=utf-8"


def read_json(handler: BaseHTTPRequestHandler) -> dict[str, Any]:
    length = int(handler.headers.get("Content-Length", "0"))
    raw = handler.rfile.read(length) if length else b"{}"
    if not raw.strip():
        return {}
    try:
        data = json.loads(raw.decode("utf-8"))
    except json.JSONDecodeError as exc:
        raise ValueError(f"invalid JSON: {exc}") from exc
    if not isinstance(data, dict):
        raise ValueError("JSON body must be an object")
    return data


def normalize_space(value: str) -> str:
    return re.sub(r"\s+", " ", value).strip()


def normalize_video_analysis_tenant_id(value: str) -> str:
    cleaned = re.sub(r"[^a-zA-Z0-9_-]+", "-", normalize_space(str(value or ""))).strip("-").lower()
    return (cleaned[:64] or DEFAULT_VIDEO_ANALYSIS_TENANT_ID)


def slugify(value: str, fallback: str = "untitled") -> str:
    cleaned = re.sub(r"[^\w\u4e00-\u9fff-]+", "-", str(value).strip().lower())
    cleaned = re.sub(r"-{2,}", "-", cleaned).strip("-")
    return cleaned or fallback


def normalize_inline_punctuation(value: str) -> str:
    value = normalize_space(value)
    value = value.replace("哪。里", "哪里")
    value = value.replace("哪.里", "哪里")
    value = value.replace("生大纲", "生成大纲")
    value = re.sub(r"([。！？!?])\1+", r"\1", value)
    value = re.sub(r"，([。！？!?])", r"\1", value)
    return value


def ensure_document_dirs() -> None:
    DOCUMENT_DIR.mkdir(parents=True, exist_ok=True)
