def demo_deck_has_missing_source_quotes(deck: dict[str, Any]) -> bool:
    if not isinstance(deck, dict):
        return False
    if deck.get("evidenceMode") == "visual-only":
        return False
    slides = deck.get("slides") if isinstance(deck.get("slides"), list) else []
    return bool(
        slides
        and any(
            isinstance(slide, dict)
            and not normalize_space(str(slide.get("sourceQuote") or ""))
            for slide in slides
        )
    )


def demo_deck_uses_stale_public_talk_template(deck: dict[str, Any], source_text: str) -> bool:
    if not isinstance(deck, dict) or not public_talk_video_context(source_text):
        return False
    slides = deck.get("slides") if isinstance(deck.get("slides"), list) else []
    combined = normalize_space(
        " ".join(
            str(slide.get(key) or "")
            for slide in slides
            if isinstance(slide, dict)
            for key in ("title", "role", "action", "meaning", "speakerNote", "productDimension", "productQuestion", "productAnswer")
        )
    )
    return bool(
        re.search(
            r"模型进步|产品是什么|谁会用|跑通证据|工程入口|CLAUDE|终端|先抛出问题|别和模型进步硬拼|"
            r"这段有可回看的证据|先看证据|拿出证据|继续看证据|补充证据|补一条证据",
            combined,
            re.I,
        )
    )


def demo_deck_has_stale_template_copy(deck: dict[str, Any]) -> bool:
    if not isinstance(deck, dict):
        return False
    slides = deck.get("slides") if isinstance(deck.get("slides"), list) else []
    return any(
        isinstance(slide, dict)
        and any(
            generic_video_slide_text(str(slide.get(key) or ""))
            for key in (
                "title",
                "role",
                "action",
                "meaning",
                "speakerNote",
                "proof",
                "audienceTakeaway",
                "productDimension",
                "productQuestion",
                "productAnswer",
            )
        )
        for slide in slides
    )


def mark_stale_video_job(record: dict[str, Any], *, now: dt.datetime | None = None, timeout_seconds: int | None = None) -> tuple[dict[str, Any], bool]:
    if record.get("status") not in {"queued", "running"}:
        return record, False
    timeout = int(timeout_seconds or os.environ.get("VIDEO_ANALYSIS_JOB_TIMEOUT_SECONDS", str(DEFAULT_VIDEO_ANALYSIS_JOB_TIMEOUT_SECONDS)))
    timestamp = str(record.get("startedAt") or record.get("createdAt") or record.get("updatedAt") or "")
    try:
        started_at = dt.datetime.fromisoformat(timestamp)
        if started_at.tzinfo is None:
            started_at = started_at.replace(tzinfo=dt.timezone.utc)
        current = now or dt.datetime.now(dt.timezone.utc)
        age = (current - started_at).total_seconds()
    except Exception:
        return record, False
    if age <= timeout:
        return record, False

    stale = dict(record)
    stale["status"] = "error"
    stale["stage"] = "timeout"
    stale["message"] = f"下载或分析超过 {timeout} 秒，已停止等待。可以重跑，或换一个公开视频链接。"
    stale["error"] = stale["message"]
    stale["failure"] = build_video_failure_diagnosis(
        url=str(stale.get("url") or ""),
        message=stale["message"],
        error=stale["error"],
        kind="timeout",
        cookies_from_browser=str(stale.get("cookiesFromBrowser") or ""),
    )
    stale["finishedAt"] = utc_now()
    stale["updatedAt"] = utc_now()
    stale.setdefault("events", []).append({"at": utc_now(), "stage": "timeout", "message": stale["message"], "extra": {"timeoutSeconds": timeout}})
    return stale, True


def read_video_job(job_id: str) -> dict[str, Any]:
    path = video_job_path(job_id)
    if not path.exists():
        raise FileNotFoundError(f"video job not found: {job_id}")
    stat = path.stat()
    record = json.loads(path.read_text(encoding="utf-8"))
    record, stale_changed = mark_stale_video_job(record)
    if record.get("status") == "error" and not isinstance(record.get("failure"), dict):
        record["failure"] = build_video_failure_diagnosis(
            url=str(record.get("url") or ""),
            message=str(record.get("message") or ""),
            error=str(record.get("error") or ""),
            cookies_from_browser=str(record.get("cookiesFromBrowser") or ""),
        )
        stale_changed = True
    if stale_changed:
        if record.get("status") == "error" and record.get("stage") == "timeout" and record.get("requireLocalVideo"):
            previous = previous_complete_video_job_for_url(str(record.get("url") or ""), job_id)
            if previous:
                try:
                    record = build_cached_video_job_record_from_previous(
                        record,
                        previous,
                        reason=str(record.get("error") or record.get("message") or ""),
                        cookies_from_browser=str(record.get("cookiesFromBrowser") or ""),
                        event_message="下载超时，已复用本地缓存",
                    )
                except Exception:
                    pass
        write_video_job(job_id, record)
        return record
    fast_summary = record.get("summary") if isinstance(record.get("summary"), dict) else {}
    fast_result = record.get("result") if isinstance(record.get("result"), dict) else {}
    fast_result_segments = fast_result.get("transcript_segments") if isinstance(fast_result.get("transcript_segments"), list) else []
    fast_summary_segments = fast_summary.get("transcriptSegments") if isinstance(fast_summary.get("transcriptSegments"), list) else []
    fast_missing_summary_transcript_segments = bool(fast_result_segments and not fast_summary_segments)
    fast_transcript = normalize_space(str(fast_summary.get("transcriptSource") or record.get("transcriptSource") or record.get("transcript_source") or ""))
    fast_timeline = fast_summary.get("timeline") if isinstance(fast_summary.get("timeline"), list) else []
    fast_demo = fast_summary.get("demoDeck") if isinstance(fast_summary.get("demoDeck"), dict) else {}
    fast_demo_slides = fast_demo.get("slides") if isinstance(fast_demo.get("slides"), list) else []
    fast_evidence = fast_demo.get("evidenceStatus") if isinstance(fast_demo.get("evidenceStatus"), dict) else {}
    fast_quality = fast_demo.get("demoDeckQuality") if isinstance(fast_demo.get("demoDeckQuality"), dict) else {}
    fast_quality_issues = " ".join(str(item) for item in fast_quality.get("issues") or [])
    fast_quality_missing_insights = {
        normalize_space(str(item)) for item in (fast_quality.get("missingProductInsights") or [])
    }
    fast_missing_slide_source_quotes = bool(
        demo_deck_has_missing_source_quotes(fast_demo)
    )
    fast_public_talk_source = normalize_space(
        " ".join(
            str(part or "")
            for part in (
                record.get("title"),
                (record.get("result") or {}).get("title") if isinstance(record.get("result"), dict) else "",
                fast_summary.get("coreClaim"),
                " ".join(
                    str(item.get(key) or "")
                    for item in fast_timeline
                    if isinstance(item, dict)
                    for key in ("summary", "transcriptExcerpt", "quoteCandidate")
                ),
            )
        )
    )
    fast_stale_public_talk_template = demo_deck_uses_stale_public_talk_template(fast_demo, fast_public_talk_source)
    try:
        fast_unique_screenshots = int(fast_evidence.get("uniqueScreenshots") or 0)
    except (TypeError, ValueError):
        fast_unique_screenshots = 0
    fast_has_timeline_frame = any(
        isinstance(item, dict) and bool(normalize_space(str(item.get("frameUrl") or "")))
        for item in fast_timeline
    )
    fast_video_summary = fast_summary.get("videoSummary") if isinstance(fast_summary.get("videoSummary"), dict) else {}
    fast_headline = normalize_space(str(fast_video_summary.get("headline") or fast_summary.get("coreClaim") or ""))
    fast_download_policy = fast_summary.get("downloadPolicy") if isinstance(fast_summary.get("downloadPolicy"), dict) else {}
    fast_video_embed = fast_summary.get("videoEmbed") if isinstance(fast_summary.get("videoEmbed"), dict) else {}
    fast_cached_local_video = bool(
        fast_download_policy.get("status") == "cached"
        and fast_video_embed.get("type") == "local"
        and normalize_space(str(fast_video_embed.get("src") or ""))
    )
    fast_missing_timeline_frames = bool(
        fast_timeline
        and not fast_has_timeline_frame
    )
    fast_demo_missing_template = bool(fast_demo and not fast_demo.get("templateLabel"))
    fast_weak_demo_evidence = bool(
        fast_demo
        and fast_evidence
        and not fast_evidence.get("ready")
        and fast_unique_screenshots <= 0
    )
    fast_stale_video_pack = bool(
        int(fast_summary.get("videoTimelineVersion") or 0) < VIDEO_TIMELINE_VERSION
        or int(fast_summary.get("videoSummaryVersion") or 0) < VIDEO_SUMMARY_VERSION
        or int(fast_summary.get("demoDeckVersion") or 0) < DEMO_DECK_VERSION
        or fast_demo_missing_template
        or fast_missing_slide_source_quotes
        or demo_deck_has_stale_template_copy(fast_demo)
        or fast_stale_public_talk_template
        or (fast_demo and "coveredProductInsights" not in fast_quality)
        or (fast_quality.get("status") == "ready" and "边界限制" in fast_quality_missing_insights)
        or bool(re.search(r"缺少可直接讲的一句话|缺少原字幕或画面证据|缺讲法|缺原始证据", fast_quality_issues))
        or generic_video_core_claim(fast_headline)
        or fast_missing_summary_transcript_segments
    )
    fast_needs_cached_fallback = bool(fast_stale_video_pack) or (False if fast_cached_local_video else (
        fast_transcript in {"", "none"}
        or fast_missing_timeline_frames
        or fast_weak_demo_evidence
        )
    )
    if (
        record.get("status") == "done"
        and fast_summary
        and not fast_needs_cached_fallback
        and os.environ.get("VIDEO_ANALYSIS_REFRESH_ON_READ") != "1"
    ):
        summary = record.get("summary") if isinstance(record.get("summary"), dict) else {}
        try:
            if record.get("requireLocalVideo"):
                require_local_video_embed(summary)
            acceptance_changed = maybe_enhance_video_summary_frames(summary)
            acceptance_changed = ensure_video_material_acceptance(summary) or acceptance_changed
            if normalize_required_video_source_status(summary):
                acceptance_changed = True
            if acceptance_changed:
                record["summary"] = summary
                write_video_job(job_id, record)
                os.utime(path, (stat.st_atime, stat.st_mtime))
        except Exception as exc:
            public_message = public_exception_message(exc)
            debug_message = debug_exception_message(exc)
            record["status"] = "error"
            record["stage"] = "error"
            record["message"] = public_message
            record["error"] = debug_message
            record["failure"] = build_video_failure_diagnosis(
                url=str(record.get("url") or ""),
                message=public_message,
                error=debug_message,
                cookies_from_browser=str(record.get("cookiesFromBrowser") or ""),
            )
            record["updatedAt"] = utc_now()
            record.setdefault("events", []).append({"at": utc_now(), "stage": "error", "message": public_message, "extra": {"reason": "download-required", "detail": debug_message}})
            write_video_job(job_id, record)
            os.utime(path, (stat.st_atime, stat.st_mtime))
        summary = record.get("summary") if isinstance(record.get("summary"), dict) else {}
        if sync_video_job_display_fields(record):
            write_video_job(job_id, record)
            os.utime(path, (stat.st_atime, stat.st_mtime))
        return record
    if record.get("status") == "done" and isinstance(record.get("result"), dict):
        summary = record.get("summary") if isinstance(record.get("summary"), dict) else {}
        pre_fallback_changed = False
        try:
            pre_fallback_before = json.dumps(
                {
                    "summary": record.get("summary"),
                    "transcriptMarkdown": record.get("transcriptMarkdown"),
                    "transcriptSource": record.get("transcriptSource"),
                    "timeline": record.get("timeline"),
                },
                ensure_ascii=False,
                sort_keys=True,
            )
            record = apply_cached_video_transcript_fallback(job_id, record)
            record = apply_cached_video_evidence_fallback(job_id, record)
            pre_fallback_after = json.dumps(
                {
                    "summary": record.get("summary"),
                    "transcriptMarkdown": record.get("transcriptMarkdown"),
                    "transcriptSource": record.get("transcriptSource"),
                    "timeline": record.get("timeline"),
                },
                ensure_ascii=False,
                sort_keys=True,
            )
            if pre_fallback_after != pre_fallback_before:
                pre_fallback_changed = True
                write_video_job(job_id, record)
                os.utime(path, (stat.st_atime, stat.st_mtime))
        except Exception:
            pass
        summary = record.get("summary") if isinstance(record.get("summary"), dict) else {}
        timeline = summary.get("timeline") if isinstance(summary.get("timeline"), list) else []
        demo_deck = summary.get("demoDeck") if isinstance(summary.get("demoDeck"), dict) else {}
        demo_slides = demo_deck.get("slides") if isinstance(demo_deck.get("slides"), list) else []
        demo_deck_needs_refresh = (
            not demo_deck
            or not demo_deck.get("evidenceStatus")
            or not demo_deck.get("templateLabel")
            or any(isinstance(slide, dict) and slide.get("frameUrl") and not slide.get("frameKind") for slide in demo_slides)
            or demo_deck_has_missing_source_quotes(demo_deck)
            or demo_deck_has_stale_template_copy(demo_deck)
            or demo_deck_uses_stale_public_talk_template(
                demo_deck,
                normalize_space(
                    " ".join(
                        str(part or "")
                        for part in (
                            record.get("title"),
                            (record.get("result") or {}).get("title") if isinstance(record.get("result"), dict) else "",
                            summary.get("coreClaim"),
                            " ".join(
                                str(item.get(key) or "")
                                for item in timeline
                                if isinstance(item, dict)
                                for key in ("summary", "transcriptExcerpt", "quoteCandidate")
                            ),
                        )
                    )
                ),
            )
        )
        current_deck_quality = demo_deck.get("demoDeckQuality") if isinstance(demo_deck.get("demoDeckQuality"), dict) else {}
        current_quality_issues = " ".join(str(item) for item in current_deck_quality.get("issues") or [])
        demo_deck_needs_quality_refresh = bool(
            re.search(r"缺少可直接讲的一句话|缺少原字幕或画面证据|缺讲法|缺原始证据", current_quality_issues)
        )
        current_video_summary = summary.get("videoSummary") if isinstance(summary.get("videoSummary"), dict) else {}
        current_headline = normalize_space(str(current_video_summary.get("headline") or summary.get("coreClaim") or ""))
        if (
            not summary.get("videoEmbed")
            or not timeline
            or len(timeline) > 8
            or int(summary.get("writingCardsVersion") or 0) < 3
            or int(summary.get("writingPackVersion") or 0) < 4
            or int(summary.get("videoTimelineVersion") or 0) < VIDEO_TIMELINE_VERSION
            or int(summary.get("videoSummaryVersion") or 0) < VIDEO_SUMMARY_VERSION
            or int(summary.get("demoDeckVersion") or 0) < DEMO_DECK_VERSION
            or (generic_video_core_claim(current_headline) and not pre_fallback_changed)
            or summary_has_machine_video_copy(summary)
        ):
            try:
                enriched = enrich_video_job_result(job_id, record["result"])
                if summary.get("downloadPolicy") and not enriched.get("downloadPolicy"):
                    enriched.pop("downloadPolicy", None)
                record["summary"] = preserve_local_video_material(summary, {**summary, **enriched})
                if enriched.get("sourcePackPath"):
                    record.setdefault("files", {})["source_pack_path"] = enriched["sourcePackPath"]
                write_video_job(job_id, record)
                os.utime(path, (stat.st_atime, stat.st_mtime))
            except Exception:
                pass
        try:
            fallback_before = json.dumps(
                {
                    "summary": record.get("summary"),
                    "transcriptMarkdown": record.get("transcriptMarkdown"),
                    "transcriptSource": record.get("transcriptSource"),
                    "timeline": record.get("timeline"),
                },
                ensure_ascii=False,
                sort_keys=True,
            )
            record = apply_cached_video_transcript_fallback(job_id, record)
            fallback_after = json.dumps(
                {
                    "summary": record.get("summary"),
                    "transcriptMarkdown": record.get("transcriptMarkdown"),
                    "transcriptSource": record.get("transcriptSource"),
                    "timeline": record.get("timeline"),
                },
                ensure_ascii=False,
                sort_keys=True,
            )
            if fallback_after != fallback_before:
                fallback_summary = record.get("summary") if isinstance(record.get("summary"), dict) else {}
                rebuilt = preserve_local_video_material(fallback_summary, rebuild_video_job_summary(job_id, record))
                for key in ("captionFiles", "sourcePackMarkdown", "sourcePackPath", "sourcePackUrl"):
                    value = fallback_summary.get(key)
                    if value and not rebuilt.get(key):
                        rebuilt[key] = value
                record["summary"] = rebuilt
                if rebuilt.get("sourcePackPath"):
                    record.setdefault("files", {})["source_pack_path"] = rebuilt["sourcePackPath"]
                write_video_job(job_id, record)
                os.utime(path, (stat.st_atime, stat.st_mtime))
        except Exception:
            pass
        try:
            evidence_before = json.dumps(
                {
                    "summary": record.get("summary"),
                    "timeline": record.get("timeline"),
                },
                ensure_ascii=False,
                sort_keys=True,
            )
            record = apply_cached_video_evidence_fallback(job_id, record)
            evidence_after = json.dumps(
                {
                    "summary": record.get("summary"),
                    "timeline": record.get("timeline"),
                },
                ensure_ascii=False,
                sort_keys=True,
            )
            if evidence_after != evidence_before:
                write_video_job(job_id, record)
                os.utime(path, (stat.st_atime, stat.st_mtime))
        except Exception:
            pass
        try:
            current_summary = record.get("summary") if isinstance(record.get("summary"), dict) else {}
            normalized_summary, assets_changed = normalize_video_summary_asset_urls(current_summary)
            if assets_changed:
                record["summary"] = normalized_summary
                write_video_job(job_id, record)
                os.utime(path, (stat.st_atime, stat.st_mtime))
        except Exception:
            pass
        try:
            current_summary = record.get("summary") if isinstance(record.get("summary"), dict) else {}
            if maybe_enhance_video_summary_frames(current_summary):
                record["summary"] = current_summary
                write_video_job(job_id, record)
                os.utime(path, (stat.st_atime, stat.st_mtime))
            acceptance_changed = ensure_video_material_acceptance(current_summary)
            if record.get("requireLocalVideo"):
                require_local_video_embed(current_summary)
            if normalize_required_video_source_status(current_summary):
                acceptance_changed = True
            if acceptance_changed:
                record["summary"] = current_summary
                write_video_job(job_id, record)
                os.utime(path, (stat.st_atime, stat.st_mtime))
        except Exception as exc:
            public_message = public_exception_message(exc)
            debug_message = debug_exception_message(exc)
            record["status"] = "error"
            record["stage"] = "error"
            record["message"] = public_message
            record["error"] = debug_message
            record["failure"] = build_video_failure_diagnosis(
                url=str(record.get("url") or ""),
                message=public_message,
                error=debug_message,
                cookies_from_browser=str(record.get("cookiesFromBrowser") or ""),
            )
            record["updatedAt"] = utc_now()
            record.setdefault("events", []).append({"at": utc_now(), "stage": "error", "message": public_message, "extra": {"reason": "download-required", "detail": debug_message}})
            write_video_job(job_id, record)
            os.utime(path, (stat.st_atime, stat.st_mtime))
    summary = record.get("summary") if isinstance(record.get("summary"), dict) else {}
    if summary:
        if maybe_enhance_video_summary_frames(summary):
            record["summary"] = summary
            write_video_job(job_id, record)
            os.utime(path, (stat.st_atime, stat.st_mtime))
        if ensure_video_material_acceptance(summary):
            record["summary"] = summary
            write_video_job(job_id, record)
            os.utime(path, (stat.st_atime, stat.st_mtime))
        if record.get("status") == "done" and record.get("requireLocalVideo"):
            try:
                require_local_video_embed(summary)
                if normalize_required_video_source_status(summary):
                    record["summary"] = summary
                    write_video_job(job_id, record)
                    os.utime(path, (stat.st_atime, stat.st_mtime))
            except Exception as exc:
                public_message = public_exception_message(exc)
                debug_message = debug_exception_message(exc)
                record["status"] = "error"
                record["stage"] = "error"
                record["message"] = public_message
                record["error"] = debug_message
                record["failure"] = build_video_failure_diagnosis(
                    url=str(record.get("url") or ""),
                    message=public_message,
                    error=debug_message,
                    cookies_from_browser=str(record.get("cookiesFromBrowser") or ""),
                )
                record["updatedAt"] = utc_now()
                record.setdefault("events", []).append({"at": utc_now(), "stage": "error", "message": public_message, "extra": {"reason": "download-required", "detail": debug_message}})
                write_video_job(job_id, record)
                os.utime(path, (stat.st_atime, stat.st_mtime))
        if sync_video_job_display_fields(record):
            write_video_job(job_id, record)
            os.utime(path, (stat.st_atime, stat.st_mtime))
    if record.get("status") == "done" and isinstance(record.get("result"), dict):
        current_summary = record.get("summary") if isinstance(record.get("summary"), dict) else {}
        if not current_summary:
            try:
                rebuilt = preserve_local_video_material(fallback_summary, rebuild_video_job_summary(job_id, record))
                record["summary"] = rebuilt
                if rebuilt.get("transcriptSegments") and record.get("transcript_segments") != rebuilt["transcriptSegments"]:
                    record["transcript_segments"] = rebuilt["transcriptSegments"]
                if rebuilt.get("sourcePackPath"):
                    record.setdefault("files", {})["source_pack_path"] = rebuilt["sourcePackPath"]
                sync_video_job_display_fields(record)
                write_video_job(job_id, record)
                os.utime(path, (stat.st_atime, stat.st_mtime))
                current_summary = record.get("summary") if isinstance(record.get("summary"), dict) else {}
            except Exception:
                current_summary = {}
        elif (record.get("result") or {}).get("transcript_segments") and not current_summary.get("transcriptSegments"):
            try:
                rebuilt = preserve_local_video_material(fallback_summary, rebuild_video_job_summary(job_id, record))
                record["summary"] = {**current_summary, **rebuilt}
                if rebuilt.get("transcriptSegments") and record.get("transcript_segments") != rebuilt["transcriptSegments"]:
                    record["transcript_segments"] = rebuilt["transcriptSegments"]
                if rebuilt.get("sourcePackPath"):
                    record.setdefault("files", {})["source_pack_path"] = rebuilt["sourcePackPath"]
                sync_video_job_display_fields(record)
                write_video_job(job_id, record)
                os.utime(path, (stat.st_atime, stat.st_mtime))
                current_summary = record.get("summary") if isinstance(record.get("summary"), dict) else {}
            except Exception:
                pass
        current_deck = current_summary.get("demoDeck") if isinstance(current_summary.get("demoDeck"), dict) else {}
        current_slides = current_deck.get("slides") if isinstance(current_deck.get("slides"), list) else []
        current_quality = current_deck.get("demoDeckQuality") if isinstance(current_deck.get("demoDeckQuality"), dict) else {}
        current_evidence = current_deck.get("evidenceStatus") if isinstance(current_deck.get("evidenceStatus"), dict) else {}
        current_quality_issues = " ".join(str(item) for item in current_quality.get("issues") or [])
        current_quality_missing_insights = {
            normalize_space(str(item)) for item in (current_quality.get("missingProductInsights") or [])
        }
        needs_demo_rebuild = bool(
            current_slides
            and demo_deck_has_missing_source_quotes(current_deck)
        ) or bool(
            current_deck
            and (
                "strongSlideCount" not in current_quality
                or "coveredProductInsights" not in current_quality
                or (current_quality.get("status") == "ready" and "边界限制" in current_quality_missing_insights)
                or not current_deck.get("templateLabel")
                or not current_evidence
                or demo_deck_has_stale_template_copy(current_deck)
                or re.search(r"缺少可直接讲的一句话|缺少原字幕或画面证据|缺讲法|缺原始证据", current_quality_issues)
                or demo_deck_uses_stale_public_talk_template(
                    current_deck,
                    normalize_space(
                        " ".join(
                            str(part or "")
                            for part in (
                                record.get("title"),
                                (record.get("result") or {}).get("title") if isinstance(record.get("result"), dict) else "",
                                current_summary.get("coreClaim"),
                                " ".join(
                                    str(item.get(key) or "")
                                    for item in (
                                        current_summary.get("timeline")
                                        if isinstance(current_summary.get("timeline"), list)
                                        else []
                                    )
                                    if isinstance(item, dict)
                                    for key in ("summary", "transcriptExcerpt", "quoteCandidate")
                                ),
                            )
                        )
                    ),
                )
            )
        )
        if needs_demo_rebuild:
            try:
                current_video_summary = (
                    current_summary.get("videoSummary")
                    if isinstance(current_summary.get("videoSummary"), dict)
                    else {}
                )
                rebuilt_deck = build_video_demo_deck(
                    title=normalize_space(
                        str(
                            current_video_summary.get("headline")
                            or record.get("title")
                            or record.get("result", {}).get("title")
                            or "这条视频"
                        )
                    ),
                    video_summary=video_summary_with_frame_candidates(current_video_summary, current_summary.get("frames")),
                    timeline=current_summary.get("timeline") if isinstance(current_summary.get("timeline"), list) else [],
                    video_embed=current_summary.get("videoEmbed") if isinstance(current_summary.get("videoEmbed"), dict) else {},
                    visual_notes=current_summary.get("visualNotes") if isinstance(current_summary.get("visualNotes"), list) else [],
                    transcript_quality=current_summary.get("transcriptQuality") if isinstance(current_summary.get("transcriptQuality"), dict) else {},
                )
                current_summary["demoDeck"] = rebuilt_deck
                current_summary["demoDeckVersion"] = DEMO_DECK_VERSION
                ensure_video_material_acceptance(current_summary)
                record["summary"] = current_summary
                sync_video_job_display_fields(record)
                write_video_job(job_id, record)
                os.utime(path, (stat.st_atime, stat.st_mtime))
            except Exception:
                pass
    if sync_video_job_display_fields(record):
        write_video_job(job_id, record)
        os.utime(path, (stat.st_atime, stat.st_mtime))
    return record


def write_video_job(job_id: str, payload: dict[str, Any]) -> None:
    ensure_document_dirs()
    path = video_job_path(job_id)
    tmp_path = path.with_name(f".{path.name}.{uuid.uuid4().hex}.tmp")
    tmp_path.write_text(json.dumps(payload, ensure_ascii=False, indent=2) + "\n", encoding="utf-8")
    os.replace(tmp_path, path)


def active_video_analysis_job_ids(*, max_age_seconds: int | None = None) -> list[str]:
    timeout_seconds = int(max_age_seconds or os.environ.get("VIDEO_ANALYSIS_JOB_TIMEOUT_SECONDS", str(DEFAULT_VIDEO_ANALYSIS_JOB_TIMEOUT_SECONDS)))
    active: list[str] = []
    for path in sorted(VIDEO_JOB_DIR.glob("*.json")):
        try:
            record = json.loads(path.read_text(encoding="utf-8"))
        except Exception:
            continue
        record, changed = mark_stale_video_job(record, timeout_seconds=timeout_seconds)
        if changed:
            try:
                write_video_job(str(record.get("id") or path.stem), record)
            except Exception:
                pass
        if record.get("status") in {"queued", "running"}:
            active.append(str(record.get("id") or path.stem))
    return active


def canonical_video_url(value: str) -> str:
    value = normalize_space(value).rstrip("/")
    if not value:
        return ""
    return re.sub(r"([?&])t=\d+s?(&|$)", r"\1", value).rstrip("?&").lower()


def cached_video_transcript_summary(url: str, *, exclude_job_id: str = "") -> dict[str, Any] | None:
    """Return the newest successful transcript summary for the same URL."""
    target = canonical_video_url(url)
    if not target:
        return None
    candidates: list[tuple[float, dict[str, Any]]] = []
    for path in VIDEO_JOB_DIR.glob("*.json"):
        try:
            record = json.loads(path.read_text(encoding="utf-8"))
        except Exception:
            continue
        if exclude_job_id and record.get("id") == exclude_job_id:
            continue
        if record.get("status") != "done":
            continue
        summary = record.get("summary") if isinstance(record.get("summary"), dict) else {}
        if record.get("qualityRefetch") or summary.get("frameRefetchFailed"):
            continue
        record_url = canonical_video_url(str(record.get("url") or record.get("result", {}).get("url") or ""))
        if record_url != target:
            continue
        timeline = summary.get("timeline") if isinstance(summary.get("timeline"), list) else []
        transcript_source = normalize_space(str(summary.get("transcriptSource") or record.get("transcriptSource") or ""))
        if transcript_source in {"", "none"} or not timeline:
            continue
        candidates.append((path.stat().st_mtime, {"record": record, "summary": summary}))
    if not candidates:
        return None
    return sorted(candidates, key=lambda item: item[0], reverse=True)[0][1]


def transcript_markdown_needs_refresh(markdown: str, *, summary_source: str = "") -> bool:
    text = str(markdown or "")
    if not text.strip():
        return True
    if "(No transcript content resolved.)" in text:
        return True
    if re.search(r"-\s*Source:\s*none\b", text, re.I):
        return True
    if re.search(r"-\s*Segment count:\s*0\b", text, re.I):
        return True
    source = normalize_space(summary_source)
    if source and source != "none" and f"- Source: {source}" not in text:
        return True
    return False


def apply_cached_video_transcript_fallback(job_id: str, record: dict[str, Any]) -> dict[str, Any]:
    summary = record.get("summary") if isinstance(record.get("summary"), dict) else {}
    if summary.get("frameRefetchFailed"):
        return record
    transcript_source = normalize_space(str(summary.get("transcriptSource") or "none"))
    timeline = summary.get("timeline") if isinstance(summary.get("timeline"), list) else []
    current_markdown = str(record.get("transcriptMarkdown") or "")
    if transcript_source != "none" and timeline and not transcript_markdown_needs_refresh(
        current_markdown,
        summary_source=transcript_source,
    ):
        record["transcriptSource"] = transcript_source
        record["timeline"] = timeline
        return record
    cached = cached_video_transcript_summary(str(record.get("url") or record.get("result", {}).get("url") or ""), exclude_job_id=job_id)
    if not cached:
        return record
    cached_summary = cached["summary"]
    merged_summary = dict(summary)
    for key in (
        "transcriptSource",
        "transcriptSegments",
        "transcriptQuality",
        "captionFiles",
        "timeline",
        "coreClaim",
        "angles",
        "writingCards",
        "writingPack",
        "writingCardsVersion",
        "writingPackVersion",
        "videoTimelineVersion",
        "sourcePackMarkdown",
        "sourcePackPath",
            "sourcePackUrl",
            "demoDeck",
            "demoDeckVersion",
        ):
        value = cached_summary.get(key)
        if value:
            merged_summary[key] = value
    notes = list(merged_summary.get("transcriptNotes") or [])
    cache_note = f"cached-transcript-after-fetch-failure:{cached['record'].get('id')}"
    if cache_note not in notes:
        notes.append(cache_note)
    merged_summary["transcriptNotes"] = notes
    record["summary"] = merged_summary
    record["transcriptSource"] = merged_summary.get("transcriptSource")
    record["transcript_source"] = merged_summary.get("transcriptSource")
    record["timeline"] = merged_summary.get("timeline")
    cached_segments = cached_summary.get("transcriptSegments") if isinstance(cached_summary.get("transcriptSegments"), list) else []
    if not cached_segments:
        cached_segments = [
            {
                "start": item.get("start") or 0,
                "duration": item.get("duration") or 0,
                "text": normalize_space(str(item.get("transcriptExcerpt") or item.get("summary") or "")),
            }
            for item in merged_summary.get("timeline") or []
            if isinstance(item, dict) and normalize_space(str(item.get("transcriptExcerpt") or item.get("summary") or ""))
        ]
    if cached_segments:
        record["transcriptSegments"] = cached_segments
        result = record.get("result") if isinstance(record.get("result"), dict) else {}
        result["transcript_source"] = merged_summary.get("transcriptSource")
        result["transcript_segments"] = cached_segments
        record["result"] = result
    cached_markdown = str(cached["record"].get("transcriptMarkdown") or "")
    if cached_markdown and transcript_markdown_needs_refresh(
        current_markdown,
        summary_source=str(merged_summary.get("transcriptSource") or ""),
    ):
        record["transcriptMarkdown"] = cached_markdown
        result = record.get("result") if isinstance(record.get("result"), dict) else {}
        result["transcript_markdown"] = cached_markdown
        record["result"] = result
    return record


def recent_video_jobs(limit: int = 12) -> list[dict[str, Any]]:
    ensure_document_dirs()
    records: list[dict[str, Any]] = []
    for path in VIDEO_JOB_DIR.glob("*.json"):
        try:
            record = json.loads(path.read_text(encoding="utf-8"))
            record, stale_changed = mark_stale_video_job(record)
            changed = stale_changed
            if record.get("status") == "error" and not isinstance(record.get("failure"), dict):
                record["failure"] = build_video_failure_diagnosis(
                    url=str(record.get("url") or ""),
                    message=str(record.get("message") or ""),
                    error=str(record.get("error") or ""),
                    cookies_from_browser=str(record.get("cookiesFromBrowser") or ""),
                )
                changed = True
            if record.get("status") == "done":
                current_summary = record.get("summary") if isinstance(record.get("summary"), dict) else {}
                try:
                    if record.get("requireLocalVideo"):
                        require_local_video_embed(current_summary)
                    if normalize_required_video_source_status(current_summary):
                        record["summary"] = current_summary
                        changed = True
                except Exception as exc:
                    message = public_exception_message(exc)
                    detail = debug_exception_message(exc)
                    record["status"] = "error"
                    record["stage"] = "error"
                    record["message"] = message
                    record["error"] = detail
                    record["failure"] = build_video_failure_diagnosis(
                        url=str(record.get("url") or ""),
                        message=message,
                        error=detail,
                        cookies_from_browser=str(record.get("cookiesFromBrowser") or ""),
                    )
                    record.setdefault("events", []).append({
                        "at": utc_now(),
                        "stage": "error",
                        "message": message,
                        "extra": {"reason": "download-required", "detail": detail},
                    })
                    changed = True
            if changed:
                write_video_job(str(record.get("id") or path.stem), record)
            records.append(record)
        except Exception:
            continue
    records.sort(key=lambda item: str(item.get("createdAt") or item.get("updatedAt") or ""), reverse=True)
    return records[:limit]


def previous_complete_video_job_for_url(url: str, exclude_id: str) -> dict[str, Any] | None:
    target = canonical_video_url(url)
    if not target:
        return None
    candidates: list[tuple[tuple[int, int, int, int, str], dict[str, Any]]] = []
    for path in VIDEO_JOB_DIR.glob("*.json"):
        try:
            record = json.loads(path.read_text(encoding="utf-8"))
        except Exception:
            continue
        if str(record.get("id") or path.stem) == exclude_id:
            continue
        if record.get("status") != "done":
            continue
        if canonical_video_url(str(record.get("url") or "")) != target:
            continue
        summary = record.get("summary") if isinstance(record.get("summary"), dict) else {}
        deck = summary.get("demoDeck") if isinstance(summary.get("demoDeck"), dict) else {}
        slides = deck.get("slides") if isinstance(deck.get("slides"), list) else []
        timeline = summary.get("timeline") if isinstance(summary.get("timeline"), list) else []
        if len(slides) < 3 or len(timeline) < 3:
            continue
        evidence = deck.get("evidenceStatus") if isinstance(deck.get("evidenceStatus"), dict) else {}
        score = (
            1 if evidence.get("ready") else 0,
            int(evidence.get("uniqueScreenshots") or 0),
            len(slides),
            len({str(item.get("frameUrl") or "") for item in timeline if str(item.get("frameUrl") or "")}),
            str(record.get("updatedAt") or record.get("createdAt") or ""),
        )
        candidates.append((score, record))
    candidates.sort(key=lambda item: item[0], reverse=True)
    return candidates[0][1] if candidates else None


def video_job_has_unusable_transcript(record: dict[str, Any]) -> bool:
    summary = record.get("summary") if isinstance(record.get("summary"), dict) else {}
    result = record.get("result") if isinstance(record.get("result"), dict) else {}
    transcript_quality = summary.get("transcriptQuality") if isinstance(summary.get("transcriptQuality"), dict) else {}
    transcript_source = normalize_space(
        str(
            summary.get("transcriptSource")
            or record.get("transcriptSource")
            or record.get("transcript_source")
            or result.get("transcript_source")
            or ""
        )
    ).lower()
    if normalize_space(str(transcript_quality.get("level") or "none")) == "none":
        return True
    if transcript_source in {"", "none", "no-transcript", "missing"}:
        return True
    return False


def video_job_has_reusable_local_material(record: dict[str, Any]) -> bool:
    summary = record.get("summary") if isinstance(record.get("summary"), dict) else {}
    transcript_quality = summary.get("transcriptQuality") if isinstance(summary.get("transcriptQuality"), dict) else {}
    if transcript_quality.get("usable") is False:
        return False
    video_embed = summary.get("videoEmbed") if isinstance(summary.get("videoEmbed"), dict) else {}
    if video_embed.get("type") != "local" or not normalize_space(str(video_embed.get("src") or "")):
        return False
    deck = summary.get("demoDeck") if isinstance(summary.get("demoDeck"), dict) else {}
    slides = deck.get("slides") if isinstance(deck.get("slides"), list) else []
    timeline = summary.get("timeline") if isinstance(summary.get("timeline"), list) else []
    evidence = deck.get("evidenceStatus") if isinstance(deck.get("evidenceStatus"), dict) else {}
    return len(slides) >= 3 and len(timeline) >= 3 and bool(evidence.get("ready"))


def should_refresh_cached_video_transcript(previous: dict[str, Any], cookies_from_browser: str) -> bool:
    if video_job_has_reusable_local_material(previous):
        return False
    cookie_source = normalize_space(str(cookies_from_browser or "")).lower()
    if cookie_source in {"", "none", "false", "0", "disabled"}:
        return False
    summary = previous.get("summary") if isinstance(previous.get("summary"), dict) else {}
    result = previous.get("result") if isinstance(previous.get("result"), dict) else {}
    transcript_source = normalize_space(
        str(
            summary.get("transcriptSource")
            or previous.get("transcriptSource")
            or previous.get("transcript_source")
            or result.get("transcript_source")
            or ""
        )
    ).lower()
    caption_files = previous.get("captionFiles") or summary.get("captionFiles") or result.get("caption_files") or []
    try:
        caption_selection_version = int(summary.get("captionSelectionVersion") or previous.get("captionSelectionVersion") or 0)
    except (TypeError, ValueError):
        caption_selection_version = 0
    if (
        caption_selection_version < VIDEO_CAPTION_SELECTION_VERSION
        and (caption_files or transcript_source.startswith(("yt-dlp", "local-cached-caption")))
    ):
        return True
    return video_job_has_unusable_transcript(previous)


def video_demo_evidence_score(summary: dict[str, Any]) -> tuple[int, int, int, int, int]:
    deck = summary.get("demoDeck") if isinstance(summary.get("demoDeck"), dict) else {}
    evidence = deck.get("evidenceStatus") if isinstance(deck.get("evidenceStatus"), dict) else {}
    slides = deck.get("slides") if isinstance(deck.get("slides"), list) else []
    timeline = summary.get("timeline") if isinstance(summary.get("timeline"), list) else []
    timeline_frame_count = len({str(item.get("frameUrl") or "") for item in timeline if str(item.get("frameUrl") or "")})
    return (
        1 if evidence.get("ready") else 0,
        int(evidence.get("uniqueScreenshots") or 0),
        int(evidence.get("screenshotSlides") or 0),
        len(slides),
        timeline_frame_count,
    )


def demo_deck_has_mechanical_titles(deck: dict[str, Any]) -> bool:
    slides = deck.get("slides") if isinstance(deck.get("slides"), list) else []
    titles = [normalize_space(str(slide.get("title") or "")) for slide in slides if isinstance(slide, dict)]
    titles = [title for title in titles if title]
    if not titles:
        return False
    if any(re.search(r"\s\d+$", title) for title in titles):
        return True
    return len(set(titles)) < len(titles)


def merge_video_timeline_visual_evidence(
    current_timeline: list[dict[str, Any]],
    cached_timeline: list[dict[str, Any]],
) -> tuple[list[dict[str, Any]], bool]:
    if not current_timeline or not cached_timeline:
        return current_timeline, False

    by_watch: dict[str, dict[str, Any]] = {}
    by_time: dict[str, dict[str, Any]] = {}
    by_start: dict[int, dict[str, Any]] = {}
    for item in cached_timeline:
        if not isinstance(item, dict):
            continue
        watch_key = normalize_space(str(item.get("watchAtUrl") or ""))
        if watch_key and watch_key not in by_watch:
            by_watch[watch_key] = item
        time_key = normalize_space(str(item.get("timeLabel") or ""))
        if time_key and time_key not in by_time:
            by_time[time_key] = item
        try:
            start_key = int(round(float(item.get("start") or -1)))
        except Exception:
            start_key = -1
        if start_key >= 0 and start_key not in by_start:
            by_start[start_key] = item

    merged: list[dict[str, Any]] = []
    changed = False
    same_length = len(current_timeline) == len(cached_timeline)
    for index, item in enumerate(current_timeline):
        if not isinstance(item, dict):
            merged.append(item)
            continue
        updated = dict(item)
        if not normalize_space(str(updated.get("frameUrl") or "")):
            cached_match = None
            watch_key = normalize_space(str(updated.get("watchAtUrl") or ""))
            if watch_key:
                cached_match = by_watch.get(watch_key)
            if not cached_match:
                time_key = normalize_space(str(updated.get("timeLabel") or ""))
                if time_key:
                    cached_match = by_time.get(time_key)
            if not cached_match:
                try:
                    start_key = int(round(float(updated.get("start") or -1)))
                except Exception:
                    start_key = -1
                if start_key >= 0:
                    cached_match = by_start.get(start_key)
            if not cached_match and same_length and index < len(cached_timeline):
                candidate = cached_timeline[index]
                if isinstance(candidate, dict):
                    cached_match = candidate
            cached_frame = normalize_space(str((cached_match or {}).get("frameUrl") or ""))
            if cached_frame:
                updated["frameUrl"] = cached_frame
                if cached_match and cached_match.get("frameLabel"):
                    updated["frameLabel"] = cached_match.get("frameLabel")
                changed = True
        merged.append(updated)
    return merged, changed


def apply_cached_video_evidence_fallback(job_id: str, record: dict[str, Any]) -> dict[str, Any]:
    summary = record.get("summary") if isinstance(record.get("summary"), dict) else {}
    current_timeline = summary.get("timeline") if isinstance(summary.get("timeline"), list) else []
    if not current_timeline:
        return record

    previous = previous_complete_video_job_for_url(
        str(record.get("url") or record.get("result", {}).get("url") or ""),
        job_id,
    )
    if not previous:
        return record

    previous_summary = previous.get("summary") if isinstance(previous.get("summary"), dict) else {}
    current_transcript_source = normalize_space(
        str(
            summary.get("transcriptSource")
            or record.get("transcriptSource")
            or record.get("transcript_source")
            or record.get("result", {}).get("transcript_source")
            or ""
        )
    )
    previous_transcript_source = normalize_space(
        str(
            previous_summary.get("transcriptSource")
            or previous.get("transcriptSource")
            or previous.get("transcript_source")
            or previous.get("result", {}).get("transcript_source")
            or ""
        )
    )
    current_has_transcript = current_transcript_source not in {"", "none"}
    previous_has_transcript = previous_transcript_source not in {"", "none"}
    current_video_summary = summary.get("videoSummary") if isinstance(summary.get("videoSummary"), dict) else {}
    current_deck = summary.get("demoDeck") if isinstance(summary.get("demoDeck"), dict) else {}
    previous_deck = previous_summary.get("demoDeck") if isinstance(previous_summary.get("demoDeck"), dict) else {}
    previous_timeline = previous_summary.get("timeline") if isinstance(previous_summary.get("timeline"), list) else []
    current_frames = summary.get("frames") if isinstance(summary.get("frames"), list) else []
    previous_frames = previous_summary.get("frames") if isinstance(previous_summary.get("frames"), list) else []
    current_video_embed = summary.get("videoEmbed") if isinstance(summary.get("videoEmbed"), dict) else {}
    previous_video_embed = previous_summary.get("videoEmbed") if isinstance(previous_summary.get("videoEmbed"), dict) else {}
    merged_video_embed = prefer_local_video_embed(current_video_embed, previous_video_embed)
    merged_frames = current_frames or previous_frames
    current_effectively_visual_only = (
        infer_video_evidence_mode(current_timeline) == "visual-only"
        or normalize_space(str(current_video_summary.get("evidenceMode") or "")) == "visual-only"
        or normalize_space(str(current_deck.get("evidenceMode") or "")) == "visual-only"
    )
    current_score = video_demo_evidence_score(summary)
    previous_score = video_demo_evidence_score(previous_summary)
    if not current_has_transcript and current_effectively_visual_only:
        merged_timeline, _ = merge_video_timeline_visual_evidence(current_timeline, previous_timeline)
        if merged_frames and len(merged_timeline) < min(3, len(merged_frames)):
            merged_timeline = build_video_timeline(
                result={
                    "title": record.get("title") or record.get("result", {}).get("title") or "",
                    "transcript_source": "none",
                    "transcript_markdown": "",
                },
                info_payload={
                    "title": record.get("title") or record.get("result", {}).get("title") or "",
                    "description_preview": "",
                    "transcript_source": "none",
                    "transcript_segments": [],
                    "analysis": {
                        "summary": current_video_summary.get("headline") or "",
                        "content_outline": current_video_summary.get("bullets") or [],
                        "talking_points": [],
                        "repurpose_angles": [current_video_summary.get("takeaway") or ""],
                    },
                },
                frames=merged_frames,
                video_embed=merged_video_embed,
            )
        visual_notes: list[str] = []
        for note in list(summary.get("visualNotes") or []) + list(previous_summary.get("visualNotes") or []):
            note_text = normalize_space(str(note))
            if note_text and note_text not in visual_notes:
                visual_notes.append(note_text)
        borrowed_cached_evidence = merged_frames != current_frames or merged_video_embed != current_video_embed
        if borrowed_cached_evidence:
            fallback_note = f"cached-evidence-fallback:{previous.get('id')}"
            if fallback_note not in visual_notes:
                visual_notes.append(fallback_note)
        changed = (
            merged_frames != current_frames
            or merged_video_embed != current_video_embed
            or merged_timeline != current_timeline
            or visual_notes != list(summary.get("visualNotes") or [])
        )
        if not changed:
            return record
        merged_summary = dict(summary)
        merged_summary["frames"] = merged_frames
        merged_summary["videoEmbed"] = merged_video_embed
        merged_summary["visualNotes"] = visual_notes
        merged_summary["demoDeck"] = build_video_demo_deck(
            title=normalize_space(
                str(
                    current_video_summary.get("headline")
                    or record.get("title")
                    or record.get("result", {}).get("title")
                    or "这条视频"
                )
            ),
            video_summary=video_summary_with_frame_candidates(current_video_summary, merged_frames),
            timeline=merged_timeline,
            video_embed=merged_video_embed,
            visual_notes=visual_notes,
            transcript_quality=merged_summary.get("transcriptQuality") if isinstance(merged_summary.get("transcriptQuality"), dict) else {},
        )
        merged_summary["demoDeckVersion"] = DEMO_DECK_VERSION
        merged_summary["timeline"] = merged_timeline
        record["summary"] = merged_summary
        record["timeline"] = merged_timeline
        return record
    should_reuse_previous_titles = (
        bool(previous_deck)
        and demo_deck_has_mechanical_titles(current_deck)
        and not demo_deck_has_mechanical_titles(previous_deck)
    )
    if previous_score <= current_score and not should_reuse_previous_titles:
        return record

    merged_timeline, timeline_changed = merge_video_timeline_visual_evidence(current_timeline, previous_timeline)
    if not timeline_changed and previous_score <= current_score and not should_reuse_previous_titles:
        return record

    merged_frames = current_frames
    if len(previous_frames) > len(current_frames):
        merged_frames = previous_frames

    previous_video_summary = previous_summary.get("videoSummary") if isinstance(previous_summary.get("videoSummary"), dict) else {}
    merged_video_summary = {**previous_video_summary, **current_video_summary}

    merged_video_embed = {**previous_video_embed, **current_video_embed}

    visual_notes: list[str] = []
    for note in list(summary.get("visualNotes") or []) + list(previous_summary.get("visualNotes") or []):
        note_text = normalize_space(str(note))
        if note_text and note_text not in visual_notes:
            visual_notes.append(note_text)
    fallback_note = f"cached-evidence-fallback:{previous.get('id')}"
    if fallback_note not in visual_notes:
        visual_notes.append(fallback_note)

    rebuilt_deck = build_video_demo_deck(
        title=normalize_space(
            str(
                merged_video_summary.get("headline")
                or record.get("title")
                or record.get("result", {}).get("title")
                or "这条视频"
            )
        ),
        video_summary=video_summary_with_frame_candidates(merged_video_summary, merged_frames),
        timeline=merged_timeline,
        video_embed=merged_video_embed,
        visual_notes=visual_notes,
        transcript_quality=summary.get("transcriptQuality") if isinstance(summary.get("transcriptQuality"), dict) else {},
    )
    previous_deck_quality = previous_deck.get("demoDeckQuality") if isinstance(previous_deck.get("demoDeckQuality"), dict) else {}
    previous_quality_issues = " ".join(str(item) for item in previous_deck_quality.get("issues") or [])
    previous_deck_has_blocking_quality_issues = bool(
        re.search(r"缺少可直接讲的一句话|缺少原字幕或画面证据|缺讲法|缺原始证据", previous_quality_issues)
    )
    previous_slides = previous_deck.get("slides") if isinstance(previous_deck.get("slides"), list) else []
    rebuilt_slides = rebuilt_deck.get("slides") if isinstance(rebuilt_deck.get("slides"), list) else []
    previous_has_richer_deck = bool(previous_deck) and (
        len(previous_slides) > len(rebuilt_slides)
        or video_demo_evidence_score({"demoDeck": previous_deck, "timeline": previous_timeline})
        > video_demo_evidence_score({"demoDeck": rebuilt_deck, "timeline": merged_timeline})
    )
    prefer_previous_deck = bool(previous_deck) and (
        previous_has_richer_deck
        or
        should_reuse_previous_titles
        or (demo_deck_has_mechanical_titles(rebuilt_deck) and not demo_deck_has_mechanical_titles(previous_deck))
    ) and not previous_deck_has_blocking_quality_issues
    if prefer_previous_deck:
        reused_deck = copy.deepcopy(previous_deck)
        reused_deck["headline"] = rebuilt_deck.get("headline") or reused_deck.get("headline")
        reused_deck["sourceStatus"] = rebuilt_deck.get("sourceStatus") or reused_deck.get("sourceStatus")
        reused_deck["evidenceMode"] = rebuilt_deck.get("evidenceMode") or reused_deck.get("evidenceMode")
        reused_deck["evidenceNote"] = rebuilt_deck.get("evidenceNote") or reused_deck.get("evidenceNote")
        reused_deck["evidenceStatus"] = previous_deck.get("evidenceStatus") or rebuilt_deck.get("evidenceStatus")
        reused_deck["demoDeckQuality"] = previous_deck.get("demoDeckQuality") or rebuilt_deck.get("demoDeckQuality")
        reused_deck["deckSpine"] = previous_deck.get("deckSpine") or rebuilt_deck.get("deckSpine")
        reused_deck["droppedSlides"] = previous_deck.get("droppedSlides") or rebuilt_deck.get("droppedSlides") or []
        merged_demo_deck = reused_deck
    else:
        merged_demo_deck = rebuilt_deck

    merged_summary = dict(summary)
    merged_summary["timeline"] = merged_timeline
    merged_summary["frames"] = merged_frames
    merged_summary["videoSummary"] = merged_video_summary
    merged_summary["videoEmbed"] = merged_video_embed
    merged_summary["visualNotes"] = visual_notes
    merged_summary["demoDeck"] = merged_demo_deck
    merged_summary["demoDeckVersion"] = DEMO_DECK_VERSION
    merged_summary["frameRefetchFallbackJobId"] = previous.get("id")
    record["summary"] = merged_summary
    record["timeline"] = merged_timeline
    return record


def delete_video_job(job_id: str) -> dict[str, Any]:
    path = video_job_path(job_id)
    if not path.exists():
        raise FileNotFoundError(f"video job not found: {job_id}")
    record = json.loads(path.read_text(encoding="utf-8"))
    path.unlink()
    return record


def clear_video_jobs(status: str | None = None) -> dict[str, Any]:
    ensure_document_dirs()
    removed: list[str] = []
    for path in VIDEO_JOB_DIR.glob("*.json"):
        try:
            record = json.loads(path.read_text(encoding="utf-8"))
        except Exception:
            continue
        if status and record.get("status") != status:
            continue
        path.unlink()
        removed.append(str(record.get("id") or path.stem))
    return {"ok": True, "removed": removed, "count": len(removed), "status": status or "all"}


def relaunch_video_analysis_job(job_id: str) -> dict[str, Any]:
    record = read_video_job(job_id)
    if record.get("sourceType") == "local":
        local_video_path = normalize_space(str(record.get("localVideoPath") or ""))
        if not local_video_path or not Path(local_video_path).exists():
            raise FileNotFoundError("本地视频文件不存在，不能重跑。")
        payload = {
            "title": record.get("title") or Path(local_video_path).stem,
            "localVideoPath": local_video_path,
            "analysisBackend": record.get("analysisBackend", "rules"),
            "extractFrames": True,
            "frameIntervalSeconds": int(record.get("frameIntervalSeconds") or 180),
            "maxFrames": int(record.get("maxFrames") or 8),
            "targetFrameSeconds": record.get("targetFrameSeconds") or [],
            "tenantId": record.get("tenantId") or record.get("ownerId") or DEFAULT_VIDEO_ANALYSIS_TENANT_ID,
            "ownerId": record.get("ownerId") or record.get("tenantId") or DEFAULT_VIDEO_ANALYSIS_TENANT_ID,
            "disableWhisperFallback": bool(record.get("disableWhisperFallback", False)),
            "skipRewrites": bool(record.get("skipRewrites", True)),
        }
        return launch_local_video_analysis_job(payload)
    payload = {
        "url": record.get("url", ""),
        "analysisBackend": record.get("analysisBackend", "rules"),
        "extractFrames": bool(record.get("extractFrames", False)),
        "frameIntervalSeconds": int(record.get("frameIntervalSeconds") or 600),
        "maxFrames": int(record.get("maxFrames") or 2),
        "targetFrameSeconds": record.get("targetFrameSeconds") or [],
        "qualityRefetch": bool(record.get("qualityRefetch", False)),
        "requireLocalVideo": bool(record.get("requireLocalVideo", False)),
        "tenantId": record.get("tenantId") or record.get("ownerId") or DEFAULT_VIDEO_ANALYSIS_TENANT_ID,
        "ownerId": record.get("ownerId") or record.get("tenantId") or DEFAULT_VIDEO_ANALYSIS_TENANT_ID,
        "disableVideoParser": bool(record.get("disableVideoParser", False)),
        "disableWhisperFallback": bool(record.get("disableWhisperFallback", False)),
        "includeComments": bool(record.get("includeComments", False)),
        "skipRewrites": bool(record.get("skipRewrites", False)),
        "cookiesFromBrowser": record.get("cookiesFromBrowser") or "none",
    }
    return launch_video_analysis_job(payload)


LOCAL_VIDEO_EXTENSIONS = {".mp4", ".mov", ".m4v", ".mkv", ".webm"}


def local_video_transcription_limit_seconds() -> int:
    raw = os.environ.get("VIDEO_ANALYSIS_LOCAL_TRANSCRIBE_MAX_SECONDS", "240").strip()
    try:
        return max(0, int(float(raw)))
    except Exception:
        return 240


def video_transcription_health() -> dict[str, Any]:
    ffmpeg_path = video_notes.resolve_binary("ffmpeg")
    whisper_cpp_cli = video_notes.WHISPER_CPP_CLI
    whisper_cpp_model = video_notes.resolve_whisper_cpp_model()
    external_python = video_notes.LOCAL_VLM_PYTHON
    python_backends: list[str] = []
    for module_name, label in (
        ("mlx_whisper", "mlx-whisper"),
        ("lightning_whisper_mlx", "lightning-mlx"),
        ("faster_whisper", "faster-whisper"),
        ("whisper", "whisper"),
    ):
        try:
            __import__(module_name)
        except Exception:
            continue
        python_backends.append(label)
    whisper_cpp_ready = bool(ffmpeg_path and whisper_cpp_cli.exists() and whisper_cpp_model)
    python_ready = bool(ffmpeg_path and python_backends)
    missing: list[str] = []
    if not ffmpeg_path:
        missing.append("ffmpeg")
    if not whisper_cpp_cli.exists() and not python_backends:
        missing.append("转写引擎")
    if whisper_cpp_cli.exists() and not whisper_cpp_model and not python_backends:
        missing.append("whisper.cpp 模型")
    status = "ready" if whisper_cpp_ready or python_ready else "missing"
    if status == "ready":
        primary = "whisper.cpp" if whisper_cpp_ready else python_backends[0]
        label = f"转写可用：{primary}"
    else:
        label = "转写不可用：" + "、".join(missing or ["环境未配置"])
    return {
        "ok": status == "ready",
        "status": status,
        "label": label,
        "primary": "whisper.cpp" if whisper_cpp_ready else python_backends[0] if python_backends else "",
        "ffmpeg": str(ffmpeg_path or ""),
        "whisperCppCli": str(whisper_cpp_cli) if whisper_cpp_cli.exists() else "",
        "whisperCppModel": str(whisper_cpp_model or ""),
        "externalPython": str(external_python) if external_python.exists() else "",
        "pythonBackends": python_backends,
        "missing": missing,
        "localLimitSeconds": local_video_transcription_limit_seconds(),
    }


def form_first_value(form: cgi.FieldStorage, name: str, default: str = "") -> str:
    try:
        value = form.getfirst(name, default)
    except Exception:
        return default
    if value is None:
        return default
    if isinstance(value, bytes):
        return value.decode("utf-8", errors="ignore")
    return str(value)


def form_bool_value(form: cgi.FieldStorage, name: str, default: bool = False) -> bool:
    value = form_first_value(form, name, "1" if default else "0").strip().lower()
    return value not in {"", "0", "false", "off", "no", "none"}


def form_int_value(form: cgi.FieldStorage, name: str, default: int, min_value: int, max_value: int) -> int:
    try:
        value = int(form_first_value(form, name, str(default)))
    except (TypeError, ValueError):
        value = default
    return max(min_value, min(max_value, value))


def video_upload_filename(value: str, fallback: str = "local-video.mp4") -> str:
    raw = Path(str(value or fallback).replace("\\", "/")).name
    cleaned = re.sub(r"[^0-9A-Za-z\u4e00-\u9fff._ -]+", "-", raw).strip(" .-_")
    return cleaned or fallback


def parse_local_video_upload(handler: BaseHTTPRequestHandler, job_id: str) -> tuple[dict[str, Any], Path]:
    content_type = normalize_space(str(handler.headers.get("Content-Type") or ""))
    if "multipart/form-data" not in content_type.lower():
        raise ValueError("local video upload requires multipart/form-data")
    form = cgi.FieldStorage(
        fp=handler.rfile,
        headers=handler.headers,
        environ={
            "REQUEST_METHOD": "POST",
            "CONTENT_TYPE": content_type,
            "CONTENT_LENGTH": str(handler.headers.get("Content-Length") or "0"),
        },
        keep_blank_values=True,
    )
    file_item = form["video"] if "video" in form else form["file"] if "file" in form else None
    if isinstance(file_item, list):
        file_item = file_item[0] if file_item else None
    if file_item is None or not getattr(file_item, "file", None):
        raise ValueError("请选择一个本地视频文件。")
    filename = video_upload_filename(getattr(file_item, "filename", "") or "local-video.mp4")
    suffix = Path(filename).suffix.lower()
    if suffix not in LOCAL_VIDEO_EXTENSIONS:
        raise ValueError("只支持 mp4、mov、m4v、mkv、webm。")
    upload_dir = VIDEO_UPLOAD_DIR / job_id
    upload_dir.mkdir(parents=True, exist_ok=True)
    saved_path = upload_dir / filename
    with saved_path.open("wb") as handle:
        shutil.copyfileobj(file_item.file, handle)
    if not saved_path.exists() or saved_path.stat().st_size <= 0:
        raise ValueError("视频文件为空，不能分析。")
    payload = {
        "title": normalize_space(form_first_value(form, "title", "")) or Path(filename).stem,
        "tenantId": form_first_value(form, "tenantId", DEFAULT_VIDEO_ANALYSIS_TENANT_ID),
        "ownerId": form_first_value(form, "ownerId", DEFAULT_VIDEO_ANALYSIS_TENANT_ID),
        "analysisBackend": form_first_value(form, "analysisBackend", "rules") or "rules",
        "extractFrames": form_bool_value(form, "extractFrames", True),
        "frameIntervalSeconds": form_int_value(form, "frameIntervalSeconds", 180, 30, MAX_VIDEO_ANALYSIS_FRAME_INTERVAL_SECONDS),
        "maxFrames": form_int_value(form, "maxFrames", 8, 1, MAX_VIDEO_ANALYSIS_FRAMES),
        "targetFrameSeconds": form_first_value(form, "targetFrameSeconds", ""),
        "disableWhisperFallback": form_bool_value(form, "disableWhisperFallback", True),
        "skipRewrites": form_bool_value(form, "skipRewrites", True),
        "originalFilename": filename,
        "localVideoPath": str(saved_path),
    }
    return payload, saved_path


def process_local_video_file(job_id: str, payload: dict[str, Any], progress_callback=None) -> dict[str, Any]:
    def report(stage: str, message: str, **extra: Any) -> None:
        if progress_callback:
            progress_callback(stage, message, extra)

    source_video = Path(str(payload.get("localVideoPath") or "")).expanduser().resolve()
    if not source_video.exists() or not source_video.is_file():
        raise FileNotFoundError("本地视频文件不存在。")
    title = normalize_space(str(payload.get("title") or source_video.stem)) or source_video.stem
    video_slug = video_notes.safe_name(job_id)
    out_dir = Path(video_notes.DEFAULT_OUTPUT).expanduser().resolve()
    asset_dir = out_dir / video_slug
    asset_dir.mkdir(parents=True, exist_ok=True)
    note_path = out_dir / f"{video_slug}_notes.md"
    json_path = out_dir / f"{video_slug}_info.json"
    transcript_json_path = out_dir / f"{video_slug}_transcript.json"
    transcript_md_path = out_dir / f"{video_slug}_transcript.md"
    rewrites_path = out_dir / f"{video_slug}_rewrites.md"

    report("import", "正在导入本地视频")
    visual_notes: list[str] = ["local-upload:source"]
    persisted_video = video_notes.persist_source_video_for_material(source_video, asset_dir, notes=visual_notes)
    report(
        "import",
        "本地视频已保存",
        local_video_path=str(persisted_video),
        local_video_size=persisted_video.stat().st_size,
    )

    visual_assets: list[dict[str, Any]] = [
        {"type": "source_video", "path": str(persisted_video), "source": "local-upload"}
    ]
    if bool(payload.get("extractFrames", True)):
        report("frames", "正在截图")
        frame_assets, frame_notes = video_notes.extract_keyframes(
            f"local://{quote(source_video.name)}",
            asset_dir,
            int(payload.get("frameIntervalSeconds") or 180),
            int(payload.get("maxFrames") or 8),
            target_seconds=payload.get("targetFrameSeconds") or "",
            source_video_path=persisted_video,
        )
        visual_assets.extend(frame_assets)
        visual_notes.extend(frame_notes)
    else:
        visual_notes.append("frame-extraction-disabled")

    transcript_items: list[dict[str, Any]] = []
    transcript_source = "none"
    transcript_notes: list[str] = []
    if bool(payload.get("disableWhisperFallback", True)):
        transcript_notes.append("local-video:transcription-skipped-fast-mode")
    else:
        report("transcript", "正在提取音频")
        audio_path = video_notes.extract_audio_from_video(persisted_video, asset_dir / "audio-from-video.mp3")
        if audio_path is None:
            transcript_notes.append("local-video:audio-extract-failed")
        else:
            limit_seconds = local_video_transcription_limit_seconds()
            transcribe_path = video_notes.limit_audio_duration(audio_path, limit_seconds)
            if transcribe_path != audio_path:
                transcript_notes.append(f"local-video:transcribe-preview-first-{limit_seconds}s")
                report("transcript", f"正在转写前 {limit_seconds} 秒", transcript_limit_seconds=limit_seconds)
            else:
                report("transcript", "正在转写音频")
            transcript_items, whisper_source = video_notes.transcribe_audio(transcribe_path)
            if transcript_items:
                transcript_source = whisper_source
                report("transcript", "转写成功", transcript_source=transcript_source, transcript_count=len(transcript_items))
            else:
                transcript_notes.append(whisper_source or "local-video:transcription-empty")
    if not transcript_items:
        transcript_notes.append("local-video:no-transcript")

    video_notes.write_transcript_artifacts(
        out_dir,
        video_slug,
        transcript_items,
        transcript_source,
        transcript_notes,
    )

    info = {
        "id": job_id,
        "platform": "local",
        "title": title,
        "channel": "本地文件",
        "uploader": "本地文件",
        "duration": None,
        "upload_date": "",
        "webpage_url": "",
        "description": "本地上传的视频。没有平台字幕时，先按截图和文件信息整理材料。",
        "subtitles": {},
        "automatic_captions": {},
    }
    outline: list[dict[str, Any]] = []
    key_points = [
        "本地视频已保存，可以直接回看画面。",
        f"已抽取 {len([item for item in visual_assets if item.get('type') == 'frame'])} 张截图作为材料。",
    ]
    if transcript_items:
        key_points.append(f"已有 {len(transcript_items)} 段字幕，拆解会结合画面和声音。")
    else:
        key_points.append("没有字幕或转写时，拆解结果只能作为画面线索，正式写稿前需要人工确认关键句。")
    report("materials", "正在整理材料")
    analysis_payload = video_notes.build_analysis_payload(
        "",
        "local",
        info,
        transcript_items,
        outline,
        key_points,
        visual_assets,
        visual_notes,
        transcript_source,
    )
    analysis, backend_notes = video_notes.run_analysis_backend(str(payload.get("analysisBackend") or "rules"), analysis_payload)
    report("materials", "材料已整理", frame_count=len([item for item in visual_assets if item.get("type") == "frame"]))

    download_policy = video_notes.download_policy_from_notes(
        platform="local",
        auth_note="local-file",
        notes=transcript_notes + visual_notes,
        local_video_path=str(persisted_video),
        require_local_video=True,
    )
    transcript_preview = (
        video_notes.compact_text(video_notes.transcript_items_to_text(transcript_items, with_timestamps=True), 12000)
        if transcript_items
        else "(本地视频暂无字幕。)"
    )
    report_markdown = video_notes.render_markdown_report(
        "",
        "local",
        info,
        "local-file",
        transcript_source,
        transcript_notes,
        [],
        outline,
        key_points,
        visual_assets,
        visual_notes,
        analysis,
        backend_notes,
        transcript_preview,
    )
    json_payload = {
        "id": job_id,
        "platform": "local",
        "title": title,
        "channel": "本地文件",
        "duration": None,
        "upload_date": "",
        "view_count": None,
        "like_count": None,
        "comment_count": None,
        "comments_preview": [],
        "webpage_url": "",
        "subtitles": [],
        "automatic_captions": [],
        "caption_files": [],
        "auth": "local-file",
        "transcript_source": transcript_source,
        "transcript_notes": transcript_notes,
        "chapters": [],
        "outline": outline,
        "key_points": key_points,
        "transcript_preview": transcript_preview,
        "transcript_segments": transcript_items,
        "transcript_json_path": str(transcript_json_path),
        "transcript_md_path": str(transcript_md_path),
        "source_video_path": str(persisted_video),
        "download_policy": download_policy,
        "visual_assets": visual_assets,
        "visual_notes": visual_notes,
        "analysis_backend": analysis.get("backend"),
        "backend_notes": backend_notes,
        "analysis": analysis,
        "analysis_payload": analysis_payload,
        "rewrites_path": str(rewrites_path),
        "rewrite_pack": {"final_take": "", "rewrite_candidates": []},
    }
    out_dir.mkdir(parents=True, exist_ok=True)
    json_path.write_text(json.dumps(json_payload, ensure_ascii=False, indent=2), encoding="utf-8")
    note_path.write_text(report_markdown, encoding="utf-8")
    result = {
        "url": "",
        "video_id": job_id,
        "title": title,
        "channel": "本地文件",
        "duration_human": "",
        "transcript_source": transcript_source,
        "transcript_notes": transcript_notes,
        "transcript_segments": transcript_items,
        "core_claim": analysis.get("core_claim"),
        "repurpose_angles": analysis.get("repurpose_angles") or [],
        "final_take": "",
        "note_path": str(note_path),
        "json_path": str(json_path),
        "transcript_json_path": str(transcript_json_path),
        "transcript_md_path": str(transcript_md_path),
        "source_video_path": str(persisted_video),
        "download_policy": download_policy,
    }
    return result


def launch_local_video_analysis_job(payload: dict[str, Any]) -> dict[str, Any]:
    local_video_path = normalize_space(str(payload.get("localVideoPath") or ""))
    if not local_video_path:
        raise ValueError("localVideoPath is required")
    source_path = Path(local_video_path).expanduser().resolve()
    if not source_path.exists() or not source_path.is_file():
        raise FileNotFoundError("本地视频文件不存在。")
    analysis_backend = normalize_space(str(payload.get("analysisBackend", "rules"))) or "rules"
    if analysis_backend not in video_notes.SUPPORTED_RULES_BACKENDS:
        raise ValueError("unsupported analysis backend")
    max_active_jobs = max(1, int(os.environ.get("MAX_ACTIVE_VIDEO_ANALYSIS_JOBS", str(DEFAULT_MAX_ACTIVE_VIDEO_ANALYSIS_JOBS))))
    active_jobs = active_video_analysis_job_ids()
    if len(active_jobs) >= max_active_jobs:
        raise VideoAnalysisCapacityError(f"当前已有 {len(active_jobs)} 个视频任务在处理，最多同时 {max_active_jobs} 个。等一个完成后再试。")
    job_id = f"video_{dt.datetime.now().strftime('%Y%m%d_%H%M%S')}_{uuid.uuid4().hex[:8]}"
    title = normalize_space(str(payload.get("title") or source_path.stem)) or source_path.stem
    try:
        requested_max_frames = int(payload.get("maxFrames") or 8)
    except (TypeError, ValueError):
        requested_max_frames = 8
    max_frames = max(1, min(requested_max_frames, MAX_VIDEO_ANALYSIS_FRAMES))
    try:
        requested_frame_interval = int(payload.get("frameIntervalSeconds") or 180)
    except (TypeError, ValueError):
        requested_frame_interval = 180
    frame_interval_seconds = max(30, min(requested_frame_interval, MAX_VIDEO_ANALYSIS_FRAME_INTERVAL_SECONDS))
    target_frame_seconds = [
        seconds
        for seconds in video_notes.normalize_target_frame_seconds(payload.get("targetFrameSeconds"), max_frames)
        if seconds <= MAX_VIDEO_ANALYSIS_FRAME_TARGET_SECONDS
    ][:max_frames]
    job_record: dict[str, Any] = {
        "id": job_id,
        "url": "",
        "title": title,
        "sourceType": "local",
        "platform": "local",
        "localVideoPath": str(source_path),
        "tenantId": normalize_video_analysis_tenant_id(payload.get("tenantId") or payload.get("ownerId") or DEFAULT_VIDEO_ANALYSIS_TENANT_ID),
        "ownerScope": "single-user-local",
        "tenantIsolation": {
            "mode": "local-file-record",
            "publicSaasReady": False,
        },
        "status": "queued",
        "stage": "queued",
        "message": "等待开始",
        "createdAt": utc_now(),
        "updatedAt": utc_now(),
        "analysisBackend": analysis_backend,
        "extractFrames": True,
        "frameIntervalSeconds": frame_interval_seconds,
        "maxFrames": max_frames,
        "targetFrameSeconds": target_frame_seconds,
        "budgetPolicy": {
            "maxActiveJobs": max_active_jobs,
            "maxFrames": MAX_VIDEO_ANALYSIS_FRAMES,
            "timeoutSeconds": DEFAULT_VIDEO_ANALYSIS_JOB_TIMEOUT_SECONDS,
            "requiresLocalVideoWhenRequested": True,
        },
        "requireLocalVideo": True,
        "disableWhisperFallback": bool(payload.get("disableWhisperFallback", True)),
        "skipRewrites": bool(payload.get("skipRewrites", True)),
        "cookiesFromBrowser": "none",
        "events": [],
    }
    write_video_job(job_id, job_record)

    def run() -> None:
        def update(stage: str, message: str, extra: dict[str, Any] | None = None) -> None:
            current = read_video_job(job_id)
            event = {"at": utc_now(), "stage": stage, "message": message, "extra": extra or {}}
            current["status"] = "running"
            current["stage"] = stage
            current["message"] = message
            current["updatedAt"] = utc_now()
            current.setdefault("events", []).append(event)
            if extra:
                for key, value in extra.items():
                    current[key] = value
            write_video_job(job_id, current)

        try:
            result = process_local_video_file(
                job_id,
                {
                    **payload,
                    "title": title,
                    "localVideoPath": str(source_path),
                    "analysisBackend": analysis_backend,
                    "maxFrames": max_frames,
                    "frameIntervalSeconds": frame_interval_seconds,
                    "targetFrameSeconds": target_frame_seconds,
                },
                progress_callback=update,
            )
            enriched = enrich_video_job_result(job_id, result)
            final = read_video_job(job_id)
            final["status"] = "done"
            final["stage"] = "done"
            final["message"] = "分析完成"
            final["updatedAt"] = utc_now()
            final["result"] = result
            final["files"] = extract_job_result_files(result)
            if enriched.get("sourcePackPath"):
                final["files"]["source_pack_path"] = enriched["sourcePackPath"]
            final["summary"] = enriched
            final["noteMarkdown"] = read_text_file_if_exists(str(result.get("note_path") or ""))
            final["transcriptMarkdown"] = read_text_file_if_exists(str(result.get("transcript_md_path") or ""))
            final["summary"] = rebuild_video_job_summary(job_id, final)
            final_summary = final.get("summary") if isinstance(final.get("summary"), dict) else {}
            require_local_video_embed(final_summary)
            normalize_required_video_source_status(final_summary)
            final["summary"] = final_summary
            final["transcriptSource"] = final_summary.get("transcriptSource") or "none"
            final["transcript_source"] = final["transcriptSource"]
            final["timeline"] = final_summary.get("timeline") or []
            write_video_job(job_id, final)
        except Exception as exc:
            failed = read_video_job(job_id)
            failed["status"] = "error"
            failed["stage"] = "error"
            failed["message"] = public_video_job_error_message(exc)
            failed["error"] = debug_exception_message(exc)
            failed["updatedAt"] = utc_now()
            failed.setdefault("events", []).append({"at": utc_now(), "stage": "error", "message": str(exc), "extra": {}})
            write_video_job(job_id, failed)

    thread = threading.Thread(target=run, daemon=True)
    thread.start()
    return read_video_job(job_id)


def read_text_file_if_exists(path_value: str) -> str:
    path = Path(path_value)
    if not path.exists():
        return ""
    try:
        return path.read_text(encoding="utf-8", errors="ignore")
    except Exception:
        return ""


def extract_job_result_files(result: dict[str, Any]) -> dict[str, str]:
    files: dict[str, str] = {}
    for key in ("note_path", "json_path", "transcript_json_path", "transcript_md_path", "rewrites_path"):
        value = result.get(key)
        if value:
            files[key] = str(value)
    return files


def local_path_from_video_asset(value: str) -> str:
    text = normalize_space(str(value or ""))
    if not text:
        return ""
    if text.startswith("/api/video-analysis-file?"):
        try:
            params = parse_qs(urlparse(text).query)
            return normalize_space((params.get("path") or [""])[0])
        except Exception:
            return ""
    return text


def safe_package_member_name(value: str, fallback: str) -> str:
    cleaned = re.sub(r"[\r\n/\\]+", "-", normalize_space(value)).strip(" .-_")
    return cleaned or fallback


def add_workspace_file_to_zip(zf: zipfile.ZipFile, path_value: str, arcname: str, added: set[str]) -> bool:
    local_path = local_path_from_video_asset(path_value)
    if not local_path:
        return False
    try:
        file_path = safe_workspace_file(local_path)
    except (FileNotFoundError, ValueError):
        return False
    safe_arcname = arcname.replace("\\", "/").strip("/")
    if not safe_arcname or safe_arcname in added:
        return False
    zf.write(file_path, safe_arcname)
    added.add(safe_arcname)
    return True


def build_video_analysis_package(job_id: str) -> tuple[bytes, str]:
    raw_job: dict[str, Any] = {}
    try:
        raw_job = json.loads(video_job_path(job_id).read_text(encoding="utf-8"))
    except Exception:
        raw_job = {}
    job = read_video_job(job_id)
    summary = job.get("summary") if isinstance(job.get("summary"), dict) else {}
    raw_summary = raw_job.get("summary") if isinstance(raw_job.get("summary"), dict) else {}
    result = job.get("result") if isinstance(job.get("result"), dict) else {}
    raw_result = raw_job.get("result") if isinstance(raw_job.get("result"), dict) else {}
    title = normalize_space(str(job.get("title") or result.get("title") or summary.get("coreClaim") or job_id))
    filename_base = safe_package_member_name(slugify(title, "video-material"), "video-material")[:80]
    package = io.BytesIO()
    added: set[str] = set()
    manifest: dict[str, Any] = {
        "jobId": job_id,
        "title": title,
        "url": job.get("url") or result.get("url") or "",
        "status": job.get("status") or "",
        "createdAt": job.get("createdAt") or "",
        "sourceStatus": summary.get("sourceStatus") or "",
        "included": [],
    }
    with zipfile.ZipFile(package, "w", zipfile.ZIP_DEFLATED) as zf:
        video_embed = next(
            (
                value
                for value in (
                    summary.get("videoEmbed"),
                    job.get("videoEmbed"),
                    result.get("videoEmbed"),
                    raw_summary.get("videoEmbed"),
                    raw_job.get("videoEmbed"),
                    raw_result.get("videoEmbed"),
                )
                if isinstance(value, dict)
                and normalize_space(str(value.get("localPath") or value.get("src") or ""))
            ),
            {},
        )
        download_policy = next(
            (
                value
                for value in (
                    summary.get("downloadPolicy"),
                    job.get("downloadPolicy"),
                    result.get("downloadPolicy"),
                    raw_summary.get("downloadPolicy"),
                    raw_job.get("downloadPolicy"),
                    raw_result.get("downloadPolicy"),
                )
                if isinstance(value, dict)
            ),
            {},
        )
        video_path = normalize_space(str(video_embed.get("localPath") or download_policy.get("localVideoPath") or ""))
        if not video_path:
            video_path = local_path_from_video_asset(str(video_embed.get("src") or ""))
        video_added = add_workspace_file_to_zip(zf, video_path, f"video/{safe_package_member_name(Path(video_path).name, 'source-video.mp4')}", added)
        if video_added:
            manifest["included"].append("video")
        frames: list[Any] = []
        for value in (
            summary.get("frames"),
            job.get("frames"),
            result.get("frames"),
            raw_summary.get("frames"),
            raw_job.get("frames"),
            raw_result.get("frames"),
        ):
            if isinstance(value, list):
                frames.extend(value)
        for collection in (
            summary.get("timeline"),
            job.get("timeline"),
            result.get("timeline"),
            raw_summary.get("timeline"),
            raw_job.get("timeline"),
            raw_result.get("timeline"),
            (summary.get("demoDeck") or {}).get("slides") if isinstance(summary.get("demoDeck"), dict) else [],
            (raw_summary.get("demoDeck") or {}).get("slides") if isinstance(raw_summary.get("demoDeck"), dict) else [],
        ):
            if isinstance(collection, list):
                frames.extend(collection)
        frame_count = 0
        seen_frame_paths: set[str] = set()
        for index, frame in enumerate(frames, start=1):
            if not isinstance(frame, dict):
                continue
            frame_path = normalize_space(str(frame.get("path") or local_path_from_video_asset(str(frame.get("url") or frame.get("frameUrl") or ""))))
            if not frame_path or frame_path in seen_frame_paths:
                continue
            seen_frame_paths.add(frame_path)
            suffix = Path(frame_path).suffix.lower() or ".jpg"
            label = safe_package_member_name(str(frame.get("label") or frame.get("timeLabel") or f"{index:03d}"), f"{index:03d}")
            if add_workspace_file_to_zip(zf, frame_path, f"frames/{index:03d}-{label}{suffix}", added):
                frame_count += 1
        if frame_count:
            manifest["included"].append(f"frames:{frame_count}")
        file_map = job.get("files") if isinstance(job.get("files"), dict) else {}
        raw_file_map = raw_job.get("files") if isinstance(raw_job.get("files"), dict) else {}
        for key, label in (
            ("note_path", "report.md"),
            ("transcript_md_path", "transcript.md"),
            ("source_pack_path", "source-pack.md"),
        ):
            value = normalize_space(str(file_map.get(key) or result.get(key) or raw_file_map.get(key) or raw_result.get(key) or ""))
            if add_workspace_file_to_zip(zf, value, f"notes/{label}", added):
                manifest["included"].append(label)
        demo_deck = summary.get("demoDeck") if isinstance(summary.get("demoDeck"), dict) else {}
        raw_demo_deck = raw_summary.get("demoDeck") if isinstance(raw_summary.get("demoDeck"), dict) else {}
        deck_markdown = normalize_space(str(demo_deck.get("deckMarkdown") or ""))
        if not deck_markdown:
            deck_markdown = normalize_space(str(raw_demo_deck.get("deckMarkdown") or ""))
        if deck_markdown:
            zf.writestr("notes/script.md", deck_markdown + "\n")
            manifest["included"].append("script.md")
        zf.writestr("manifest.json", json.dumps(manifest, ensure_ascii=False, indent=2))
    return package.getvalue(), f"{filename_base}.zip"


def workspace_file_url(path_value: str) -> str:
    path = Path(path_value).expanduser().resolve()
    try:
        path.relative_to(ROOT.resolve())
    except ValueError:
        return ""
    return f"/api/video-analysis-file?path={quote(str(path), safe='')}"


def remote_video_asset_url(url_value: str) -> str:
    value = normalize_space(url_value)
    parsed = urlparse(value)
    if parsed.scheme.lower() not in {"http", "https"} or not parsed.netloc:
        return value
    return f"/api/video-analysis-file?remote={quote(value, safe='')}"


def normalize_video_asset_url(url_value: str) -> str:
    value = normalize_space(url_value)
    if not value:
        return ""
    if value.startswith("/api/video-analysis-file?") or value.startswith("data:"):
        return value
    if re.match(r"^https?://", value, re.I):
        return remote_video_asset_url(value)
    return value


def build_video_deck_markdown(
    *,
    headline: str,
    source_status: str,
    evidence_note: str,
    slides: list[dict[str, Any]],
    deck_template: dict[str, str] | None = None,
) -> str:
    template = deck_template or {}
    deck_lines = [
        f"# {headline}",
        "",
        f"> {source_status}",
    ]
    if evidence_note:
        deck_lines.append(f"> {evidence_note}")
    if template:
        deck_lines.extend(
            [
                f"> 类型：{template.get('label') or '视频拆解'}",
                f"> 主线：{template.get('spine') or template.get('promise') or ''}",
            ]
        )
    deck_lines.append("")
    for slide in slides:
        proof_text = normalize_space(str(slide.get("proof") or ""))
        if re.search(r"这里把视频里的材料压成一个可引用的判断点|把这一段压成一个可复述的操作判断", proof_text):
            proof_text = normalize_space(
                str(slide.get("meaning") or slide.get("audienceTakeaway") or slide.get("evidence") or slide.get("action") or "")
            )
        talk_text = normalize_space(str(slide.get("talkTrack") or ""))
        if re.search(r"先说具体动作，再说明它为什么值得记|把这一段压成一个可复述的操作判断", talk_text):
            talk_text = normalize_space(
                str(slide.get("speakerNote") or slide.get("action") or slide.get("audienceTakeaway") or "")
            )
        deck_lines.extend(
            [
                "---",
                "",
                f"## 第 {slide['index']} 页｜{slide['title']}",
                "",
                f"时间：{slide['timeLabel']}",
                f"位置：{slide.get('role') or '证据'}",
            ]
        )
        if slide.get("frameUrl"):
            deck_lines.extend(["", f"![{slide['title']}]({slide['frameUrl']})"])
        if slide.get("watchAtUrl"):
            deck_lines.extend(["", f"[回看这一段]({slide['watchAtUrl']})"])
        deck_lines.extend(
            [
                "",
                f"- 画面：{slide['action']}",
                f"- 原句：{slide.get('sourceQuote') or slide.get('evidence') or slide.get('action') or ''}",
                f"- 这页留下：{proof_text}",
                f"- 讲法：{talk_text}",
                "",
            ]
        )
    return "\n".join(deck_lines).strip() + "\n"


def video_deck_template_profile(
    *,
    route_kind: str = "",
    is_tutorial: bool = False,
    template_key: str = "",
) -> dict[str, str]:
    key = normalize_space(template_key)
    if not key:
        key = "tutorial" if is_tutorial else normalize_space(route_kind) or "opinion"
    profiles = {
        "tutorial": {
            "key": "tutorial",
            "label": "教程拆解",
            "spine": "问题入口 -> 准备条件 -> 操作步骤 -> 结果验收 -> 排错补充",
            "promise": "把视频拆成别人能照着做的一套步骤。",
        },
        "demo": {
            "key": "demo",
            "label": "演示拆解",
            "spine": "使用场景 -> 输入设置 -> 现场验证 -> 限制门槛 -> 选择判断",
            "promise": "把演示变成能判断值不值得用的材料。",
        },
        "review": {
            "key": "review",
            "label": "工具评测",
            "spine": "适用场景 -> 核心功能 -> 输出结果 -> 成本卡点 -> 选择标准",
            "promise": "把工具视频拆成可比较、可取舍的评测稿。",
        },
        "interview": {
            "key": "interview",
            "label": "访谈提炼",
            "spine": "立场 -> 用户证据 -> 取舍成本 -> 产品判断 -> 可写结论",
            "promise": "从访谈里提炼产品判断，而不是复述对话。",
        },
        "opinion": {
            "key": "opinion",
            "label": "观点拆解",
            "spine": "问题 -> 证据 -> 转折 -> 代价 -> 判断",
            "promise": "从画面讲起。",
        },
    }
    return dict(profiles.get(key, profiles["opinion"]))


def required_demo_deck_roles(route_kind: str = "opinion", *, is_tutorial: bool = False) -> tuple[str, ...]:
    if is_tutorial:
        return ("入口", "准备", "操作", "连接", "验收")
    if route_kind == "review":
        return ("场景", "功能", "结果", "门槛", "判断")
    if route_kind == "demo":
        return ("场景", "设置", "验证", "限制", "判断")
    if route_kind == "interview":
        return ("立场", "用户证据", "结论")
    return ("问题", "证据", "转折", "判断")


def demo_deck_role_matches_requirement(role: str, required_role: str) -> bool:
    role = normalize_space(role)
    required_role = normalize_space(required_role)
    if role == required_role:
        return True
    aliases = {
        "入口": {"入口", "场景", "问题"},
        "准备": {"准备", "设备", "输入", "设置", "素材"},
        "操作": {"操作", "步骤", "连接", "功能", "准备", "设备", "输入", "设置", "生成", "校对", "材料", "证据"},
        "连接": {"连接", "门槛", "限制", "操作", "步骤", "功能"},
        "验收": {"验收", "结果", "验证", "成片", "收束", "判断"},
        "场景": {"场景", "入口"},
        "功能": {"功能", "操作", "输入", "生成", "设置"},
        "结果": {"结果", "验证", "成片"},
        "门槛": {"门槛", "限制", "成本", "取舍"},
        "判断": {"判断", "取舍", "结论", "对比"},
        "证据": {"证据", "材料", "验证", "用户证据", "入口"},
        "转折": {"转折", "限制", "门槛", "取舍"},
        "用户证据": {"用户证据", "证据", "验证", "材料"},
        "立场": {"立场", "判断", "取舍", "结论"},
        "结论": {"结论", "判断", "取舍"},
    }
    return role in aliases.get(required_role, set())


def covered_required_demo_deck_roles(roles: set[str], required_roles: tuple[str, ...]) -> list[str]:
    return [
        required_role
        for required_role in required_roles
        if any(demo_deck_role_matches_requirement(role, required_role) for role in roles)
    ]


def product_lens_required_dimensions(route_kind: str = "opinion", *, is_tutorial: bool = False) -> tuple[str, ...]:
    if is_tutorial or route_kind == "demo":
        return ("产品是什么", "谁会用", "核心流程", "失败门槛", "跑通证据", "限制")
    if route_kind == "review":
        return ("产品是什么", "谁会用", "核心能力", "真实结果", "选择门槛", "限制")
    if route_kind == "interview":
        return ("立场", "证据", "反对意见", "结论")
    return ("问题", "证据", "转折", "代价", "判断")


def cross_route_demo_role_issue(route_kind: str, roles: set[str], *, is_tutorial: bool = False) -> str:
    """Detect when a deck uses the wrong article/product template for the video type."""
    normalized = {normalize_space(str(role)) for role in roles if normalize_space(str(role))}
    if not normalized:
        return ""
    tutorial_roles = {"入口", "准备", "操作", "连接", "验收", "步骤", "设备", "二次排错", "收束", "排错"}
    review_roles = {"场景", "功能", "结果", "门槛", "对比", "判断"}
    opinion_roles = {"问题", "证据", "转折", "代价", "判断"}
    interview_roles = {"立场", "用户证据", "反对意见", "结论"}
    if is_tutorial:
        if len(normalized & (review_roles | opinion_roles | interview_roles)) >= 3 and len(normalized & tutorial_roles) < 3:
            return "教程视频被拆成观点或评测卡，缺少可照做的步骤链"
        return ""
    if route_kind == "review":
        if len(normalized & tutorial_roles) >= 3 and len(normalized & {"场景", "结果", "门槛", "判断", "对比"}) < 3:
            return "评测视频被拆成教程步骤，缺少适用场景、结果和选择标准"
        if len(normalized & opinion_roles) >= 3 and len(normalized & {"场景", "功能", "结果", "门槛"}) < 3:
            return "评测视频被拆成观点稿，缺少产品能力和结果对比"
        return ""
    if route_kind == "demo":
        if len(normalized & opinion_roles) >= 3 and len(normalized & {"场景", "设置", "验证", "限制"}) < 3:
            return "演示视频被拆成观点稿，缺少输入、验证和限制"
        return ""
    if route_kind == "interview":
        if len(normalized & tutorial_roles) >= 3 and len(normalized & interview_roles) < 2:
            return "访谈视频被拆成教程步骤，缺少立场、证据和结论"
        return ""
    if route_kind == "opinion":
        if len(normalized & tutorial_roles) >= 3 and len(normalized & opinion_roles) < 3:
            return "观点视频被拆成教程步骤，缺少问题、证据、转折和判断"
        if len(normalized & review_roles) >= 4 and len(normalized & opinion_roles) < 3:
            return "观点视频被拆成工具评测，缺少论证转折和判断"
    return ""


def product_type_from_video_text(title: str, source: str) -> str:
    text = f"{title} {source}"
    if re.search(r"面试|笔试|简历|offer", text, re.I):
        return "AI 面试/笔试辅助工具"
    if re.search(r"字幕|转写|caption|subtitle", text, re.I):
        return "AI 字幕/转写工具"
    if re.search(r"剪辑|视频|生成|素材|成片", text, re.I):
        return "视频创作工具"
    if re.search(r"编程|代码|coding|IDE|agent", text, re.I):
        return "AI 编程工具"
    if re.search(r"教程|指南|演示|使用|流程", text, re.I):
        return "操作教程"
    title_value = normalize_space(title)
    return video_notes.compact_text(title_value, 24) if title_value else "待判断的产品/方法"


def video_material_unsuitable_reason(title: str, source: str = "") -> str:
    text = normalize_space(f"{title} {source}")
    if not text:
        return ""
    public_talk_terms = (
        r"\bTED\b|tedx|talk|lecture|speech|research|study|experiment|science|scientist|"
        r"brain|body|health|sitting|walking|public\s+health|演讲|讲座|研究|实验|科学|"
        r"健康|大脑|身体|久坐|走动|步行"
    )
    if re.search(public_talk_terms, text, re.I):
        return ""
    material_terms = (
        r"教程|教学|指南|演示|流程|评测|测评|讲解|访谈|播客|课程|案例|复盘|"
        r"tutorial|guide|demo|review|course|interview|podcast|explainer|how to"
    )
    if re.search(material_terms, text, re.I):
        return ""
    music_terms = (
        r"official\s+video|music\s+video|lyric\s+video|lyrics?|mv\b|remaster|"
        r"karaoke|\bsingle\b|\balbum\b|\bost\b|soundtrack|live\s+performance|bach|perlman|"
        r"演唱会|纯音乐|音乐现场|演奏|钢琴|小提琴|吉他|古典音乐|巴赫|莫扎特|贝多芬|帕尔曼|"
        r"官方(?:音乐)?视频|歌词版|字幕版|歌曲|单曲|专辑|翻唱|现场版"
    )
    if re.search(music_terms, text, re.I):
        return "这更像音乐或纯娱乐视频，不适合生成教程拆解或写稿材料。"
    title_value = normalize_space(title)
    if title_value and re.search(r"\b(never gonna give you up|official|remaster)\b", title_value, re.I):
        return "这更像音乐或纯娱乐视频，不适合生成教程拆解或写稿材料。"
    if (
        source
        and not re.search(material_terms, text, re.I)
        and not re.search(public_talk_terms, text, re.I)
        and cjk_char_count(source) < 24
        and ascii_word_count(source) < 18
    ):
        return "这条视频可用信息太少，不适合生成拆解页或写稿材料。"
    return ""


def public_talk_video_context(text: str) -> bool:
    value = normalize_space(text)
    if not value:
        return False
    # This branch contains hand-written copy for a sitting/health TED-style talk.
    # Do not apply it to every TED/research/interview video; that creates plausible
    # but wrong cards for unrelated talks.
    return bool(
        re.search(
            r"public\s+health|brain|body|health|sitting|sedentary|walking|summer[-\s]?camp|"
            r"counselor|physically\s+tired|mentally\s+drained|muscle|metabolism|blood\s+sugar|glucose|"
            r"公共健康|健康|大脑|身体|久坐|坐着|走动|步行|夏令营|辅导员|肌肉|代谢|血糖|疲惫",
            value,
            re.I,
        )
    )


def infer_public_talk_slide_title(text: str, index: int) -> str:
    value = normalize_space(text)
    rules = [
        (r"summer[-\s]?camp|counselor|夏令营|辅导员|physically tired|mentally drained", "身体累和脑子累不是一回事"),
        (r"muscle|metabolism|blood sugar|glucose|sponge|肌肉|代谢|血糖", "肌肉不只是拿来运动"),
        (r"walking|walk|20 minutes|twenty minutes|走路|走动|步行|二十分钟", "二十分钟走动改变了对比"),
        (r"research|study|scan|brain|body|研究|实验|扫描|大脑|身体", "用实验图像把判断钉住"),
        (r"sitting|sedentary|chair|office|desk|久坐|坐着|椅子|办公室", "问题从椅子上开始"),
        (r"break up|exercise|movement|action|建议|动作|运动|打断", "最后落到打断久坐"),
    ]
    for pattern, title in rules:
        if re.search(pattern, value, re.I):
            return title
    fallback = ["先把问题落到身体感受", "找到它背后的机制", "用对比证明差异", "承认执行门槛", "收成一个日常动作"]
    return fallback[min(index, len(fallback) - 1)]


