def normalize_video_summary_asset_urls(summary: dict[str, Any]) -> tuple[dict[str, Any], bool]:
    if not isinstance(summary, dict) or not summary:
        return summary, False

    changed = False
    updated = copy.deepcopy(summary)

    video_embed = updated.get("videoEmbed")
    if isinstance(video_embed, dict):
        thumbnail = normalize_video_asset_url(str(video_embed.get("thumbnailUrl") or ""))
        if thumbnail and thumbnail != str(video_embed.get("thumbnailUrl") or ""):
            video_embed["thumbnailUrl"] = thumbnail
            changed = True

    frames = updated.get("frames")
    if isinstance(frames, list):
        for frame in frames:
            if not isinstance(frame, dict):
                continue
            normalized_url = normalize_video_asset_url(str(frame.get("url") or ""))
            if normalized_url and normalized_url != str(frame.get("url") or ""):
                frame["url"] = normalized_url
                changed = True

    timeline = updated.get("timeline")
    if isinstance(timeline, list):
        for item in timeline:
            if not isinstance(item, dict):
                continue
            normalized_url = normalize_video_asset_url(str(item.get("frameUrl") or ""))
            if normalized_url != str(item.get("frameUrl") or ""):
                item["frameUrl"] = normalized_url
                changed = True

    demo_deck = updated.get("demoDeck")
    if isinstance(demo_deck, dict):
        slides = demo_deck.get("slides")
        if isinstance(slides, list):
            for slide in slides:
                if not isinstance(slide, dict):
                    continue
                normalized_url = normalize_video_asset_url(str(slide.get("frameUrl") or ""))
                if normalized_url != str(slide.get("frameUrl") or ""):
                    slide["frameUrl"] = normalized_url
                    changed = True
            stale_deck_markdown = bool(
                re.search(
                    r"这里把视频里的材料压成一个可引用的判断点|先说具体动作，再说明它为什么值得记|把这一段压成一个可复述的操作判断",
                    str(demo_deck.get("deckMarkdown") or ""),
                )
            )
            if stale_deck_markdown:
                changed = True
            if changed and demo_deck.get("headline") and demo_deck.get("sourceStatus") and demo_deck.get("evidenceNote"):
                demo_deck["deckMarkdown"] = build_video_deck_markdown(
                    headline=str(demo_deck.get("headline") or ""),
                    source_status=str(demo_deck.get("sourceStatus") or ""),
                    evidence_note=str(demo_deck.get("evidenceNote") or ""),
                    slides=[slide for slide in slides if isinstance(slide, dict)],
                    deck_template=demo_deck.get("template") if isinstance(demo_deck.get("template"), dict) else None,
                )
    return updated, changed


def safe_workspace_file(path_value: str) -> Path:
    path = Path(path_value).expanduser().resolve()
    root = ROOT.resolve()
    try:
        path.relative_to(root)
    except ValueError as exc:
        raise ValueError("file is outside workspace") from exc
    if not path.exists() or not path.is_file():
        raise FileNotFoundError(str(path))
    return path


def read_remote_video_asset(url_value: str) -> tuple[bytes, str]:
    url = normalize_space(url_value)
    parsed = urlparse(url)
    if parsed.scheme.lower() not in {"http", "https"} or not parsed.netloc:
        raise ValueError("remote url must be http or https")
    request = urllib_request.Request(
        url,
        headers={
            "User-Agent": "Mozilla/5.0 CodexVideoAnalysis/1.0",
            "Accept": "image/avif,image/webp,image/apng,image/*,*/*;q=0.8",
        },
    )
    with urllib_request.urlopen(request, timeout=15) as response:
        payload = response.read()
        content_type = normalize_space(str(response.headers.get("Content-Type") or "")).lower()
        if "image/" not in content_type:
            raise ValueError("remote asset is not an image")
        return payload, content_type


def discover_cached_video_frame_assets(info_payload: dict[str, Any], json_path: str = "") -> list[dict[str, Any]]:
    existing = [
        asset for asset in info_payload.get("visual_assets") or []
        if isinstance(asset, dict) and asset.get("type") == "frame"
    ]
    if existing:
        return existing
    frame_dirs: list[Path] = []
    source_video_path = normalize_space(str(info_payload.get("source_video_path") or ""))
    if source_video_path:
        frame_dirs.append(Path(source_video_path).expanduser().resolve().parent / "frames")
    if json_path:
        info_path = Path(json_path).expanduser().resolve()
        stem = info_path.stem
        slug = stem[:-5] if stem.endswith("_info") else stem
        frame_dirs.append(info_path.with_name(slug) / "frames")
    seen_dirs: set[Path] = set()
    paths: list[Path] = []
    for frame_dir in frame_dirs:
        if frame_dir in seen_dirs or not frame_dir.exists() or not frame_dir.is_dir():
            continue
        seen_dirs.add(frame_dir)
        for pattern in ("*.jpg", "*.jpeg", "*.png", "*.webp"):
            paths.extend(sorted(frame_dir.glob(pattern)))
    assets: list[dict[str, Any]] = []
    seen_files: set[Path] = set()
    for index, path in enumerate(sorted(paths)):
        resolved = path.expanduser().resolve()
        if resolved in seen_files or not resolved.is_file():
            continue
        seen_files.add(resolved)
        timestamp = index * 120
        assets.append(
            {
                "type": "frame",
                "path": str(resolved),
                "timestamp": timestamp,
                "label": video_notes.format_timestamp(timestamp),
                "source": "cached-frames",
            }
        )
    return assets


def build_video_source_pack(result: dict[str, Any], info_payload: dict[str, Any]) -> tuple[str, str]:
    note_path = str(result.get("note_path") or "")
    json_path = str(result.get("json_path") or "")
    transcript_md_path = str(result.get("transcript_md_path") or "")
    analysis = info_payload.get("analysis") or {}
    frames = discover_cached_video_frame_assets(info_payload, json_path)
    lines = [
        "# Video Source Pack",
        "",
        f"- Title: {info_payload.get('title') or result.get('title') or 'Untitled'}",
        f"- URL: {result.get('url') or info_payload.get('webpage_url') or ''}",
        f"- Platform: {info_payload.get('platform') or 'unknown'}",
        f"- Channel: {info_payload.get('channel') or result.get('channel') or 'unknown'}",
        f"- Duration: {result.get('duration_human') or ''}",
        f"- Auth: {info_payload.get('auth') or 'unknown'}",
        f"- Transcript source: {info_payload.get('transcript_source') or result.get('transcript_source') or 'none'}",
        f"- Report: {note_path}",
        f"- Data JSON: {json_path}",
        f"- Transcript: {transcript_md_path}",
        "",
        "## Core Claim",
        "",
        str(analysis.get("core_claim") or result.get("core_claim") or "").strip() or "(none)",
        "",
        "## Candidate Angles",
        "",
    ]
    for angle in analysis.get("repurpose_angles") or result.get("repurpose_angles") or []:
        lines.append(f"- {angle}")
    editorial = analysis.get("editorial_decision") or {}
    if editorial:
        lines.extend(
            [
                "",
                "## Editorial Decision",
                "",
                f"- Level: {editorial.get('level') or ''}",
                f"- Reason: {editorial.get('reason') or ''}",
                "",
                "### Gaps",
            ]
        )
        for item in editorial.get("gaps") or []:
            lines.append(f"- {item}")
        lines.extend(["", "### Writing Brief", "", str(editorial.get("brief") or "").strip() or "(none)"])
    lines.extend(["", "## Key Points", ""])
    for point in info_payload.get("key_points") or []:
        lines.append(f"- {point}")
    lines.extend(["", "## Visual Evidence", ""])
    if frames:
        for frame in frames:
            lines.append(f"- {video_notes.format_timestamp(frame.get('timestamp'))}: {frame.get('path')}")
    else:
        lines.append("(No frame evidence resolved.)")
    lines.extend(["", "## Notes", ""])
    for note in info_payload.get("transcript_notes") or []:
        lines.append(f"- transcript: {note}")
    for note in info_payload.get("visual_notes") or []:
        lines.append(f"- visual: {note}")
    source_pack = "\n".join(lines).strip() + "\n"
    source_pack_path = Path(json_path).with_name(f"{Path(json_path).stem}_source_pack.md") if json_path else VIDEO_JOB_DIR / f"{result.get('video_id', 'video')}_source_pack.md"
    source_pack_path.write_text(source_pack, encoding="utf-8")
    return source_pack, str(source_pack_path)


def effective_video_core_claim(raw_claim: str, video_summary: dict[str, Any]) -> str:
    """Prefer a concrete video summary over stale generic analysis claims."""
    raw = normalize_space(raw_claim)
    headline = normalize_video_material_copy(str(video_summary.get("headline") or ""), role="headline")
    if raw and not generic_video_core_claim(raw):
        return raw
    if headline and not generic_video_core_claim(headline):
        return headline
    bullets = [
        normalize_video_material_copy(str(item or ""), role="bullet")
        for item in video_summary.get("bullets") or []
        if normalize_video_material_copy(str(item or ""), role="bullet")
    ]
    if len(bullets) >= 2:
        return video_notes.compact_text(f"这条视频主要拆两件事：{bullets[0]} {bullets[1]}", 92)
    if bullets:
        return bullets[0]
    return raw


def sync_video_job_display_fields(record: dict[str, Any]) -> bool:
    """Keep top-level fields aligned with the latest regenerated summary."""
    summary = record.get("summary") if isinstance(record.get("summary"), dict) else {}
    if not summary:
        return False
    changed = False
    video_summary = summary.get("videoSummary") if isinstance(summary.get("videoSummary"), dict) else {}
    if video_summary:
        next_claim = effective_video_core_claim(str(summary.get("coreClaim") or record.get("core_claim") or ""), video_summary)
        if next_claim and summary.get("coreClaim") != next_claim:
            summary["coreClaim"] = next_claim
            changed = True
        if next_claim and record.get("coreClaim") != next_claim:
            record["coreClaim"] = next_claim
            changed = True
        if next_claim and record.get("core_claim") != next_claim:
            record["core_claim"] = next_claim
            changed = True
    deck = summary.get("demoDeck") if isinstance(summary.get("demoDeck"), dict) else {}
    if deck:
        if deck.get("headline") and video_summary.get("headline") != deck.get("headline"):
            video_summary["headline"] = deck["headline"]
            changed = True
        if deck.get("templateLabel") and summary.get("demoDeckTemplateLabel") != deck.get("templateLabel"):
            summary["demoDeckTemplateLabel"] = deck["templateLabel"]
            changed = True
        if deck.get("sourceStatus") and summary.get("sourceStatus") != deck.get("sourceStatus"):
            summary["sourceStatus"] = deck["sourceStatus"]
            changed = True
    for key in (
        "videoEmbed",
        "timeline",
        "demoDeck",
        "transcriptSource",
        "captionFiles",
        "transcriptNotes",
        "frames",
        "materialAcceptance",
        "materialState",
        "transcriptQuality",
        "transcriptSegments",
        "videoSummary",
        "coreClaim",
        "angles",
        "sourceStatus",
        "downloadPolicy",
    ):
        if key in summary and record.get(key) != summary[key]:
            record[key] = summary[key]
            changed = True
    record["summary"] = summary
    return changed


def video_summary_angles(video_summary: dict[str, Any]) -> list[str]:
    angles: list[str] = []
    headline = normalize_video_material_copy(str(video_summary.get("headline") or ""), role="headline")
    if headline and not generic_video_core_claim(headline):
        angles.append(headline)
    for item in video_summary.get("bullets") or []:
        text = normalize_video_material_copy(str(item or ""), role="bullet")
        if text and text not in angles and not low_signal_video_material_copy(text):
            angles.append(text)
        if len(angles) >= 3:
            break
    takeaway = normalize_video_material_copy(str(video_summary.get("takeaway") or ""))
    if takeaway and takeaway not in angles and not low_signal_video_material_copy(takeaway):
        angles.append(takeaway)
    return angles[:3]


def build_video_writing_cards(result: dict[str, Any], info_payload: dict[str, Any], analysis: dict[str, Any]) -> list[dict[str, str]]:
    title = normalize_space(str(info_payload.get("title") or result.get("title") or ""))
    core_claim = normalize_space(str(analysis.get("core_claim") or result.get("core_claim") or ""))
    angles = [normalize_space(str(item)) for item in analysis.get("repurpose_angles") or [] if normalize_space(str(item))]
    talking_points = [normalize_space(str(item)) for item in analysis.get("talking_points") or [] if normalize_space(str(item))]
    hidden_premises = [normalize_space(str(item)) for item in analysis.get("hidden_premises") or [] if normalize_space(str(item))]
    lower = "\n".join(
        [
            title,
            str(info_payload.get("transcript_plain") or ""),
            core_claim,
            "\n".join(angles),
            "\n".join(talking_points),
        ]
    ).lower()
    if "claude code" in lower and (
        "six months from now" in lower
        or "terminal" in lower
        or "六个月" in lower
        or "终端" in lower
    ):
        return [
            {
                "label": "切入",
                "title": "为什么 Claude Code 先做终端，而不是漂亮界面？",
                "detail": "这能讲清楚一个产品判断：先用最低成本进入真实工程任务，再等模型能力补上。",
            },
            {
                "label": "冲突",
                "title": "多数人盯着今天模型够不够强，Boris 盯的是六个月后。",
                "detail": "文章可以从这里拆：好工具不是追热点能力，而是押注能力曲线。",
            },
            {
                "label": "落点",
                "title": "AI 编程不是聊天框升级，而是项目上下文能不能长期留下。",
                "detail": "最后可以接到开发者真实使用：文件、命令、测试、团队规则都要进工作流。",
            },
        ]
    cards: list[dict[str, str]] = []
    first_angle = angles[0] if angles else ""
    first_point = talking_points[0] if talking_points else ""
    first_hidden = hidden_premises[0] if hidden_premises else ""
    cards.append(
        {
            "label": "切入",
            "title": first_angle or (f"别复述《{title}》，先找它背后的门槛。" if title else "先找这条视频背后的门槛。"),
            "detail": core_claim or "把视频结论压成一个可判断的问题，再决定值不值得写。",
        }
    )
    cards.append(
        {
            "label": "冲突",
            "title": first_hidden or "观众真正会问的是：这和我有什么关系？",
            "detail": "写之前先把反对意见摆出来，文章会比顺着视频总结更有力。",
        }
    )
    cards.append(
        {
            "label": "落点",
            "title": first_point or "最后要落到一个具体动作或判断。",
            "detail": "少做知识点搬运，多写你看完后会怎么取舍。",
        }
    )
    return cards[:3]


def format_video_metric(value: Any) -> str:
    if not isinstance(value, int):
        return ""
    if value >= 100000000:
        return f"{value / 100000000:.1f} 亿".replace(".0", "")
    if value >= 10000:
        return f"{value / 10000:.1f} 万".replace(".0", "")
    return str(value)


def format_upload_date(value: Any) -> str:
    text = normalize_space(str(value or ""))
    if re.fullmatch(r"\d{8}", text):
        return f"{text[:4]}-{text[4:6]}-{text[6:8]}"
    return text if text and text != "unknown" else ""


def build_video_discussion_signals(info_payload: dict[str, Any]) -> list[str]:
    signals: list[str] = []
    upload_date = format_upload_date(info_payload.get("upload_date"))
    if upload_date:
        signals.append(f"发布 {upload_date}")
    view_count = format_video_metric(info_payload.get("view_count"))
    if view_count:
        signals.append(f"播放 {view_count}")
    like_count = format_video_metric(info_payload.get("like_count"))
    if like_count:
        signals.append(f"点赞 {like_count}")
    comment_count = format_video_metric(info_payload.get("comment_count"))
    if comment_count:
        signals.append(f"评论 {comment_count}")
    if not signals:
        signals.append("平台未返回热度数据")
    return signals[:4]


def build_video_discussion_profile(info_payload: dict[str, Any]) -> dict[str, list[str]]:
    signals = build_video_discussion_signals(info_payload)
    evidence: list[str] = []
    gaps: list[str] = []
    comments_preview = info_payload.get("comments_preview")
    if isinstance(comments_preview, list) and comments_preview:
        evidence.append(f"已读 {min(len(comments_preview), 5)} 条评论样本")
        for item in comments_preview[:2]:
            if not isinstance(item, dict):
                continue
            text = normalize_space(str(item.get("text") or ""))
            if text:
                evidence.append(video_notes.compact_text(text, 52))
    else:
        comment_count = info_payload.get("comment_count")
        if isinstance(comment_count, int) and comment_count > 0:
            gaps.append("有评论数，还没读评论正文")
        else:
            gaps.append("还没读评论区")
    gaps.append("还没补外部报道和社媒讨论")
    return {
        "signals": signals,
        "evidence": evidence[:3],
        "gaps": gaps[:2],
    }


def build_video_writing_pack(
    *,
    result: dict[str, Any],
    info_payload: dict[str, Any],
    analysis: dict[str, Any],
    timeline: list[dict[str, Any]],
    writing_cards: list[dict[str, str]],
) -> dict[str, Any]:
    title = normalize_space(str(info_payload.get("title") or result.get("title") or ""))
    editorial = analysis.get("editorial_decision") or {}
    quote_moments: list[dict[str, str]] = []
    for item in timeline:
        summary = normalize_space(str(item.get("summary") or ""))
        if not summary:
            continue
        quote_moments.append(
            {
                "timeLabel": str(item.get("timeLabel") or ""),
                "text": video_notes.compact_text(summary, 76),
                "watchAtUrl": str(item.get("watchAtUrl") or ""),
            }
        )
        if len(quote_moments) >= 4:
            break

    title_directions = [
        normalize_space(str(card.get("title") or ""))
        for card in writing_cards
        if normalize_space(str(card.get("title") or ""))
    ][:3]
    if not title_directions and title:
        title_directions = [
            f"看完《{title}》，最值得写的不是结论，而是门槛",
            f"这条视频真正能写的，是它背后的使用代价",
        ]

    gaps = [
        normalize_space(str(item))
        for item in editorial.get("gaps") or []
        if normalize_space(str(item))
    ][:3]
    gaps = [
        item
        for item in gaps
        if not any(marker in item for marker in ("评论区", "外部报道", "热度和争议"))
    ][:2]

    return {
        "status": editorial.get("level") or "",
        "reason": editorial.get("reason") or "",
        "discussionSignals": build_video_discussion_signals(info_payload),
        "discussionProfile": build_video_discussion_profile(info_payload),
        "quoteMoments": quote_moments,
        "gaps": gaps,
        "titleDirections": title_directions,
    }


def build_video_summary_card(
    *,
    result: dict[str, Any],
    info_payload: dict[str, Any],
    analysis: dict[str, Any],
    timeline: list[dict[str, Any]],
) -> dict[str, Any]:
    title = normalize_space(str(info_payload.get("title") or result.get("title") or "这条视频"))
    core_claim = normalize_space(str(analysis.get("core_claim") or result.get("core_claim") or ""))
    description_text = normalize_space(str(info_payload.get("description_preview") or info_payload.get("description") or ""))
    route_source, has_real_transcript = build_video_route_source(
        title=title,
        description_text=description_text,
        timeline=timeline,
    )
    title_parts = [normalize_space(part) for part in re.split(r"\s*[-｜|]\s*", title) if normalize_space(part)]
    tutorial_action = ""
    tutorial_subject = title
    if title_parts:
        tutorial_action = re.sub(r"(教程|演示|流程|使用|指南)$", "", title_parts[0]).strip()
        if len(title_parts) > 1:
            tutorial_subject = title_parts[-1]
    key_points = [
        normalize_space(str(item))
        for item in info_payload.get("key_points") or []
        if normalize_space(str(item))
    ]
    outline = [
        normalize_space(str(item))
        for key in ("content_outline", "talking_points")
        for item in analysis.get(key) or []
        if normalize_space(str(item))
    ]
    timeline_points = [
        normalize_space(str(item.get("summary") or item.get("transcriptExcerpt") or ""))
        for item in timeline
        if isinstance(item, dict) and normalize_space(str(item.get("summary") or item.get("transcriptExcerpt") or ""))
    ]

    missing_transcript = not has_real_transcript
    content_detection_source = build_video_content_detection_source(
        title=title,
        description_text=description_text,
        timeline=timeline,
    )
    route_kind = classify_video_route_kind(title, content_detection_source or route_source)
    is_tutorial = route_kind == "tutorial"
    is_caption_demo = route_kind == "demo" and looks_like_caption_demo(content_detection_source or route_source)
    unsuitable_reason = video_material_unsuitable_reason(title, content_detection_source or route_source)
    if unsuitable_reason:
        return {
            "headline": unsuitable_reason,
            "bullets": [],
            "takeaway": "换成教程、访谈、观点或产品演示类视频再生成材料。",
            "evidenceMode": infer_video_evidence_mode(timeline),
            "contentSuitability": {
                "status": "unsuitable",
                "reason": unsuitable_reason,
            },
            "productLens": video_product_lens(
                title=title,
                route_source=route_source,
                timeline=timeline,
                route_kind=route_kind,
                is_tutorial=is_tutorial,
            ),
        }
    tutorial_bullets: list[str] = []
    if is_tutorial:
        if re.search(r"iPad|IPAD|平板|Windows|电脑|双端|双机|互联|连接", route_source, re.I):
            tutorial_bullets.append("用平板或 iPad 连接 Windows 电脑，先把双端互联跑通。")
        if re.search(r"连不上|联系不上|连接不上|访问|地址|证书|继续访问|使用此地址", route_source):
            tutorial_bullets.append("连不上时，先打开连接地址，按提示安装证书，再回到工具里重试。")
        if re.search(r"简历|音频来源|面试官|面试过程|双机互联|确认|音频|麦克风|配置|设置", route_source):
            tutorial_bullets.append("进入面试前，先上传简历，再选音频来源和互联模式。")
        if re.search(r"重启|刷新|服务|地址没有问题|强制|防火墙", route_source):
            tutorial_bullets.append("地址没问题但仍失败时，再查服务、防火墙和连接状态。")
    demo_bullets: list[str] = []
    if route_kind == "demo":
        if is_caption_demo:
            demo_bullets.extend(
                [
                    "先上传视频或素材，再让工具自动生成字幕。",
                    "生成后要检查转写文本，再选字幕样式。",
                    "最后调整动效和品牌感，用导出结果验收这条流程。",
                ]
            )
        if re.search(r"面试|剪辑|录音|发布|场景|工作流|workflow|什么时候用|谁会用", route_source, re.I):
            demo_bullets.append("先看这东西到底给谁用、在什么场景里用，不要一上来只讲功能名。")
        if re.search(r"配置|设置|上传|简历|音频|权限|来源|入口", route_source, re.I):
            demo_bullets.append("前提和设置没讲清，后面的结果就没法判断。")
        if re.search(r"结果|转写|识别|跑通|生效|消息列表|输出|预览", route_source, re.I):
            demo_bullets.append("真正要看的不是按钮亮没亮，而是结果有没有真的出来。")
        if re.search(r"失败|限制|代价|连不上|证书|防火墙|服务|卡住|问题", route_source, re.I):
            demo_bullets.append("值钱的不是成功画面，而是把会卡住的地方也交代出来。")

    strong_outline = [item for item in outline if not generic_video_summary_hint(item)]
    strong_timeline_points = [item for item in timeline_points if not generic_video_summary_hint(item)]
    if is_tutorial:
        source_points = tutorial_bullets or key_points or strong_timeline_points or strong_outline or timeline_points or outline
    elif route_kind == "demo":
        source_points = strong_timeline_points or key_points or strong_outline or timeline_points or demo_bullets or outline
    else:
        source_points = key_points or strong_timeline_points or strong_outline or timeline_points or outline
    cleaned_points: list[str] = []
    for item in source_points:
        if low_signal_video_material_copy(item):
            continue
        text = normalize_video_material_copy(item, role="point")
        if not text or text in cleaned_points:
            continue
        cleaned_points.append(text)
        if len(cleaned_points) >= 3:
            break
    if is_tutorial and len(cleaned_points) < 3:
        for item in timeline_points:
            if low_signal_video_material_copy(item):
                continue
            text = normalize_video_material_copy(item, role="point")
            if not text or text in cleaned_points:
                continue
            cleaned_points.append(text)
            if len(cleaned_points) >= 3:
                break
    if route_kind == "demo" and len(cleaned_points) < 3:
        for item in demo_bullets:
            text = normalize_video_material_copy(item, role="point")
            if not text or text in cleaned_points:
                continue
            cleaned_points.append(text)
            if len(cleaned_points) >= 3:
                break
    if route_kind == "demo" and len(cleaned_points) < 3:
        for step in demo_route_steps(route_source):
            text = normalize_video_material_copy(step, role="point")
            if not text or text in cleaned_points:
                continue
            cleaned_points.append(text)
            if len(cleaned_points) >= 3:
                break

    if missing_transcript:
        visual_summary = build_visual_only_video_summary(
            route_kind=route_kind,
            route_text=route_source,
            title=title,
            core_claim=core_claim,
        )
        visual_summary["productLens"] = video_product_lens(
            title=title,
            route_source=route_source,
            timeline=timeline,
            route_kind=route_kind,
            is_tutorial=is_tutorial,
        )
        return visual_summary

    if is_tutorial:
        subject = tutorial_subject_label(tutorial_subject if tutorial_subject != title else tutorial_action or tutorial_subject)
        headline = build_tutorial_summary_headline(subject, route_source)
    elif route_kind == "demo":
        if is_caption_demo:
            headline = f"这条短视频演示用 AI 加字幕：{caption_demo_summary_sentence(route_source)}"
        else:
            headline = build_demo_summary_headline(title, route_source, cleaned_points, core_claim)
    elif core_claim:
        headline = build_opinion_summary_headline(title, core_claim, cleaned_points, route_source)
    else:
        headline = build_opinion_summary_headline(title, core_claim, cleaned_points, route_source)

    if not cleaned_points and core_claim:
        cleaned_points = [video_notes.compact_text(core_claim, 58)]

    takeaway_candidates = [
        normalize_space(str(item.get("writingValue") or ""))
        for item in timeline
        if isinstance(item, dict) and normalize_space(str(item.get("writingValue") or ""))
    ]
    takeaway = ""
    if is_tutorial:
        takeaway = build_tutorial_takeaway_copy(route_source)
    elif route_kind == "demo":
        if is_caption_demo:
            takeaway = "适合写成短教程或工具评测：上传、自动字幕、检查转写、调样式、导出。"
        else:
            takeaway = build_demo_takeaway_copy(route_source)
    else:
        takeaway = build_opinion_takeaway_copy(core_claim, route_source, title=title, cleaned_points=cleaned_points)
    for item in takeaway_candidates:
        if takeaway:
            break
        text = re.sub(r"^(可以|适合)(写|放进|解释|证明|拆成|回扣)?[：: ]*", "", item).strip()
        if text and text not in takeaway:
            takeaway = video_notes.compact_text(text, 72)
            break
    if not takeaway:
        takeaway = "先判断这条视频能不能支撑一篇稿，再决定是否展开。"

    return {
        "headline": normalize_video_material_copy(headline, role="headline"),
        "bullets": [normalize_video_material_copy(item, role="bullet") for item in cleaned_points[:3]],
        "takeaway": normalize_video_material_copy(takeaway),
        "evidenceMode": infer_video_evidence_mode(timeline),
        "productLens": video_product_lens(
            title=title,
            route_source=route_source,
            timeline=timeline,
            route_kind=route_kind,
            is_tutorial=is_tutorial,
        ),
    }


def video_source_status(video_embed: dict[str, Any], *, frame_count: int = 0) -> str:
    embed_type = str(video_embed.get("type") or "")
    frame_status = f"截图 {frame_count} 张已保存。" if frame_count else "未抓到截图。"
    if embed_type == "youtube":
        return f"YouTube 内嵌播放，未保存完整视频；{frame_status}"
    if embed_type == "bilibili":
        return f"B站内嵌播放，未保存完整视频；{frame_status}"
    if embed_type == "local":
        size_text = ""
        local_path = normalize_space(str(video_embed.get("localPath") or ""))
        if local_path:
            try:
                size = Path(local_path).stat().st_size
                video_embed["localBytes"] = size
                size_text = f" · {size / 1024 / 1024:.1f} MB"
            except OSError:
                size_text = ""
        return f"已下载到本地{size_text}；{frame_status}"
    if video_embed.get("thumbnailUrl") and video_embed.get("watchUrl"):
        return "只保存封面和原链接。"
    if video_embed.get("watchUrl"):
        return "只保留原链接。"
    return ""


class VideoLocalDownloadRequiredError(RuntimeError):
    def __init__(self, embed_type: str, notes: str) -> None:
        self.public_message = "视频下载失败，已停止分析。这个链接没有保存成本地视频。"
        detail = f"当前只拿到 {embed_type}，没有本地视频文件"
        if notes:
            detail = f"{detail}；{notes}"
        self.debug_detail = detail
        super().__init__(self.public_message)


def public_exception_message(exc: Exception) -> str:
    return normalize_space(str(getattr(exc, "public_message", "") or str(exc)))


def debug_exception_message(exc: Exception) -> str:
    return normalize_space(str(getattr(exc, "debug_detail", "") or str(exc)))


def public_video_job_error_message(exc: Exception) -> str:
    if isinstance(exc, VideoLocalDownloadRequiredError):
        return public_exception_message(exc)
    detail = debug_exception_message(exc)
    if re.search(r"yt-dlp|YoutubeDL|Video unavailable|No video formats|Requested format|HTTP Error|ERROR:|bilibili|youtube", detail, re.I):
        return "视频资料抓取失败。这个链接暂时不可用、需要登录，或平台没有返回可下载视频。"
    return public_exception_message(exc)


def video_analysis_platform_from_url(url: str) -> str:
    parsed = urlparse(str(url or ""))
    host = parsed.netloc.lower()
    if "youtube.com" in host or "youtu.be" in host:
        return "youtube"
    if "bilibili.com" in host or "b23.tv" in host:
        return "bilibili"
    return ""


def build_video_failure_diagnosis(
    *,
    url: str = "",
    message: str = "",
    error: str = "",
    kind: str = "",
    cookies_from_browser: str = "",
) -> dict[str, Any]:
    platform = video_analysis_platform_from_url(url)
    raw = normalize_space(f"{message} {error}")
    browser_cookies_used = normalize_space(cookies_from_browser).lower() not in {"", "none", "false", "0"}
    detected = kind or ""
    if not detected:
        if url and not is_supported_video_analysis_url(url):
            detected = "unsupported_platform"
        elif re.search(r"超过 \d+ 秒|timeout|timed out|停止等待", raw, re.I):
            detected = "timeout"
        elif re.search(r"debug\(\) got an unexpected keyword argument 'once'|unexpected keyword argument ['\"]once['\"]", raw, re.I):
            detected = "downloader_runtime"
        elif re.search(r"KeyError\(['\"]bvid['\"]\)|extractor error.*bvid|invalid bvid", raw, re.I):
            detected = "fetch_failed"
        elif re.search(r"Video unavailable|This video is unavailable|Private video|removed by the uploader", raw, re.I):
            detected = "fetch_failed"
        elif re.search(r"视频下载失败|没有本地视频文件|没有保存成本地|video-download|yt-dlp-video-download-failed", raw, re.I):
            detected = "download_required"
        elif re.search(r"not a bot|Sign in to confirm|page needs to be reloaded|反机器人|需要登录|登录验证", raw, re.I):
            detected = "download_required"
        elif re.search(r"Requested format is not available|No video formats|format is not available|SABR|PO Token|HTTP Error 403|403 Forbidden", raw, re.I):
            detected = "download_required"
        elif re.search(r"yt-dlp|YoutubeDL|Video unavailable|No video formats|HTTP Error|需要登录|平台没有返回可下载视频", raw, re.I):
            detected = "fetch_failed"
        else:
            detected = "unknown"

    platform_label = {"youtube": "YouTube", "bilibili": "B站"}.get(platform, "这个平台")
    if detected == "unsupported_platform":
        return {
            "kind": detected,
            "platform": platform,
            "title": "暂不支持这个链接",
            "reason": "目前只稳定处理 YouTube 和 B站。",
            "canRetry": False,
            "nextActions": ["换成 YouTube 或 B站链接", "确认链接能公开访问"],
        }
    if detected == "timeout":
        if browser_cookies_used and platform in {"youtube", "bilibili"}:
            return {
                "kind": detected,
                "platform": platform,
                "title": "保存视频超时",
                "reason": "已经尝试使用浏览器登录状态，但本地保存视频超过等待时间。",
                "canRetry": True,
                "nextActions": ["重跑一次", "换一个更短的视频验证链路", "换网络后重试", "改用本地视频上传"],
                "auth": cookies_from_browser,
            }
        return {
            "kind": detected,
            "platform": platform,
            "title": "下载超时",
            "reason": "本地等待时间用完了，任务已停止，没有继续占用后台。",
            "canRetry": True,
            "nextActions": ["重跑一次", "换一个更短或更稳定的视频", "确认网络和平台访问正常"],
        }
    if detected == "downloader_runtime":
        return {
            "kind": detected,
            "platform": platform,
            "title": "下载器版本不兼容",
            "reason": "yt-dlp 或 PO Token provider 的版本不匹配，下载器在启动时就报错。",
            "canRetry": True,
            "nextActions": ["更新 yt-dlp 和 PO Token provider 后重跑", "重启工作台服务", "换一个公开短视频做连通性测试"],
        }
    if detected == "download_required":
        needs_login = bool(re.search(r"not a bot|Sign in to confirm|cookies-from-browser|需要登录|登录|bot", raw, re.I))
        no_format = bool(re.search(r"Requested format is not available|No video formats|format is not available", raw, re.I))
        needs_reload = bool(re.search(r"page needs to be reloaded|Failed to extract any player response", raw, re.I))
        network_tls = bool(re.search(r"EOF occurred in violation of protocol|SSLEOFError|Read timed out|Connection reset|TLS", raw, re.I))
        no_ffmpeg = bool(re.search(r"no-ffmpeg|ffmpeg=missing", raw, re.I))
        has_po_provider = bool(re.search(r"po-token-provider=ok", raw, re.I))
        missing_po_provider = bool(re.search(r"po-token-provider=missing", raw, re.I))
        http_403 = bool(re.search(r"HTTP Error 403|403 Forbidden|SABR|PO Token", raw, re.I))
        if needs_login:
            title = "平台要求登录验证"
            if browser_cookies_used:
                title = "平台仍要求验证"
                reason = f"已经尝试使用浏览器登录状态，但 {platform_label} 仍要求真人验证或拦截媒体流。"
                next_actions = ["先在 Chrome 里确认这个视频能播放", "重跑一次", "换同平台另一个公开视频测试", "改用本地视频上传"]
            elif platform == "youtube" and http_403 and has_po_provider:
                reason = "YouTube 已读取本机 Chrome 登录，但媒体流仍被平台 403 拦下。"
                next_actions = ["确认 Chrome 里这个视频能直接播放", "换同平台另一个公开视频测试", "如果仍失败，换网络或使用本地上传视频"]
            elif platform == "youtube" and missing_po_provider:
                reason = "YouTube 要求登录或反机器人验证，本地下载被拦下；当前还缺 PO Token provider。"
                next_actions = ["使用 Chrome 登录后重跑", "安装或启用 PO Token provider", "换一个不需要登录验证的公开视频"]
            else:
                reason = f"{platform_label} 要求登录或反机器人验证，本地下载被拦下。"
                next_actions = ["使用 Chrome 登录后重跑", "先在浏览器确认这个视频可直接播放", "必要时换同平台另一个公开视频"]
        elif no_ffmpeg:
            title = "本机缺少视频工具"
            reason = "本机没有可用 ffmpeg，无法保存和校验视频文件。"
            next_actions = ["安装 ffmpeg 后重跑", "换一台已配置视频工具的机器", "先上传本地视频文件"]
        elif needs_reload:
            title = "平台页面验证失败"
            reason = f"{platform_label} 返回的播放页没有稳定给出媒体信息，下载器要求重新加载或更换客户端路径。"
            next_actions = [f"重跑这个 {platform_label} 链接", "先在 Chrome 里打开并确认能播放", "如果还是失败，换同平台另一个公开视频"]
        elif network_tls:
            title = "网络连接中断"
            reason = "下载时网络或 TLS 连接被中断，媒体流没有稳定保存到本地。"
            next_actions = ["重跑一次", "换一个更稳定的网络或代理节点", "换一个更短的公开视频验证链路"]
        elif no_format:
            title = "没有可下载格式"
            reason = f"{platform_label} 没有返回可保存的视频格式，本地下载被拦下。"
            next_actions = [f"重跑这个 {platform_label} 链接", "换一个公开可播放的视频", "确认视频能在浏览器正常播放"]
        elif platform == "bilibili":
            title = "没有下载到本地视频"
            reason = "B站没有保存成本地视频，常见原因是风控、登录验证、权限或视频源限制。"
            next_actions = [f"重跑这个 {platform_label} 链接", "换一个公开可播放的视频", "如果平台需要登录，先在浏览器确认能正常播放"]
        elif platform == "youtube":
            title = "没有下载到本地视频"
            reason = "YouTube 没有保存成本地视频，常见原因是网络、权限或下载器没有拿到可用格式。"
            next_actions = [f"重跑这个 {platform_label} 链接", "换一个公开可播放的视频", "如果平台需要登录，先在浏览器确认能正常播放"]
        else:
            title = "没有下载到本地视频"
            reason = "没有拿到本地视频文件，所以不继续生成总结和拆解。"
            next_actions = [f"重跑这个 {platform_label} 链接", "换一个公开可播放的视频", "如果平台需要登录，先在浏览器确认能正常播放"]
        return {
            "kind": detected,
            "platform": platform,
            "title": title,
            "reason": reason,
            "canRetry": True,
            "nextActions": next_actions,
            "auth": cookies_from_browser if browser_cookies_used else "",
        }
    if detected == "fetch_failed":
        return {
            "kind": detected,
            "platform": platform,
            "title": "视频资料没拿到",
            "reason": f"{platform_label} 没有返回可下载的视频资料，可能需要登录、权限不足，或视频不可用。",
            "canRetry": True,
            "nextActions": ["确认链接能公开播放", "重跑一次", "换同平台另一个视频测试"],
        }
    return {
        "kind": detected,
        "platform": platform,
        "title": "处理失败",
        "reason": normalize_space(message) or "这个任务没有成功完成。",
        "canRetry": True,
        "nextActions": ["重跑一次", "换一个 YouTube 或 B站链接"],
    }


def cached_download_policy_from_previous(
    previous: dict[str, Any],
    *,
    reason: str = "",
    cookies_from_browser: str = "",
) -> dict[str, Any]:
    previous_summary = previous.get("summary") if isinstance(previous.get("summary"), dict) else {}
    previous_policy = previous_summary.get("downloadPolicy") if isinstance(previous_summary.get("downloadPolicy"), dict) else {}
    video_embed = previous_summary.get("videoEmbed") if isinstance(previous_summary.get("videoEmbed"), dict) else {}
    local_path = normalize_space(str(video_embed.get("localPath") or previous_policy.get("localVideoPath") or ""))
    local_bytes = previous_policy.get("localVideoBytes") or video_embed.get("localBytes") or 0
    try:
        if local_path and not local_bytes:
            local_bytes = Path(local_path).expanduser().stat().st_size
    except OSError:
        local_bytes = 0
    cookie_source = normalize_space(str(cookies_from_browser or previous.get("cookiesFromBrowser") or "none")).lower()
    browser_cookies = normalize_space(str(previous_policy.get("browserCookies") or ""))
    auth_source = normalize_space(str(previous_policy.get("auth") or ""))
    if cookie_source and cookie_source != "none":
        browser_cookies = cookie_source
        auth_source = f"browser:{cookie_source}"
    elif not auth_source:
        auth_source = "none"
    policy = dict(previous_policy)
    policy.update(
        {
            "required": True,
            "status": "cached",
            "auth": auth_source,
            "browserCookies": browser_cookies,
            "cacheReuse": True,
            "cacheJobId": previous.get("id") or "",
            "cacheReason": video_notes.compact_text(reason, 180),
            "localVideoPath": local_path,
            "localVideoBytes": local_bytes,
        }
    )
    return policy


def infer_saved_download_policy_from_local_embed(
    video_embed: dict[str, Any],
    *,
    platform: str = "",
    required: bool = True,
    auth: str = "",
) -> dict[str, Any]:
    if not isinstance(video_embed, dict) or video_embed.get("type") != "local":
        return {}
    local_path = normalize_space(str(video_embed.get("localPath") or ""))
    if not local_path:
        local_path = local_path_from_video_asset(str(video_embed.get("src") or ""))
    if not local_path:
        return {}
    try:
        local_bytes = Path(local_path).expanduser().stat().st_size
    except OSError:
        return {}
    platform_value = normalize_space(str(platform or ""))
    watch_url = normalize_space(str(video_embed.get("watchUrl") or ""))
    if not platform_value:
        platform_value = video_notes.detect_platform(watch_url) if watch_url else ""
    auth_value = normalize_space(str(auth or ""))
    if not auth_value:
        auth_value = "none"
    return {
        "required": bool(required),
        "status": "saved",
        "platform": platform_value or "unknown",
        "auth": auth_value,
        "browserCookies": auth_value.replace("browser:", "") if auth_value.startswith("browser:") else "",
        "cacheReuse": False,
        "localVideoPath": local_path,
        "localVideoBytes": local_bytes,
        "inferredFromLocalVideo": True,
    }


def build_cached_video_job_record_from_previous(
    base: dict[str, Any],
    previous: dict[str, Any],
    *,
    reason: str = "",
    cookies_from_browser: str = "",
    message: str = "已使用本地缓存",
    event_message: str = "已复用本地缓存",
) -> dict[str, Any]:
    previous_summary = previous.get("summary") if isinstance(previous.get("summary"), dict) else {}
    require_local_video_embed(previous_summary)
    normalize_required_video_source_status(previous_summary)
    cached_summary = copy.deepcopy(previous_summary)
    cached_summary["downloadPolicy"] = cached_download_policy_from_previous(
        previous,
        reason=reason,
        cookies_from_browser=cookies_from_browser,
    )
    cached_summary["sourceStatus"] = video_source_status(
        cached_summary.get("videoEmbed") if isinstance(cached_summary.get("videoEmbed"), dict) else {},
        frame_count=len(cached_summary.get("frames") if isinstance(cached_summary.get("frames"), list) else []),
    )
    title = normalize_space(
        str(
            (previous.get("result") if isinstance(previous.get("result"), dict) else {}).get("title")
            or previous.get("title")
            or base.get("title")
            or ""
        )
    )
    unsuitable_reason = video_material_unsuitable_reason(
        title,
        " ".join(
            [
                title,
                normalize_space(str((cached_summary.get("videoSummary") or {}).get("headline") if isinstance(cached_summary.get("videoSummary"), dict) else "")),
                " ".join(
                    normalize_space(str(item.get("summary") or item.get("transcriptExcerpt") or ""))
                    for item in (cached_summary.get("timeline") if isinstance(cached_summary.get("timeline"), list) else [])
                    if isinstance(item, dict)
                ),
            ]
        ),
    )
    if unsuitable_reason:
        cached_summary["videoSummary"] = {
            "headline": unsuitable_reason,
            "bullets": [],
            "takeaway": "换一个教程、访谈、观点或产品演示类视频。",
            "evidenceMode": "blocked",
            "contentSuitability": {"status": "unsuitable", "reason": unsuitable_reason},
        }
        cached_summary["demoDeck"] = build_video_demo_deck(
            title=title or "这条视频",
            video_summary=cached_summary["videoSummary"],
            timeline=cached_summary.get("timeline") if isinstance(cached_summary.get("timeline"), list) else [],
            video_embed=cached_summary.get("videoEmbed") if isinstance(cached_summary.get("videoEmbed"), dict) else {},
            visual_notes=cached_summary.get("visualNotes") if isinstance(cached_summary.get("visualNotes"), list) else [],
            transcript_quality=cached_summary.get("transcriptQuality") if isinstance(cached_summary.get("transcriptQuality"), dict) else {},
        )
    demo_deck = cached_summary.get("demoDeck") if isinstance(cached_summary.get("demoDeck"), dict) else {}
    if demo_deck:
        demo_deck["sourceStatus"] = cached_summary["sourceStatus"]
    ensure_video_material_acceptance(cached_summary)
    ensure_video_material_state(cached_summary)
    cached_summary.setdefault("videoTimelineVersion", VIDEO_TIMELINE_VERSION)
    cached_summary.setdefault("videoSummaryVersion", VIDEO_SUMMARY_VERSION)
    cached_summary.setdefault("demoDeckVersion", DEMO_DECK_VERSION)
    cached_summary.setdefault("captionSelectionVersion", VIDEO_CAPTION_SELECTION_VERSION)
    cached_summary.setdefault("writingCardsVersion", 3)
    cached_summary.setdefault("writingPackVersion", 4)
    cached = dict(base)
    cached["status"] = "done"
    cached["stage"] = "done"
    cached["message"] = message
    cached["updatedAt"] = utc_now()
    cached["finishedAt"] = cached.get("finishedAt") or utc_now()
    cached["result"] = previous.get("result") or {}
    cached["files"] = previous.get("files") or {}
    cached["summary"] = cached_summary
    cached["downloadPolicy"] = cached_summary.get("downloadPolicy") or {}
    cached["videoEmbed"] = cached_summary.get("videoEmbed") or cached.get("videoEmbed")
    cached["timeline"] = cached_summary.get("timeline") or cached.get("timeline") or []
    cached["demoDeck"] = cached_summary.get("demoDeck") or cached.get("demoDeck") or {}
    cached["frames"] = cached_summary.get("frames") or cached.get("frames") or []
    for key in (
        "noteMarkdown",
        "transcriptMarkdown",
        "rewritesMarkdown",
        "transcriptSource",
        "transcript_source",
        "timeline",
        "videoEmbed",
        "demoDeck",
        "captionFiles",
        "transcriptNotes",
        "frames",
        "coreClaim",
        "angles",
    ):
        if key in previous:
            cached[key] = previous[key]
    cached.setdefault("events", []).append(
        {
            "at": utc_now(),
            "stage": "cache-fallback",
            "message": event_message,
            "extra": {"fallbackJobId": previous.get("id")},
        }
    )
    return cached


def local_video_embed_is_ready(video_embed: dict[str, Any]) -> bool:
    return bool(
        isinstance(video_embed, dict)
        and video_embed.get("type") == "local"
        and normalize_space(str(video_embed.get("src") or ""))
    )


def prefer_local_video_embed(current: dict[str, Any], fallback: dict[str, Any]) -> dict[str, Any]:
    current_embed = current if isinstance(current, dict) else {}
    fallback_embed = fallback if isinstance(fallback, dict) else {}
    if local_video_embed_is_ready(current_embed):
        return {**fallback_embed, **current_embed}
    if local_video_embed_is_ready(fallback_embed):
        return {**current_embed, **fallback_embed}
    return {**fallback_embed, **current_embed}


def preserve_local_video_material(existing: dict[str, Any], rebuilt: dict[str, Any]) -> dict[str, Any]:
    if not isinstance(existing, dict) or not isinstance(rebuilt, dict):
        return rebuilt
    existing_embed = existing.get("videoEmbed") if isinstance(existing.get("videoEmbed"), dict) else {}
    rebuilt_embed = rebuilt.get("videoEmbed") if isinstance(rebuilt.get("videoEmbed"), dict) else {}
    if not local_video_embed_is_ready(existing_embed):
        return rebuilt

    preserved = dict(rebuilt)
    if not local_video_embed_is_ready(rebuilt_embed):
        preserved["videoEmbed"] = existing_embed
    else:
        preserved["videoEmbed"] = prefer_local_video_embed(rebuilt_embed, existing_embed)
    for key in ("downloadPolicy", "sourceStatus"):
        if existing.get(key) and not preserved.get(key):
            preserved[key] = copy.deepcopy(existing[key])
    existing_frames = existing.get("frames") if isinstance(existing.get("frames"), list) else []
    if existing_frames and not isinstance(preserved.get("frames"), list):
        preserved["frames"] = copy.deepcopy(existing_frames)
    return preserved


def require_local_video_embed(summary: dict[str, Any]) -> None:
    video_embed = summary.get("videoEmbed") if isinstance(summary.get("videoEmbed"), dict) else {}
    if video_embed.get("type") == "local" and normalize_space(str(video_embed.get("src") or "")):
        return
    embed_type = normalize_space(str(video_embed.get("type") or "none"))
    notes = " / ".join(
        normalize_space(str(note))
        for note in summary.get("visualNotes", [])
        if normalize_space(str(note))
    )
    raise VideoLocalDownloadRequiredError(embed_type, notes)


def parse_video_time_to_seconds(value: Any) -> float | None:
    if value is None:
        return None
    if isinstance(value, (int, float)):
        return float(value) if value >= 0 else None
    text = normalize_space(str(value))
    if not text:
        return None
    try:
        if ":" in text:
            return float(video_notes.parse_clock_to_seconds(text))
        seconds = float(text)
        return seconds if seconds >= 0 else None
    except (TypeError, ValueError):
        return None


def demo_deck_target_frame_seconds(summary: dict[str, Any], *, max_targets: int = 12) -> list[float]:
    targets: list[float] = []
    demo_deck = summary.get("demoDeck") if isinstance(summary.get("demoDeck"), dict) else {}
    slides = demo_deck.get("slides") if isinstance(demo_deck.get("slides"), list) else []
    for slide in slides:
        if not isinstance(slide, dict):
            continue
        seconds = parse_video_time_to_seconds(slide.get("start"))
        if seconds is None:
            seconds = parse_video_time_to_seconds(slide.get("timeLabel"))
        if seconds is None:
            continue
        rounded = float(round(seconds))
        if rounded not in targets:
            targets.append(rounded)
        if len(targets) >= max_targets:
            break
    if len(targets) < min(4, max_targets):
        timeline = summary.get("timeline") if isinstance(summary.get("timeline"), list) else []
        for item in timeline:
            if not isinstance(item, dict):
                continue
            seconds = parse_video_time_to_seconds(item.get("start"))
            if seconds is None:
                seconds = parse_video_time_to_seconds(item.get("timeLabel"))
            if seconds is None:
                continue
            rounded = float(round(seconds))
            if rounded not in targets:
                targets.append(rounded)
            if len(targets) >= max_targets:
                break
    return targets


def extract_target_frames_from_local_video(
    *,
    local_video_path: str,
    target_seconds: list[float],
    frames_dir: Path,
) -> tuple[list[dict[str, Any]], list[str]]:
    notes: list[str] = []
    assets: list[dict[str, Any]] = []
    video_path = Path(local_video_path).expanduser()
    if not video_path.exists():
        return assets, ["target-frame-extraction-skipped:no-local-video"]
    ffmpeg_bin = video_notes.resolve_binary("ffmpeg")
    if ffmpeg_bin is None:
        return assets, ["target-frame-extraction-skipped:no-ffmpeg"]
    frames_dir.mkdir(parents=True, exist_ok=True)
    normalized_targets = video_notes.normalize_target_frame_seconds(target_seconds, 20)
    for index, timestamp in enumerate(normalized_targets):
        safe_timestamp = int(round(float(timestamp)))
        frame_path = frames_dir / f"target-frame-{index + 1:03d}-{safe_timestamp:06d}.jpg"
        command = [
            ffmpeg_bin,
            "-hide_banner",
            "-loglevel",
            "error",
            "-y",
            "-ss",
            str(timestamp),
            "-i",
            str(video_path),
            "-frames:v",
            "1",
            str(frame_path),
        ]
        result = subprocess.run(command, capture_output=True, text=True)
        if result.returncode != 0 or not frame_path.exists():
            notes.append(
                f"target-frame-extraction-failed:{video_notes.format_timestamp(timestamp)}:{video_notes.compact_text(result.stderr, 140)}"
            )
            continue
        assets.append(
            {
                "type": "frame",
                "path": str(frame_path),
                "source": "ffmpeg-targeted-local",
                "timestamp": float(timestamp),
            }
        )
    if assets:
        notes.append("target-frame-extraction:local-video")
    elif normalized_targets:
        notes.append("target-frame-extraction-produced-no-assets")
    return assets, notes


def frame_asset_from_path(asset: dict[str, Any]) -> dict[str, Any] | None:
    path_value = normalize_space(str(asset.get("path") or ""))
    if not path_value:
        return None
    frame_path = Path(path_value)
    if not frame_path.exists():
        return None
    timestamp = asset.get("timestamp")
    try:
        timestamp_value = float(timestamp)
    except (TypeError, ValueError):
        timestamp_value = None
    return {
        "timestamp": timestamp_value,
        "label": video_notes.format_timestamp(timestamp_value or 0),
        "url": workspace_file_url(frame_path),
        "source": normalize_space(str(asset.get("source") or "ffmpeg")),
    }


def maybe_enhance_video_summary_frames(summary: dict[str, Any], *, _depth: int = 0) -> bool:
    if not isinstance(summary, dict):
        return False
    demo_deck = summary.get("demoDeck") if isinstance(summary.get("demoDeck"), dict) else {}
    quality = demo_deck.get("demoDeckQuality") if isinstance(demo_deck.get("demoDeckQuality"), dict) else {}
    issues = " ".join(str(item) for item in quality.get("issues") or [])
    has_frame_timing_issue = demo_deck_has_frame_timing_issue(summary)
    if not has_frame_timing_issue and not re.search(r"截图区分度不够|补关键帧|画面|截图|时间点偏离|配图时间", issues):
        return False
    video_embed = summary.get("videoEmbed") if isinstance(summary.get("videoEmbed"), dict) else {}
    local_path = normalize_space(str(video_embed.get("localPath") or ""))
    if video_embed.get("type") != "local" or not local_path:
        return False
    targets = demo_deck_target_frame_seconds(summary, max_targets=12)
    if len(targets) < 3:
        return False
    current_frames = summary.get("frames") if isinstance(summary.get("frames"), list) else []
    current_timestamps: set[int] = set()
    for frame in current_frames:
        if not isinstance(frame, dict):
            continue
        timestamp = parse_video_time_to_seconds(frame.get("timestamp"))
        if timestamp is not None:
            current_timestamps.add(int(round(timestamp)))
    missing_targets = [seconds for seconds in targets if int(round(seconds)) not in current_timestamps]
    new_frames: list[dict[str, Any]] = []
    frames_dir = Path(local_path).expanduser().resolve().parent / "frames"
    notes: list[str] = []
    if missing_targets or len(current_timestamps) < min(len(targets), 4):
        assets, notes = extract_target_frames_from_local_video(
            local_video_path=local_path,
            target_seconds=targets,
            frames_dir=frames_dir,
        )
        new_frames = [frame for asset in assets if (frame := frame_asset_from_path(asset))]
        if not new_frames:
            if notes:
                visual_notes = summary.get("visualNotes") if isinstance(summary.get("visualNotes"), list) else []
                summary["visualNotes"] = list(visual_notes) + [note for note in notes if note not in visual_notes]
            return False
    merged_by_timestamp: dict[int, dict[str, Any]] = {}
    for frame in current_frames + new_frames:
        if not isinstance(frame, dict):
            continue
        timestamp = parse_video_time_to_seconds(frame.get("timestamp"))
        if timestamp is None:
            continue
        key = int(round(timestamp))
        merged_by_timestamp[key] = dict(frame)
    merged_frames = [merged_by_timestamp[key] for key in sorted(merged_by_timestamp)]
    summary["frames"] = merged_frames
    timeline = summary.get("timeline") if isinstance(summary.get("timeline"), list) else []
    if timeline:
        updated_timeline = []
        for item in timeline:
            if not isinstance(item, dict):
                continue
            updated_item = dict(item)
            seconds = parse_video_time_to_seconds(updated_item.get("start"))
            if seconds is None:
                seconds = parse_video_time_to_seconds(updated_item.get("timeLabel")) or 0
            frame = nearest_video_frame(merged_frames, seconds)
            if frame:
                updated_item["frameUrl"] = normalize_video_asset_url(str(frame.get("url") or ""))
                updated_item["frameLabel"] = normalize_space(str(frame.get("label") or video_notes.format_timestamp(seconds)))
            updated_timeline.append(updated_item)
        summary["timeline"] = updated_timeline
    video_summary = summary.get("videoSummary") if isinstance(summary.get("videoSummary"), dict) else {}
    title = normalize_space(str(video_summary.get("headline") or summary.get("coreClaim") or "这条视频"))
    summary["demoDeck"] = build_video_demo_deck(
        title=title,
        video_summary=video_summary_with_frame_candidates(video_summary, summary.get("frames")),
        timeline=summary.get("timeline") if isinstance(summary.get("timeline"), list) else [],
        video_embed=video_embed,
        visual_notes=summary.get("visualNotes") if isinstance(summary.get("visualNotes"), list) else [],
    )
    transcript_quality = summary.get("transcriptQuality") if isinstance(summary.get("transcriptQuality"), dict) else {}
    summary["materialAcceptance"] = build_video_material_acceptance(
        video_embed=video_embed,
        frames=merged_frames,
        transcript_quality=transcript_quality,
        demo_deck=summary["demoDeck"],
        timeline=summary.get("timeline") if isinstance(summary.get("timeline"), list) else [],
    )
    ensure_video_material_state(summary)
    visual_notes = summary.get("visualNotes") if isinstance(summary.get("visualNotes"), list) else []
    summary["visualNotes"] = list(visual_notes) + [note for note in notes if note not in visual_notes]
    normalize_required_video_source_status(summary)
    if _depth < 2 and demo_deck_has_frame_timing_issue(summary):
        maybe_enhance_video_summary_frames(summary, _depth=_depth + 1)
    return True


def demo_deck_has_frame_timing_issue(summary: dict[str, Any], *, max_delta_seconds: float = 75.0) -> bool:
    if not isinstance(summary, dict):
        return False
    frames = summary.get("frames") if isinstance(summary.get("frames"), list) else []
    frame_timestamps: dict[str, float] = {}
    for frame in frames:
        if not isinstance(frame, dict):
            continue
        url = normalize_video_asset_url(str(frame.get("url") or frame.get("frameUrl") or ""))
        timestamp = parse_video_time_to_seconds(frame.get("timestamp"))
        if url and timestamp is not None:
            frame_timestamps[url] = float(timestamp)
    if not frame_timestamps:
        return False
    demo_deck = summary.get("demoDeck") if isinstance(summary.get("demoDeck"), dict) else {}
    slides = demo_deck.get("slides") if isinstance(demo_deck.get("slides"), list) else []
    for slide in slides:
        if not isinstance(slide, dict):
            continue
        if normalize_space(str(slide.get("frameKind") or "")) != "screenshot":
            continue
        frame_url = normalize_video_asset_url(str(slide.get("frameUrl") or ""))
        frame_timestamp = parse_video_time_to_seconds(slide.get("frameTimestamp"))
        if frame_timestamp is None and frame_url:
            frame_timestamp = frame_timestamps.get(frame_url)
        start_seconds = parse_video_time_to_seconds(slide.get("startSeconds"))
        if start_seconds is None:
            start_seconds = parse_video_time_to_seconds(slide.get("start"))
        if start_seconds is None:
            start_seconds = parse_video_time_to_seconds(slide.get("timeLabel"))
        if frame_timestamp is None or start_seconds is None:
            continue
        if abs(float(frame_timestamp) - float(start_seconds)) > max_delta_seconds:
            return True
    return False


def normalize_required_video_source_status(summary: dict[str, Any]) -> bool:
    if not isinstance(summary, dict):
        return False
    video_embed = summary.get("videoEmbed") if isinstance(summary.get("videoEmbed"), dict) else {}
    frames = summary.get("frames") if isinstance(summary.get("frames"), list) else []
    source_status = video_source_status(video_embed, frame_count=len(frames))
    changed = False
    demo_deck = summary.get("demoDeck") if isinstance(summary.get("demoDeck"), dict) else {}
    if source_status and isinstance(demo_deck, dict) and demo_deck.get("sourceStatus") != source_status:
        demo_deck["sourceStatus"] = source_status
        changed = True
    if source_status and summary.get("sourceStatus") != source_status:
        summary["sourceStatus"] = source_status
        changed = True
    download_policy = summary.get("downloadPolicy") if isinstance(summary.get("downloadPolicy"), dict) else {}
    if not download_policy.get("status"):
        inferred_policy = infer_saved_download_policy_from_local_embed(
            video_embed,
            platform=str(summary.get("platform") or ""),
            required=True,
            auth=str(summary.get("auth") or ""),
        )
        if inferred_policy:
            summary["downloadPolicy"] = inferred_policy
            changed = True
    return changed


def ensure_video_material_acceptance(summary: dict[str, Any]) -> bool:
    if not isinstance(summary, dict):
        return False
    previous_acceptance = summary.get("materialAcceptance") if isinstance(summary.get("materialAcceptance"), dict) else {}
    video_embed = summary.get("videoEmbed") if isinstance(summary.get("videoEmbed"), dict) else {}
    frames = summary.get("frames") if isinstance(summary.get("frames"), list) else []
    transcript_quality = summary.get("transcriptQuality") if isinstance(summary.get("transcriptQuality"), dict) else {}
    if not transcript_quality:
        transcript_quality = assess_video_transcript_quality(
            transcript_source=str(summary.get("transcriptSource") or ""),
            transcript_segments=[],
            timeline=summary.get("timeline") if isinstance(summary.get("timeline"), list) else [],
            visual_notes=summary.get("visualNotes") if isinstance(summary.get("visualNotes"), list) else [],
        )
        summary["transcriptQuality"] = transcript_quality
    demo_deck = summary.get("demoDeck") if isinstance(summary.get("demoDeck"), dict) else {}
    timeline = summary.get("timeline") if isinstance(summary.get("timeline"), list) else []
    next_acceptance = build_video_material_acceptance(
        video_embed=video_embed,
        frames=frames,
        transcript_quality=transcript_quality,
        demo_deck=demo_deck,
        timeline=timeline,
    )
    if previous_acceptance == next_acceptance:
        return ensure_video_material_state(summary)
    summary["materialAcceptance"] = next_acceptance
    ensure_video_material_state(summary)
    return True


def assess_video_transcript_quality(
    *,
    transcript_source: str,
    transcript_segments: list[dict[str, Any]],
    timeline: list[dict[str, Any]],
    visual_notes: list[str] | None = None,
) -> dict[str, Any]:
    source = normalize_space(transcript_source).lower()
    notes = [normalize_space(str(note)).lower() for note in (visual_notes or [])]
    real_segments = [
        item
        for item in transcript_segments
        if isinstance(item, dict) and has_real_video_transcript_excerpt(str(item.get("text") or item.get("transcriptExcerpt") or ""))
    ]
    real_timeline = [
        item
        for item in timeline
        if isinstance(item, dict) and has_real_video_transcript_excerpt(str(item.get("transcriptExcerpt") or ""))
    ]
    if not source or source == "none" or (not real_segments and not real_timeline):
        return {
            "level": "none",
            "label": "无字幕",
            "usable": False,
            "fallback": "先保留视频和截图，补到字幕后再写。",
            "segmentCount": 0,
        }
    segment_count = len(real_segments) or len(real_timeline)
    is_asr = "whisper" in source or "asr" in source or "转写" in source
    is_auto = "auto" in source or "ai-zh" in source or any("automatic" in note for note in notes)
    if segment_count < 5:
        level = "weak"
        label = "字幕待确认"
        fallback = "字幕太少，会用截图和时间线补判断。"
    elif is_asr or is_auto:
        level = "medium"
        label = "AI字幕"
        fallback = "能用，但关键句最好回看视频确认。"
    else:
        level = "strong"
        label = "字幕可靠"
        fallback = "可以作为主要拆解依据。"
    return {
        "level": level,
        "label": label,
        "usable": level in {"medium", "strong"},
        "fallback": fallback,
        "segmentCount": segment_count,
        "source": transcript_source,
    }


def build_video_material_acceptance(
    *,
    video_embed: dict[str, Any],
    frames: list[dict[str, Any]],
    transcript_quality: dict[str, Any],
    demo_deck: dict[str, Any],
    timeline: list[dict[str, Any]],
) -> dict[str, Any]:
    checks: list[dict[str, Any]] = []

    def add_check(key: str, label: str, status: str, detail: str) -> None:
        checks.append(
            {
                "key": key,
                "label": label,
                "status": status,
                "detail": video_notes.compact_text(normalize_space(detail), 72),
            }
        )

    local_video = video_embed.get("type") == "local" and bool(normalize_space(str(video_embed.get("src") or "")))
    add_check(
        "video",
        "视频",
        "pass" if local_video else "fail",
        video_source_status(video_embed, frame_count=len(frames)) or "没有视频源。",
    )

    transcript_level = normalize_space(str(transcript_quality.get("level") or "none"))
    transcript_usable = bool(transcript_quality.get("usable"))
    transcript_status = "pass" if transcript_level in {"strong", "medium"} else "warn" if transcript_usable else "fail"
    add_check(
        "transcript",
        "字幕",
        transcript_status,
        str(transcript_quality.get("fallback") or transcript_quality.get("label") or "未拿到可用字幕。"),
    )

    evidence = demo_deck.get("evidenceStatus") if isinstance(demo_deck.get("evidenceStatus"), dict) else {}
    unique_screenshots = int(evidence.get("uniqueScreenshots") or 0)
    saved_frame_count = len(frames)
    if unique_screenshots >= 3:
        screenshot_status = "pass"
        screenshot_detail = str(evidence.get("label") or f"截图 {unique_screenshots} 张")
    elif saved_frame_count >= 3 and unique_screenshots > 0:
        screenshot_status = "pass"
        screenshot_detail = f"已保存 {saved_frame_count} 张；拆页使用 {unique_screenshots} 张"
    else:
        screenshot_status = "warn" if unique_screenshots > 0 or saved_frame_count > 0 else "fail"
        screenshot_detail = str(evidence.get("label") or f"截图 {unique_screenshots} 张")
    add_check("screenshots", "截图", screenshot_status, screenshot_detail)

    deck_quality = demo_deck.get("demoDeckQuality") if isinstance(demo_deck.get("demoDeckQuality"), dict) else {}
    slides = demo_deck.get("slides") if isinstance(demo_deck.get("slides"), list) else []
    strong_slides = int(deck_quality.get("strongSlideCount") or 0)
    quality_status = normalize_space(str(deck_quality.get("status") or ""))
    quality_score = float(deck_quality.get("score") or 0)
    slide_count = len(slides)
    deck_has_minimum_shape = slide_count >= 3 and strong_slides >= min(3, slide_count)
    issues = deck_quality.get("issues") if isinstance(deck_quality.get("issues"), list) else []
    no_quality_issues = not issues and (not quality_status or quality_status == "ready")
    if deck_has_minimum_shape and no_quality_issues and (quality_score >= 0.75 or not quality_score):
        deck_status = "pass"
    elif strong_slides:
        deck_status = "warn"
    else:
        deck_status = "fail"
    deck_detail = f"{strong_slides}/{slide_count} 页可直接讲" if slide_count else "没有形成演示页。"
    if issues:
        deck_detail = f"{deck_detail}；{issues[0]}"
    add_check("deck", "拆解", deck_status, deck_detail)

    timeline_status = "pass" if len(timeline) >= 3 else "warn" if timeline else "fail"
    add_check("timeline", "时间线", timeline_status, f"{len(timeline)} 段可回看")

    fail_count = sum(1 for item in checks if item["status"] == "fail")
    warn_count = sum(1 for item in checks if item["status"] == "warn")
    failed_keys = {str(item.get("key") or "") for item in checks if item.get("status") == "fail"}
    warned_keys = {str(item.get("key") or "") for item in checks if item.get("status") == "warn"}
    if fail_count:
        status = "blocked"
        if "video" in failed_keys:
            label = "没有视频"
            summary = "先把视频保存下来。"
        elif "transcript" in failed_keys:
            label = "缺字幕"
            summary = "视频已保存，但没有可用字幕；只能先看截图粗拆。"
        elif "screenshots" in failed_keys:
            label = "缺截图"
            summary = "视频已保存，但关键画面还不够。"
        else:
            label = "材料不够"
            summary = "材料还不完整，先补齐再写。"
    elif warn_count:
        status = "needs_work"
        if "transcript" in warned_keys:
            label = "字幕需确认"
            summary = "字幕不够稳，写前回看关键片段。"
        elif "screenshots" in warned_keys:
            label = "截图不足"
            summary = "视频已保存，但关键画面还不够。"
        else:
            label = "需确认"
            summary = "材料可用，关键句写前回看确认。"
    else:
        status = "ready"
        label = "材料够用"
        summary = "视频、字幕和截图都可以继续用。"
    return {
        "status": status,
        "label": label,
        "summary": summary,
        "checks": checks,
        "failCount": fail_count,
        "warnCount": warn_count,
    }


def build_video_material_state(
    *,
    video_embed: dict[str, Any],
    frames: list[dict[str, Any]],
    transcript_quality: dict[str, Any],
    demo_deck: dict[str, Any],
    timeline: list[dict[str, Any]],
    download_policy: dict[str, Any] | None = None,
) -> dict[str, Any]:
    policy = download_policy if isinstance(download_policy, dict) else {}
    local_video = video_embed.get("type") == "local" and bool(normalize_space(str(video_embed.get("src") or "")))
    local_bytes = video_embed.get("localBytes") or policy.get("localVideoBytes") or 0
    try:
        local_bytes_value = int(local_bytes or 0)
    except (TypeError, ValueError):
        local_bytes_value = 0
    video_detail = ""
    if local_video:
        video_detail = f"{local_bytes_value / 1024 / 1024:.1f} MB" if local_bytes_value else "已保存"
    else:
        video_detail = "未保存"

    transcript_level = normalize_space(str(transcript_quality.get("level") or "none"))
    transcript_count = int(transcript_quality.get("segmentCount") or 0)
    transcript_usable = bool(transcript_quality.get("usable"))
    if transcript_level in {"strong", "medium"}:
        transcript_status = "ready"
    elif transcript_usable:
        transcript_status = "warn"
    else:
        transcript_status = "missing"
    transcript_detail = f"{transcript_count} 段" if transcript_count else "未拿到"

    frame_count = len(frames)
    if frame_count >= 3:
        frame_status = "ready"
    elif frame_count > 0:
        frame_status = "warn"
    else:
        frame_status = "missing"

    deck_quality = demo_deck.get("demoDeckQuality") if isinstance(demo_deck.get("demoDeckQuality"), dict) else {}
    slides = demo_deck.get("slides") if isinstance(demo_deck.get("slides"), list) else []
    strong_slides = int(deck_quality.get("strongSlideCount") or 0)
    quality_status = normalize_space(str(deck_quality.get("status") or ""))
    if quality_status == "ready" and strong_slides >= min(3, len(slides) or 3):
        material_status = "ready"
    elif slides or timeline:
        material_status = "warn"
    else:
        material_status = "blocked"

    return {
        "video": {
            "status": "ready" if local_video else "missing",
            "label": "视频",
            "detail": video_detail,
        },
        "transcript": {
            "status": transcript_status,
            "label": "字幕",
            "detail": transcript_detail,
        },
        "frames": {
            "status": frame_status,
            "label": "截图",
            "detail": f"{frame_count} 张" if frame_count else "未抓到",
        },
        "material": {
            "status": material_status,
            "label": "材料",
            "detail": f"{strong_slides}/{len(slides)} 页可用" if slides else f"{len(timeline)} 段",
        },
    }


def ensure_video_material_state(summary: dict[str, Any]) -> bool:
    if not isinstance(summary, dict):
        return False
    video_embed = summary.get("videoEmbed") if isinstance(summary.get("videoEmbed"), dict) else {}
    frames = summary.get("frames") if isinstance(summary.get("frames"), list) else []
    transcript_quality = summary.get("transcriptQuality") if isinstance(summary.get("transcriptQuality"), dict) else {}
    demo_deck = summary.get("demoDeck") if isinstance(summary.get("demoDeck"), dict) else {}
    timeline = summary.get("timeline") if isinstance(summary.get("timeline"), list) else []
    download_policy = summary.get("downloadPolicy") if isinstance(summary.get("downloadPolicy"), dict) else {}
    next_state = build_video_material_state(
        video_embed=video_embed,
        frames=frames,
        transcript_quality=transcript_quality,
        demo_deck=demo_deck,
        timeline=timeline,
        download_policy=download_policy,
    )
    if summary.get("materialState") == next_state:
        return False
    summary["materialState"] = next_state
    return True


def has_real_video_transcript_excerpt(text: str) -> bool:
    value = normalize_space(text)
    if not value:
        return False
    return not bool(re.match(r"^(未拿到字幕|无字幕|No transcript|No transcript content resolved)", value, re.I))


def build_video_route_source(
    *,
    title: str,
    description_text: str,
    timeline: list[dict[str, Any]],
) -> tuple[str, bool]:
    transcript_parts: list[str] = []
    summary_parts: list[str] = []
    for item in timeline:
        if not isinstance(item, dict):
            continue
        transcript_value = normalize_space(str(item.get("transcriptExcerpt") or ""))
        summary_value = normalize_space(str(item.get("summary") or ""))
        if has_real_video_transcript_excerpt(transcript_value):
            transcript_parts.append(transcript_value)
        if usable_video_material_field(summary_value, role="summary"):
            summary_parts.append(summary_value)
    route_body = " ".join([*summary_parts, *transcript_parts]) if transcript_parts else " ".join(summary_parts)
    route_source = normalize_space(" ".join(part for part in (title, description_text, route_body) if part))
    return route_source, bool(transcript_parts)


def build_video_content_detection_source(
    *,
    title: str,
    description_text: str = "",
    timeline: list[dict[str, Any]] | None = None,
) -> str:
    """Build a conservative source for content classification.

    This intentionally excludes derived writing fields such as writingAngle and
    writingValue. Those fields are generated by this system and can otherwise
    feed back into route detection, causing unrelated videos to be mistaken for
    subtitle demos.
    """
    parts: list[str] = [normalize_space(title), normalize_space(description_text)]
    for item in timeline or []:
        if not isinstance(item, dict):
            continue
        for key in ("summary", "transcriptExcerpt", "quoteCandidate"):
            value = normalize_space(str(item.get(key) or ""))
            if key == "transcriptExcerpt" and not has_real_video_transcript_excerpt(value):
                continue
            if key != "transcriptExcerpt" and not usable_video_material_field(value, role=key):
                continue
            if value:
                parts.append(value)
    return normalize_space(" ".join(part for part in parts if part))


def infer_video_evidence_mode(timeline: list[dict[str, Any]]) -> str:
    resolved = 0
    unresolved = 0
    for item in timeline:
        if not isinstance(item, dict):
            continue
        transcript_value = normalize_space(str(item.get("transcriptExcerpt") or ""))
        if has_real_video_transcript_excerpt(transcript_value):
            resolved += 1
        else:
            unresolved += 1
    if resolved == 0:
        return "visual-only"
    if unresolved:
        return "hybrid"
    return "subtitle-led"


def strip_video_value_prefix(text: str) -> str:
    value = normalize_space(str(text or ""))
    value = re.sub(r"^(可以|适合)(写|放进|解释|证明|拆成|作为|回扣)?[：: ]*", "", value).strip()
    return value


def video_caption_demo_steps(text: str) -> list[str]:
    source = normalize_space(str(text or ""))
    steps: list[str] = []
    candidates = [
        (r"upload|上传|导入", "上传视频或素材"),
        (r"subtitle|caption|auto-caption|字幕", "打开字幕功能并自动生成字幕"),
        (r"transcript|转写|文稿", "检查转写文本"),
        (r"style|preset|样式|模板|字体|字号|颜色", "选择字幕样式"),
        (r"edit|customi[sz]e|effects?|animation|animate|on-brand|动效|动画|品牌|调整", "调整字幕样式、动效和品牌感"),
        (r"done|export|导出|发布", "确认效果后导出视频"),
    ]
    for pattern, label in candidates:
        if re.search(pattern, source, re.I) and label not in steps:
            steps.append(label)
    return steps


def looks_like_caption_demo(text: str) -> bool:
    source = normalize_space(str(text or ""))
    caption_hits = re.findall(r"subtitle|caption|auto-caption|字幕|转写文本|CapCut|VEED", source, re.I)
    if not caption_hits:
        return False
    file_management_noise = re.search(r"文件管理|照片|相冊|相册|硬盤|硬盘|SD卡|備份|备份|素材管理|文件夾|文件夹", source, re.I)
    strong_caption_context = re.search(
        r"AI Subtitle|Auto Captions?|CapCut|VEED|Canva Auto|generate captions|captions option|"
        r"自动生成字幕|生成字幕|加字幕|字幕功能|字幕入口|字幕样式|字幕文本|给视频.*字幕|视频.*字幕",
        source,
        re.I,
    )
    if file_management_noise and not strong_caption_context and len(caption_hits) < 3:
        return False
    if strong_caption_context and re.search(r"AI Subtitle|Subtitle Generator|CapCut|VEED|Canva Auto", source, re.I):
        return True
    if not strong_caption_context and len(caption_hits) < 3:
        return False
    return len(video_caption_demo_steps(source)) >= 2


def caption_demo_summary_sentence(text: str) -> str:
    steps = video_caption_demo_steps(text)
    if len(steps) >= 4:
        final = steps[-1]
        middle_candidates = [
            step
            for step in steps[2:-1]
            if step != final and "导出" not in step
        ]
        if middle_candidates:
            return f"先{steps[0]}，再{steps[1]}，接着{middle_candidates[0]}，最后{final}。"
        return f"先{steps[0]}，再{steps[1]}，最后{final}。"
    if len(steps) >= 2:
        return f"先{steps[0]}，再{steps[1]}。"
    return "演示用 AI 给视频自动加字幕。"


def caption_demo_chunk_summary(text: str, index: int = 0) -> str:
    source = normalize_space(str(text or ""))
    rules = [
        (
            r"open Canva|click on video|choose any size|1920|1080|uploaded|insert|canvas|set as background",
            "准备画布，把视频素材放进编辑器。",
        ),
        (
            r"text on the left|captions option|generate captions|automatically adds captions|auto-caption|字幕",
            "打开字幕入口，让工具自动生成字幕。",
        ),
        (
            r"move the captions|edit any specific text|captions text|extra text|delete a specific caption|trash",
            "检查字幕文本，必要时手动修改或删除。",
        ),
        (
            r"animate|animation|intensity|engaging|subscribe|helpful",
            "加字幕动效，再确认成片效果。",
        ),
        (
            r"font|Poppins|bold|font size|color|branding|background effect|effects",
            "调整字体、字号、颜色和背景效果。",
        ),
        (
            r"export|download|done",
            "最后确认效果并导出视频。",
        ),
    ]
    for pattern, label in rules:
        if re.search(pattern, source, re.I):
            return label
    index_defaults = [
        "准备画布，把视频素材放进编辑器。",
        "打开字幕入口，让工具自动生成字幕。",
        "检查字幕文本，必要时手动修改或删除。",
        "调整字体、字号、颜色和背景效果。",
        "加字幕动效，再确认成片效果。",
    ]
    if 0 <= index < len(index_defaults):
        return index_defaults[index]
    steps = video_caption_demo_steps(source)
    if steps:
        return f"步骤 {index + 1}：{steps[min(index, len(steps) - 1)]}。"
    return "这一段继续演示字幕生成流程。"


