def normalize_video_material_copy(text: str, *, role: str = "") -> str:
    value = normalize_space(str(text or ""))
    if not value:
        return value
    value = re.sub(r"^\d{1,2}:\d{2}(?::\d{2})?\s*(?:片段|段落)?\s*\d*\s*[：:，,\-— ]*", "", value).strip()
    value = re.sub(r"^(?:片段|段落)\s*\d+\s*[：:，,\-— ]*", "", value).strip()
    value = re.sub(r"CodeX", "Codex", value, flags=re.I)
    value = value.replace("：：", "：").replace(",,", "，").replace("，，", "，")
    value = re.sub(r"\s*([，。！？：；、])\s*", r"\1", value)
    value = re.sub(r"(这段主要在讲[：:]\s*){2,}", "这段主要在讲：", value)
    for _ in range(4):
        next_value = re.sub(r"^这段主要在讲[：:]\s*", "", value).strip()
        if next_value == value:
            break
        value = next_value
    value = re.sub(r"(先演示|再处理|围绕|压到|先把|再把)\s*这段主要在讲[：:]\s*", r"\1", value)
    value = re.sub(r"适合写[：:]\s*适合写[：:]\s*", "适合写：", value)
    value = re.sub(r"适合写成([^：:，。]+)[：:]\s*，", r"适合写成\1：", value)
    value = re.sub(r"([，。！？；：、])\1+", r"\1", value)
    value = re.sub(r"^[,，。；;：:\s]+", "", value)
    value = re.sub(r"\b(Um+|Uh+|Er+|Ah+)[,，.。 ]+", "", value, flags=re.I)
    value = normalize_inline_punctuation(value)
    value = normalize_space(value)
    if role in {"headline", "summary"}:
        return video_notes.compact_text(value, 96)
    if role in {"bullet", "point"}:
        return video_notes.compact_text(value, 58)
    if role in {"quote", "quotecandidate"}:
        return video_notes.compact_text(value, 72)
    return value


PUBLIC_VIDEO_COPY_INTERNAL_RE = re.compile(
    r"重点不是|真正要看的?不是|现实门槛|功能名|需补材料|后台规则|"
    r"先记对象|先按标题|画面判断|原话转述|像证据|像转折|"
    r"先做证据卡|材料不足|关键缺口|先补材料再写|写稿前必须补上|"
    r"回看确认|回原视频|再谈判断|成语转换|画面/字幕",
)


def public_video_copy_has_internal_language(text: str) -> bool:
    value = normalize_space(str(text or ""))
    if not value:
        return False
    if PUBLIC_VIDEO_COPY_INTERNAL_RE.search(value):
        return True
    if re.search(r"不是[^，。；;]{1,36}[，,]?\s*而是", value):
        return True
    if re.search(r"依据[：:].{0,80}", value):
        return True
    return False


def clean_public_video_copy(text: str, *, role: str = "", fallback: str = "", limit: int | None = None) -> str:
    value = normalize_video_material_copy(text, role=role if role in {"headline", "bullet", "quote", "summary"} else "")
    if not value:
        value = normalize_space(fallback)
    if not value:
        return ""
    value = re.sub(r"AI\s*字幕\s*/\s*转写工具", "字幕", value)
    value = re.sub(r"AI\s*字幕", "字幕", value)
    value = value.replace("转写工具", "字幕工具")
    value = value.replace("转写文本", "字幕")
    value = value.replace("现实门槛", "卡点")
    value = value.replace("需补材料", "材料不足")
    value = re.sub(r"后台规则[：:].*?$", "", value)
    value = re.sub(r"依据[：:].*?$", "", value)
    value = re.sub(r"真正要看的?不是[^，。；;]{1,40}[，,]?\s*而是", "", value)
    value = re.sub(r"重点不是[^，。；;]{1,40}[，,]?\s*而是", "", value)
    value = re.sub(r"不是[^，。；;]{1,40}[，,]?\s*而是", "", value)
    value = re.sub(r"^(先看|先说|说明)\s*", "", value).strip()
    value = re.sub(r"^[，。；;：:\s]+", "", value)
    value = normalize_video_material_copy(value, role=role if role in {"headline", "bullet", "quote", "summary"} else "")
    if public_video_copy_has_internal_language(value):
        value = normalize_space(fallback)
    if public_video_copy_has_internal_language(value):
        value = ""
    if limit and value:
        value = video_notes.compact_text(value, limit)
    return value


def clean_public_video_summary(card: dict[str, Any]) -> dict[str, Any]:
    if not isinstance(card, dict):
        return {}
    cleaned = dict(card)
    cleaned["headline"] = clean_public_video_copy(
        str(cleaned.get("headline") or ""),
        role="headline",
        fallback="这条视频可以拆成一组可用材料。",
        limit=96,
    )
    cleaned["evidenceNote"] = clean_public_video_copy(
        str(cleaned.get("evidenceNote") or ""),
        fallback="",
        limit=80,
    )
    cleaned["takeaway"] = clean_public_video_copy(
        str(cleaned.get("takeaway") or ""),
        fallback="先看画面和字幕，再决定怎么写。",
        limit=96,
    )
    bullets: list[str] = []
    for item in cleaned.get("bullets") if isinstance(cleaned.get("bullets"), list) else []:
        bullet = clean_public_video_copy(str(item or ""), role="bullet", limit=64)
        if bullet and not low_signal_video_material_copy(bullet):
            bullets.append(bullet)
    cleaned["bullets"] = bullets[:3]
    return cleaned


def clean_public_video_timeline(timeline: list[dict[str, Any]]) -> list[dict[str, Any]]:
    cleaned_items: list[dict[str, Any]] = []
    for item in timeline:
        if not isinstance(item, dict):
            continue
        updated = dict(item)
        updated["summary"] = clean_public_video_copy(str(updated.get("summary") or ""), fallback="", limit=96)
        updated["writingValue"] = clean_public_video_copy(str(updated.get("writingValue") or ""), fallback="", limit=96)
        updated["writingAngle"] = clean_public_video_copy(str(updated.get("writingAngle") or ""), fallback="", limit=64)
        updated["quoteCandidate"] = clean_public_video_copy(str(updated.get("quoteCandidate") or ""), role="quote", fallback="", limit=86)
        cleaned_items.append(updated)
    return cleaned_items


def clean_public_video_demo_deck(deck: dict[str, Any]) -> dict[str, Any]:
    if not isinstance(deck, dict):
        return {}
    cleaned = dict(deck)
    template = cleaned.get("template") if isinstance(cleaned.get("template"), dict) else {}
    route_kind = normalize_space(str(cleaned.get("templateKey") or template.get("key") or "opinion")) or "opinion"
    if route_kind not in {"tutorial", "demo", "review", "opinion", "interview"}:
        route_kind = "opinion"
    is_tutorial = route_kind == "tutorial"
    cleaned["headline"] = clean_public_video_copy(
        str(cleaned.get("headline") or ""),
        role="headline",
        fallback="这条视频可以拆成一组可用材料。",
        limit=96,
    )
    cleaned["evidenceNote"] = clean_public_video_copy(
        str(cleaned.get("evidenceNote") or ""),
        fallback="",
        limit=80,
    )
    slides: list[dict[str, Any]] = []
    for index, slide in enumerate(cleaned.get("slides") if isinstance(cleaned.get("slides"), list) else []):
        if not isinstance(slide, dict):
            continue
        updated = dict(slide)
        fallback_title = f"第 {index + 1} 页"
        raw_source_line = specific_video_slide_line(
            slide.get("sourceQuote"),
            slide.get("action"),
            slide.get("meaning"),
            slide.get("speakerNote"),
            slide.get("proof"),
            slide.get("talkTrack"),
            route_kind=route_kind,
            max_len=96,
        )
        spoken_fallback = (
            review_video_spoken_line(
                " ".join(
                    normalize_space(str(slide.get(key) or ""))
                    for key in ("sourceQuote", "action", "meaning", "speakerNote", "proof", "talkTrack")
                ),
                index=index,
            )
            if route_kind == "review"
            else raw_source_line
        )
        spoken_fallback = clean_public_video_copy(spoken_fallback, fallback="", limit=92)
        updated["title"] = clean_public_video_copy(str(updated.get("title") or ""), fallback=fallback_title, limit=34) or fallback_title
        updated["action"] = clean_public_video_copy(str(updated.get("action") or ""), fallback="", limit=92)
        updated["meaning"] = clean_public_video_copy(str(updated.get("meaning") or ""), fallback="", limit=92)
        updated["speakerNote"] = clean_public_video_copy(str(updated.get("speakerNote") or ""), fallback="", limit=92)
        updated["proof"] = clean_public_video_copy(str(updated.get("proof") or ""), fallback="", limit=118)
        updated["talkTrack"] = clean_public_video_copy(str(updated.get("talkTrack") or ""), fallback="", limit=92)
        updated["audienceTakeaway"] = clean_public_video_copy(str(updated.get("audienceTakeaway") or ""), fallback="", limit=92)
        updated["slideBody"] = clean_public_video_copy(str(updated.get("slideBody") or ""), fallback="", limit=180)
        updated["productAnswer"] = clean_public_video_copy(str(updated.get("productAnswer") or ""), fallback="", limit=92)
        updated["sourceQuote"] = clean_public_video_copy(str(updated.get("sourceQuote") or ""), role="quote", fallback="", limit=86)
        clean_fallback_candidates = [
            normalize_space(str(updated.get(key) or ""))
            for key in ("action", "speakerNote", "talkTrack", "meaning", "proof", "sourceQuote")
        ]
        clean_fallback_candidates = [
            candidate
            for candidate in clean_fallback_candidates
            if candidate and not generic_video_slide_text(candidate) and not generic_video_summary_hint(candidate)
        ]
        clean_fallback_candidates = sorted(
            clean_fallback_candidates,
            key=lambda candidate: (cjk_char_count(candidate) <= 0, -cjk_char_count(candidate), len(candidate)),
        )
        if clean_fallback_candidates:
            spoken_fallback = video_notes.compact_text(clean_fallback_candidates[0], 92)
        for field, limit, min_len in (
            ("action", 92, 14),
            ("meaning", 92, 14),
            ("speakerNote", 92, 14),
            ("proof", 118, 18),
            ("talkTrack", 92, 12),
            ("audienceTakeaway", 92, 14),
        ):
            value = normalize_space(str(updated.get(field) or ""))
            if (
                spoken_fallback
                and (
                    not value
                    or len(value) < min_len
                    or generic_video_slide_text(value)
                    or generic_video_summary_hint(value)
                    or re.search(r"^这页要|^这一页|^这里要|^可写成|^适合写", value)
                )
            ):
                updated[field] = video_notes.compact_text(spoken_fallback, limit)
        if not normalize_space(str(updated.get("sourceQuote") or "")) and raw_source_line:
            updated["sourceQuote"] = clean_public_video_copy(raw_source_line, role="quote", fallback="", limit=86)
        updated["slideBody"] = video_notes.compact_text(
            " ".join(
                normalize_space(str(updated.get(key) or ""))
                for key in ("proof", "talkTrack", "audienceTakeaway")
                if normalize_space(str(updated.get(key) or ""))
            ),
            180,
        )
        slides.append(updated)
    cleaned["slides"] = slides
    cleaned["demoDeckQuality"] = assess_demo_deck_quality(
        slides,
        cleaned.get("evidenceStatus") if isinstance(cleaned.get("evidenceStatus"), dict) else {},
        is_tutorial=is_tutorial,
        route_kind=route_kind,
    )
    cleaned["deckMarkdown"] = build_video_deck_markdown(
        headline=cleaned.get("headline") or "视频材料",
        source_status=normalize_space(str(cleaned.get("sourceStatus") or "")),
        evidence_note=cleaned.get("evidenceNote") or "",
        slides=slides,
        deck_template=template,
    )
    return cleaned


def low_signal_video_material_copy(text: str) -> bool:
    value = normalize_video_material_copy(text)
    if not value:
        return True
    if "..." in value or "…" in value:
        return True
    if value in {"开场", "这一段", "使用门槛", "真实使用", "材料点", "代价", "结论", "收束"}:
        return True
    if re.search(
        r"片段\s*\d|为什么是真门槛|真门槛|资源成本、心理成本|心理成本|"
        r"可以作为正文材料|写入前还要补清楚对象|开场先点明|中段拆实际条件|"
        r"结尾给一个可执行动作|收束观点，提炼成结尾判断|放进开头，交代|"
        r"标题《.+?》可以转成|优先写成个人判断|不是知识点清单|"
        r"三段式鸡汤|更像真人说话|真正要讲的不是|字面上的问题|"
        r"现实成本和判断标准|背后的现实成本",
        value,
    ):
        return True
    if value in {"开场", "中段", "结尾", "使用门槛", "核心问题", "正文材料"}:
        return True
    if re.fullmatch(r"(um+|uh+|er+|ah+|okay|ok|so|yeah|right)[.。!！?？,， ]*", value, re.I):
        return True
    english_words = ascii_word_count(value)
    chinese_chars = cjk_char_count(value)
    if "这段主要在讲" in str(text or "") and english_words >= 4:
        return True
    if looks_english_video_copy(value) and chinese_chars < 10:
        return True
    return False


def usable_video_material_field(text: str, *, role: str = "") -> str:
    value = normalize_video_material_copy(text, role="quote" if role == "quoteCandidate" else role)
    if not value:
        return ""
    if low_signal_video_material_copy(value):
        return ""
    if generic_video_slide_text(value) or generic_video_summary_hint(value):
        return ""
    if role in {"headline", "summary", "bullet"} and generic_video_core_claim(value):
        return ""
    return value


def summary_has_machine_video_copy(summary: dict[str, Any]) -> bool:
    if not isinstance(summary, dict):
        return False
    text = json.dumps(
        {
            "videoSummary": summary.get("videoSummary"),
            "demoDeck": summary.get("demoDeck"),
            "timeline": summary.get("timeline"),
        },
        ensure_ascii=False,
    )
    if re.search(r"这段主要在讲[：:].{0,160}这段主要在讲[：:]", text):
        return True
    if "适合写：适合写" in text or "，，" in text:
        return True
    if re.search(r"先把问题讲具体，再用证据、转折和代价|判断标准更接近真实使用成本|现实成本和判断标准", text):
        return True
    if re.search(
        r"片段\s*\d|为什么是真门槛|真门槛|资源成本、心理成本|心理成本|"
        r"标题《.+?》可以转成|标题表面|字面上的问题|真正(?:要讲的|的核心命题)|"
        r"背后的现实成本|CLAUDE\\.md|终端入口的价值不在复古|"
        r"这里把视频里的材料压成一个可引用的判断点|先说具体动作，再说明它为什么值得记|"
        r"把这一段压成一个可复述的操作判断",
        text,
    ):
        return True
    if re.search(r"先演示\s*这段主要在讲|再处理\s*这段主要在讲", text):
        return True
    return False


def cjk_char_count(text: str) -> int:
    return sum(1 for char in str(text or "") if "\u4e00" <= char <= "\u9fff")


def is_tutorial_video_route(title: str, route_text: str = "") -> bool:
    title_text = normalize_space(title)
    route = normalize_space(route_text)
    if re.search(r"教程|上手|实操|指南|互联|连接|安装|设置|步骤|排查|怎么用|如何用|使用流程", title_text, re.I):
        return True
    route_patterns = (
        r"双端|双机|互联|连接|地址|证书|继续访问|安装|连不上|连接不上|联系不上",
        r"简历|音频来源|麦克风|系统声音|防火墙|服务|配置页|重试",
        r"按提示|先.+再.+|最后.+验收|跑通|转写|消息列表",
    )
    hits = sum(1 for pattern in route_patterns if re.search(pattern, route, re.I))
    return hits >= 2


def classify_video_route_kind(title: str, route_text: str = "") -> str:
    title_text = normalize_space(title)
    route = normalize_space(route_text)
    combined = normalize_space(f"{title_text} {route}")
    if public_talk_video_context(combined):
        return "opinion"
    if re.search(r"教程|基础教程|入门教程|操作教程|使用教程", title_text, re.I):
        return "tutorial"
    if re.search(r"\b(only\s+AI\s+tools?\s+you\s+need|tools?\s+you\s+need|AI\s+tools?\s+you\s+need)\b|工具清单|工具推荐", title_text, re.I):
        return "review"
    if re.search(r"\b(don'?t\s+know|basics?\s+of\s+AI|mistakes?|myths?)\b|误区|不知道|基础认知", title_text, re.I):
        return "opinion"
    if re.search(r"\b(tutorial|guide|starter|course|learn)\b|教程|指南|入门|上手", title_text, re.I) and not re.search(
        r"\b(only\s+AI\s+tools?\s+you\s+need|tools?\s+you\s+need|AI\s+tools?\s+you\s+need)\b|工具清单|工具推荐",
        title_text,
        re.I,
    ):
        return "tutorial"
    if re.search(r"\b(beginner|beginners|starter|complete beginners|guide|tutorial|course)\b", title_text, re.I) and re.search(
        r"\b(AI|video|tool|tools|workflow|prompt|prompts|model|models)\b|视频|工具|工作流|提示词|模型",
        combined,
        re.I,
    ):
        return "tutorial"
    if re.search(r"\binside\b.*\bwith\b|\bwith\b.*\bcreator\b|\bcreator\b|\binterview\b|\bfounder\b|访谈|对谈|专访|创始人|嘉宾", title_text, re.I):
        return "interview"
    method_or_opinion_patterns = (
        r"自媒体|Codex|CodeX|Claude Code|脚本|课程|结构化|文字风格",
        r"文件管理|照片|相册|iCloud|硬盘|拍摄素材|資料|備份|手机相册|手機相簿",
        r"全職投資|全职投资|職業投資|投资|投資|ETF|生活費|安全墊|自由現金流|心理條件|資本條件|技術條件",
    )
    if any(re.search(pattern, combined, re.I) for pattern in method_or_opinion_patterns):
        return "opinion"
    review_patterns = (
        r"评测|测评|体验后|上手后|值不值|值得买吗|优缺点|缺点|优点|价格|定价|替代品|对比|"
        r"真实体验|使用体验|实测结果|适合谁|不适合谁|推荐吗|踩坑|门槛|成本|"
        r"tools? you need|AI tools?|tool list|tool stack|best tools?|工具清单|工具推荐"
    )
    review_hits = sum(1 for pattern in review_patterns.split("|") if pattern and re.search(pattern, combined, re.I))
    if review_hits >= 2 or re.search(r"评测|测评|值不值|值得买吗|优缺点|适合谁|不适合谁", title_text, re.I):
        return "review"
    if looks_like_caption_demo(combined):
        return "demo"
    if is_tutorial_video_route(title_text, route):
        return "tutorial"
    if re.search(r"实测|上手|体验|工作流|演示|教程|用法|配置|操作", title_text, re.I):
        return "demo"
    opinion_title_patterns = (
        r"为什么|值不值|误区|真相|问题|别再|不要|其实|判断|复盘|拆解|分析|看法|经验|背后|本质|困境|反而|更需要"
    )
    opinion_route_patterns = (
        r"问题不在|关键不在|重点不在|真正的问题|真正值钱|代价|限制|风险|误区|判断|结论|反驳|为什么|值不值|到底|本质",
        r"产品判断|入口选择|真实使用|使用门槛|低风险|上下文|六个月后|终端|CLI|工程师",
        r"我觉得|我现在|我的结论|我的判断|对我来说|先别|别急着|不是.{0,12}而是",
    )
    opinion_hits = sum(1 for pattern in opinion_route_patterns if re.search(pattern, route, re.I))
    if re.search(opinion_title_patterns, title_text, re.I) or opinion_hits >= 2:
        return "opinion"
    if re.search(r"\b(basics?|beginners?|course|essentials?|prompting|learn AI)\b|入门|基础课|课程", combined, re.I):
        return "opinion"
    demo_patterns = (
        r"演示|实测|上手|体验|工具|助手|软件|插件|工作流|workflow|配置|功能|评测|测评|玩法|用法|"
        r"generator|captions?|subtitles?|auto-caption|CapCut|VEED|Canva|upload|export|editor|preset"
    )
    if re.search(demo_patterns, f"{title_text} {route}", re.I):
        return "demo"
    if re.search(r"证据|数据|研究|观点|结论|代价|判断", route, re.I):
        return "opinion"
    return "demo"


def tutorial_subject_label(text: str) -> str:
    value = normalize_space(text)
    if not value:
        return "这套工具"
    value = re.sub(r"(教程|演示|流程|使用|指南|笔记)$", "", value).strip()
    if not value or len(value) > 22:
        return "这套工具"
    return value


def tutorial_route_steps(transcript_text: str) -> list[str]:
    transcript = normalize_space(transcript_text)
    steps: list[str] = []
    if re.search(r"iPad|IPAD|平板|Windows|电脑|双端|双机|互联|连接", transcript, re.I):
        steps.append("先把双端连上")
    if re.search(r"简历|音频来源|麦克风|系统声音|面试", transcript):
        steps.append("把简历和音频源配好")
    if re.search(r"连不上|联系不上|连接不上|访问|地址|证书|继续访问|安装成功", transcript):
        steps.append("连不上时先看地址和证书")
    if re.search(r"语音识别|转录|消息列表|视频声音|自己的话|识别", transcript):
        steps.append("最后看转写有没有真的跑通")
    if re.search(r"重启|刷新|服务|地址没有问题|强制|防火墙", transcript):
        steps.append("还不通再查防火墙和服务")
    return steps


def tutorial_visual_only_steps(route_text: str) -> list[str]:
    route = normalize_space(route_text)
    steps: list[str] = []
    if re.search(r"iPad|IPAD|平板|Windows|电脑|双端|双机|互联|连接", route, re.I):
        steps.append("先把双端连上")
    if re.search(r"地址|证书|继续访问|访问成功|连接不上|联系不上|连不上", route):
        steps.append("再处理连接地址和证书")
    if re.search(r"简历|上传|音频|麦克风|配置|设置|面试", route):
        steps.append("再把简历和音频源配好")
    if re.search(r"语音识别|转写|消息列表|视频声音|自己的话|识别", route):
        steps.append("最后确认结果有没有真的进来")
    if re.search(r"防火墙|服务|重启|刷新", route):
        steps.append("还不通再查系统层")
    if not steps:
        steps.append("先把流程入口找出来")
    if len(steps) == 1:
        steps.append("再把真正会卡住的步骤单独拎出来")
    if len(steps) == 2:
        steps.append("最后确认结果有没有真的生效")
    if len(steps) == 3 and not any("系统层" in step for step in steps):
        steps.append("还不通再查系统层")
    if re.search(r"防火墙|服务|重启|刷新", route):
        steps.append("如果还不通，再回系统层排查")
    deduped: list[str] = []
    for step in steps:
        if step not in deduped:
            deduped.append(step)
    return deduped


def demo_route_steps(route_text: str) -> list[str]:
    route = normalize_space(route_text)
    steps: list[str] = []
    if re.search(r"面试|剪辑|录音|生成|发布|使用场景|谁会用|什么时候用|演示", route, re.I):
        steps.append("先看它解决什么场景")
    if re.search(r"原文|素材|导入|输入", route, re.I):
        steps.append("先把输入材料放进去")
    if re.search(r"配置|设置|上传|简历|音频|权限|来源|前提|入口", route, re.I):
        steps.append("再把前提和设置交代清楚")
    if re.search(r"音色|语速|参数|参考音频", route, re.I):
        steps.append("再把参数和前提调清楚")
    if re.search(r"结果|转写|识别|跑通|生效|消息列表|输出|生成成功|预览", route, re.I):
        steps.append("然后看结果有没有真的出来")
    if re.search(r"成品|停顿|人声|能直接用|试听", route, re.I):
        steps.append("然后看成品能不能直接用")
    if re.search(r"失败|限制|代价|连不上|证书|防火墙|服务|卡住|问题", route, re.I):
        steps.append("最后把真正会卡住的地方讲明白")
    if re.search(r"情绪|断句|继续调|返调|不对", route, re.I):
        steps.append("最后把会翻车的地方讲明白")
    if not steps:
        steps.append("先看它在真实场景里怎么跑")
    if len(steps) == 1:
        steps.append("再看结果是不是只停在演示层")
    if len(steps) == 2:
        steps.append("最后补上前提和限制")
    deduped: list[str] = []
    for step in steps:
        if step not in deduped:
            deduped.append(step)
    return deduped


def build_tutorial_summary_headline(subject: str, transcript_text: str) -> str:
    def summary_label(step: str) -> str:
        if step == "先把双端连上":
            return "双端怎么连"
        if step == "把简历和音频源配好":
            return "简历和音频源怎么配"
        if step == "连不上时先看地址和证书":
            return "连不上先查什么"
        if step == "最后看转写有没有真的跑通":
            return "最后怎么验收"
        if step == "还不通再查防火墙和服务":
            return "还不通再查哪里"
        return step

    steps = tutorial_route_steps(transcript_text)
    if len(steps) >= 3:
        return video_notes.compact_text(
            f"这条视频顺着演示了一遍：{summary_label(steps[0])}，{summary_label(steps[1])}，{summary_label(steps[2])}。",
            92,
        )
    if len(steps) == 2:
        return video_notes.compact_text(
            f"这条视频主要在讲两件事：{summary_label(steps[0])}，{summary_label(steps[1])}。",
            92,
        )
    if len(steps) == 1:
        return video_notes.compact_text(f"这条视频就盯着一件事讲：{summary_label(steps[0])}。", 92)
    return video_notes.compact_text(f"这条视频顺着{subject}的真实使用往下演示。", 92)


def build_tutorial_takeaway_copy(transcript_text: str) -> str:
    steps = tutorial_route_steps(transcript_text)
    if steps:
        labels = []
        for step in steps[:4]:
            if step == "先把双端连上":
                labels.append("双端怎么连")
            elif step == "把简历和音频源配好":
                labels.append("简历和音频怎么配")
            elif step == "连不上时先看地址和证书":
                labels.append("连不上先查哪里")
            elif step == "最后看转写有没有真的跑通":
                labels.append("最后怎么验收")
            elif step == "还不通再查防火墙和服务":
                labels.append("系统层怎么排错")
            else:
                labels.append(step)
        route_text = "、".join(labels)
        route_text = normalize_space(route_text)
        return f"适合写成操作说明：{route_text}。"
    return "适合写成操作说明：把会卡住的步骤和排错顺序按一条线讲清。"


def compact_video_demo_point(text: str) -> str:
    value = clean_video_sentence_head(text)
    value = re.sub(r"[。；;]+$", "", value)
    return normalize_space(value)


def build_demo_summary_headline(title: str, route_text: str, cleaned_points: list[str], core_claim: str = "") -> str:
    steps = demo_route_steps(route_text)
    if core_claim and not generic_video_core_claim(core_claim):
        return video_notes.compact_text(core_claim, 92)
    if cleaned_points:
        first = compact_video_demo_point(cleaned_points[0])
        if len(cleaned_points) > 1:
            second = compact_video_demo_point(cleaned_points[1])
            return video_notes.compact_text(f"这条视频先演示 {first}，再处理 {second}。", 92)
        return video_notes.compact_text(f"这条视频把 {first} 这一步现场跑了一遍。", 92)
    if len(steps) >= 3:
        return video_notes.compact_text(f"可以按这个顺序看：{steps[0]}，{steps[1]}，{steps[2]}。", 92)
    if core_claim and not generic_video_core_claim(core_claim):
        return video_notes.compact_text(core_claim, 92)
    return video_notes.compact_text(f"这条视频把《{title}》怎么跑、哪里会卡顺着演示了一遍。", 92)


def build_demo_takeaway_copy(route_text: str) -> str:
    route = normalize_space(route_text)
    labels: list[str] = []
    if re.search(r"原文|素材|导入|输入", route, re.I):
        labels.append("先把输入材料给进去")
    if re.search(r"音色|语速|参数|设置|权限|来源|参考音频", route, re.I):
        labels.append("再把参数和前提讲清")
    if re.search(r"成品|停顿|人声|试听|结果|输出|预览|生效", route, re.I):
        labels.append("然后听结果能不能直接用")
    if re.search(r"情绪|断句|限制|代价|问题|返调|不对|失败", route, re.I):
        labels.append("不对时回去改哪里")
    if len(labels) >= 3:
        return f"适合写成实测或工具评测：{labels[0]}，{labels[1]}，{labels[2]}。"
    steps = demo_route_steps(route)
    if len(steps) >= 3:
        return f"适合写成实测或工具评测：{steps[0]}，{steps[1]}，{steps[2]}。"
    return "适合写成实测或工具评测：先讲场景，再看前提、结果和限制。"


def build_specific_opinion_summary_headline(title: str, route_text: str, cleaned_points: list[str]) -> str:
    route = normalize_space(" ".join([title, route_text, " ".join(cleaned_points)]))
    if re.search(r"Claude Code|Anthropic|terminal|终端|Boris|Cherny", route, re.I):
        return "Claude Code 的关键线索，是 Anthropic 先押注模型六个月后的能力，再用终端这种低成本形态快速交给工程师试。"
    if re.search(r"文件管理|照片|相册|iCloud|硬盘|拍摄素材|資料|備份|手机相册|手機相簿", route, re.I):
        return "这条视频讲的是个人文件怎么分层放：手机照片、iCloud、硬盘和拍摄素材各放一层，找的时候才不会乱。"
    if re.search(r"全職投資|全职投资|職業投資|投资|投資|ETF|生活費|安全墊|自由現金流|心理條件|資本條件|技術條件", route, re.I):
        return "这条视频把全职投资拆成几道门槛：先有可执行的投资系统，再有资金安全垫，最后还要扛得住波动。"
    if re.search(r"自媒体|Codex|CodeX|脚本|文字风格", route, re.I):
        if re.search(r"自媒体|Codex|CodeX|脚本|文字风格|来源", route, re.I):
            return "这条视频讲的是用 Codex 做自媒体：先找资料和来源，再整理成结构，最后按自己的文字风格出脚本。"
    if re.search(r"Background Agents|Agent Cloud|AI Agents Need Computers|runs|PRs|Daytona|agent", route, re.I):
        return "这条视频在讲 AI Agent 为什么需要真实电脑环境：任务量上来以后，浏览器、终端和云端执行都会变成基础设施。"
    return ""


def build_specific_opinion_takeaway_copy(title: str, route_text: str, cleaned_points: list[str], core_claim: str = "") -> str:
    route = normalize_space(" ".join([title, core_claim, route_text, " ".join(cleaned_points)]))
    if re.search(r"文件管理|照片|相册|iCloud|硬盘|拍摄素材|資料|備份|手机相册|手機相簿", route, re.I):
        return "能写成个人资料管理方法：照片怎么存、素材怎么备份、项目文件怎么找。"
    if re.search(r"全職投資|全职投资|職業投資|投资|投資|ETF|生活費|安全墊|自由現金流|心理條件|資本條件|技術條件", route, re.I):
        return "能写成全职投资条件清单：投资系统、资金安全垫、自由现金流和心理承受力。"
    if re.search(r"自媒体|Codex|CodeX|脚本|文字风格|来源", route, re.I) and re.search(
        r"自媒体|Codex|CodeX|脚本|文字风格", route, re.I
    ):
        return "能写成自媒体工作流实测：找资料、做结构化资料、套入个人风格，再改到能拍。"
    if re.search(r"Claude Code|Anthropic|terminal|终端|模型六个月|Boris|Cherny", route, re.I):
        return "能写成 AI 编程工具判断稿：先讲 Anthropic 的产品押注，再讲为什么终端入口能跑进真实任务。"
    if re.search(r"Background Agents|Agent Cloud|AI Agents Need Computers|runs|PRs|Daytona|agent", route, re.I):
        return "能写成 AI Agent 基础设施稿：先讲为什么需要电脑，再拆浏览器、终端和云端执行。"
    return ""


def build_visual_only_demo_summary(*, route_text: str, title: str) -> dict[str, Any]:
    route = normalize_space(route_text or title)
    if re.search(r"配音|音色|语速|参考音频|人声|断句|情绪", route, re.I):
        return {
            "headline": "这次没拿到字幕，但光看演示也能先抓到：先配输入，再调参数，最后听成品能不能直接用。",
            "bullets": [
                "先看原文、参考音频这些输入有没有先交代清楚。",
                "再看音色、语速、断句这些参数怎么调。",
                "最后只认成品：停顿、人声和情绪能不能直接用。",
            ],
            "takeaway": "适合写成工具评测：输入材料、参数、成品验收、哪里需要返调。",
            "evidenceMode": "visual-only",
        }
    steps = demo_route_steps(route)
    first = steps[0] if steps else "先看它到底给谁用"
    second = steps[1] if len(steps) > 1 else "再看前提和设置有没有讲清"
    third = steps[2] if len(steps) > 2 else "最后看结果有没有真的出来"
    return {
        "headline": "这次没拿到字幕，只能先按画面做粗拆解，不能当成完整观点稿。",
        "bullets": [
            video_notes.compact_text(f"画面能先判断：{first}。", 58),
            video_notes.compact_text(f"还要回看确认：{second}。", 58),
            video_notes.compact_text(f"写稿前必须补上：{third}。", 58),
        ],
        "takeaway": "适合写成工具评测：场景、前提、结果、翻车点。",
        "evidenceMode": "visual-only",
    }


def build_visual_only_opinion_summary(*, route_text: str, title: str, core_claim: str = "") -> dict[str, Any]:
    claim = normalize_space(core_claim)
    headline = (
        video_notes.compact_text(claim, 92)
        if claim and not generic_video_core_claim(claim)
        else video_notes.compact_text("这次没拿到字幕，先保存视频和截图，补到关键句后再写。", 92)
    )
    return {
        "headline": headline,
        "bullets": [
            "视频已保存，但还缺关键句。",
            "先补字幕或原话，再写讲稿。",
            "现在还不能当成完整材料。",
        ],
        "takeaway": "",
        "evidenceMode": "visual-only",
    }


def build_visual_only_video_summary(
    *,
    route_kind: str,
    route_text: str,
    title: str,
    core_claim: str = "",
) -> dict[str, Any]:
    if route_kind == "tutorial":
        return build_visual_only_tutorial_summary(route_text=route_text, title=title)
    if route_kind == "demo":
        return build_visual_only_demo_summary(route_text=route_text, title=title)
    return build_visual_only_opinion_summary(route_text=route_text, title=title, core_claim=core_claim)


def build_opinion_summary_headline(title: str, core_claim: str, cleaned_points: list[str], route_text: str = "") -> str:
    specific = build_specific_opinion_summary_headline(title, route_text, cleaned_points)
    if specific:
        return video_notes.compact_text(specific, 92)
    claim = normalize_space(core_claim)
    if claim and not generic_video_core_claim(claim):
        return video_notes.compact_text(claim, 92)
    if cleaned_points:
        first = clean_video_sentence_head(cleaned_points[0])
        if len(cleaned_points) > 1:
            second = clean_video_sentence_head(cleaned_points[1])
            return video_notes.compact_text(f"这条视频先讲 {first}，再用 {second} 把问题落到具体材料上。", 92)
        return video_notes.compact_text(f"这条视频从 {first} 切入，把问题落到一个可验证的材料上。", 92)
    if route_text and re.search(r"问题|代价|限制|判断|风险", route_text):
        return video_notes.compact_text(f"这条视频围绕 {clean_video_sentence_head(route_text)} 展开，重点看证据、限制和结论。", 92)
    return video_notes.compact_text(f"这条视频围绕《{title}》展开，重点看它给了哪些证据和可执行判断。", 92)


def build_opinion_takeaway_copy(core_claim: str, route_text: str = "", *, title: str = "", cleaned_points: list[str] | None = None) -> str:
    specific = build_specific_opinion_takeaway_copy(title, route_text, cleaned_points or [], core_claim)
    if specific:
        return specific
    claim = normalize_space(core_claim)
    if claim and not generic_video_core_claim(claim):
        return "能写成判断稿：先讲谁遇到什么问题，再放关键证据，最后说明它带来的代价或变化。"
    if route_text and re.search(r"风险|限制|代价", route_text):
        return "适合写成观点拆解：先讲问题，再把证据、转折和代价拆开。"
    return "适合写成观点拆解：别停在复述，要把判断和证据一起写出来。"


def build_visual_only_tutorial_summary(*, route_text: str, title: str) -> dict[str, Any]:
    steps = tutorial_visual_only_steps(route_text or title)
    first = steps[0] if steps else "先把流程入口找出来"
    second = steps[1] if len(steps) > 1 else "再把真正会卡住的步骤单独拎出来"
    third = steps[2] if len(steps) > 2 else "最后确认结果有没有真的生效"
    is_connection_tutorial = bool(re.search(r"双端|双机|互联|连接|证书|地址|防火墙|服务|iPad|平板|Windows|电脑", route_text, re.I))
    if is_connection_tutorial:
        headline = video_notes.compact_text(
            "这条视频把双端互联从连接、证书到验收顺着走了一遍。",
            90,
        )
        bullets = [
            video_notes.compact_text("先把 iPad 和 Windows 的分工讲清，再开始连接。", 58),
            video_notes.compact_text("连不上时，先回连接地址和证书，不要一上来就重装。", 58),
            video_notes.compact_text("开始前传简历、选音频源，最后看消息列表里有没有真实转写。", 58),
        ]
        takeaway = "适合写成操作说明：设备分工、连接、证书、验收。"
        return {
            "headline": headline,
            "bullets": bullets,
            "takeaway": takeaway,
            "evidenceMode": "visual-only",
        }
    headline = video_notes.compact_text(f"这次没拿到字幕，但画面已经够用：{first}，{second}。", 90)
    bullets = [
        video_notes.compact_text(f"现在先按画面把顺序记下来：{first}，{second}。", 58),
        video_notes.compact_text(f"真正会卡人的地方，多半藏在 {third} 这一类步骤里。", 58),
        video_notes.compact_text("真正动笔前，还得回原视频补上口播里的条件、提醒和例外。", 58),
    ]
    return {
        "headline": headline,
        "bullets": bullets,
        "takeaway": "先拿它做演示拆页，再决定写成教程还是评测。",
        "evidenceMode": "visual-only",
    }


