def score_demo_deck_item(item: dict[str, Any], index: int, *, is_tutorial: bool) -> int:
    text = normalize_space(
        " ".join(
            str(item.get(key) or "")
            for key in ("writingAngle", "summary", "transcriptExcerpt", "writingValue", "quoteCandidate")
        )
    )
    score = 0
    if index == 0:
        score += 3
    if item.get("frameUrl"):
        score += 2
    if is_tutorial:
        for pattern in (r"连接|证书|防火墙|连不上|失败", r"简历|音频|声音", r"转写|识别|结果|跑通"):
            if re.search(pattern, text):
                score += 3
    else:
        for pattern in (r"问题|反驳|代价|风险|证据|数据|判断|结论"):
            if re.search(pattern, text):
                score += 3
    if len(text) > 40:
        score += 1
    if generic_video_slide_text(text):
        score -= 2
    return score


def select_demo_deck_items_by_required_roles(
    enriched: list[dict[str, Any]],
    *,
    required_roles: tuple[str, ...],
    target_count: int,
) -> tuple[list[dict[str, Any]], set[int]]:
    selected: list[dict[str, Any]] = []
    selected_ids: set[int] = set()
    for role in required_roles:
        candidates = [
            item
            for item in enriched
            if demo_deck_role_matches_requirement(str(item.get("_deckRole") or ""), role)
            and int(item.get("_sourceIndex") or -1) not in selected_ids
        ]
        if not candidates:
            continue
        chosen = sorted(
            candidates,
            key=lambda current: (-int(current.get("_keepScore") or 0), int(current.get("_sourceIndex") or 0)),
        )[0]
        selected.append(chosen)
        selected_ids.add(int(chosen.get("_sourceIndex") or -1))
        if len(selected) >= target_count:
            break
    return selected, selected_ids


def select_demo_deck_items(
    source_items: list[dict[str, Any]],
    *,
    is_tutorial: bool,
    route_kind: str = "opinion",
    max_slides: int = 5,
    prefer_sequential: bool = False,
) -> tuple[list[dict[str, Any]], list[dict[str, Any]], str]:
    enriched = [
        {
            **item,
            "_deckRole": infer_demo_slide_role(item, index, is_tutorial=is_tutorial, route_kind=route_kind),
            "_keepScore": score_demo_deck_item(item, index, is_tutorial=is_tutorial),
            "_sourceIndex": index,
        }
        for index, item in enumerate(source_items)
    ]
    if enriched:
        current_roles = {str(item.get("_deckRole") or "") for item in enriched}
        if is_tutorial:
            if not any(demo_deck_role_matches_requirement(role, "入口") for role in current_roles):
                enriched[0]["_deckRole"] = "入口"
                enriched[0]["_forceDeckRole"] = "入口"
            current_roles = {str(item.get("_deckRole") or "") for item in enriched}
            if not any(demo_deck_role_matches_requirement(role, "操作") for role in current_roles):
                operation_index = 1 if len(enriched) > 2 else 0
                enriched[operation_index]["_deckRole"] = "操作"
                enriched[operation_index]["_forceDeckRole"] = "操作"
            current_roles = {str(item.get("_deckRole") or "") for item in enriched}
            if not any(demo_deck_role_matches_requirement(role, "验收") for role in current_roles):
                enriched[-1]["_deckRole"] = "验收"
                enriched[-1]["_forceDeckRole"] = "验收"
        elif route_kind == "interview":
            if not any(demo_deck_role_matches_requirement(role, "立场") for role in current_roles):
                enriched[0]["_deckRole"] = "立场"
                enriched[0]["_forceDeckRole"] = "立场"
            current_roles = {str(item.get("_deckRole") or "") for item in enriched}
            if not any(demo_deck_role_matches_requirement(role, "用户证据") for role in current_roles) and len(enriched) > 1:
                enriched[1]["_deckRole"] = "用户证据"
                enriched[1]["_forceDeckRole"] = "用户证据"
            current_roles = {str(item.get("_deckRole") or "") for item in enriched}
            if not any(demo_deck_role_matches_requirement(role, "结论") for role in current_roles):
                enriched[-1]["_deckRole"] = "结论"
                enriched[-1]["_forceDeckRole"] = "结论"
    target_count = min(max_slides, len(enriched))
    if len(source_items) <= max_slides:
        return enriched, [], build_demo_deck_spine(enriched, is_tutorial=is_tutorial, route_kind=route_kind)
    if prefer_sequential:
        selected = enriched[:target_count]
        selected_ids = {int(item.get("_sourceIndex") or -1) for item in selected}
        dropped = [
            {
                "timeLabel": str(item.get("timeLabel") or ""),
                "role": str(item.get("_deckRole") or ""),
                "reason": "顺序流程已保留，剩余细节放到时间线。",
            }
            for item in enriched
            if int(item.get("_sourceIndex") or -1) not in selected_ids
        ]
        return selected, dropped, build_demo_deck_spine(selected, is_tutorial=is_tutorial, route_kind=route_kind)
    required_roles = required_demo_deck_roles(route_kind, is_tutorial=is_tutorial)
    selected, selected_ids = select_demo_deck_items_by_required_roles(
        enriched,
        required_roles=required_roles,
        target_count=target_count,
    )
    if route_kind in {"opinion", "interview", "review", "demo"}:
        if len(selected) < target_count:
            for item in sorted(enriched, key=lambda current: (-int(current.get("_keepScore") or 0), int(current.get("_sourceIndex") or 0))):
                source_index = int(item.get("_sourceIndex") or -1)
                if source_index in selected_ids:
                    continue
                selected.append(item)
                selected_ids.add(source_index)
                if len(selected) >= target_count:
                    break
        selected = sorted(selected, key=lambda item: int(item.get("_sourceIndex") or 0))
        dropped = [
            {
                "timeLabel": str(item.get("timeLabel") or ""),
                "role": str(item.get("_deckRole") or ""),
                "reason": "和主线页面重复，放到时间线保留。",
            }
            for item in enriched
            if int(item.get("_sourceIndex") or -1) not in selected_ids
        ]
        return selected, dropped, build_demo_deck_spine(selected, is_tutorial=is_tutorial, route_kind=route_kind)

    selected_by_role: dict[str, dict[str, Any]] = {}
    for item in enriched:
        role = str(item.get("_deckRole") or "材料")
        current = selected_by_role.get(role)
        if current is None or int(item.get("_keepScore") or 0) > int(current.get("_keepScore") or 0):
            selected_by_role[role] = item

    selected = list(selected_by_role.values())
    if not any(int(item.get("_sourceIndex") or 0) == 0 for item in selected):
        selected.append(enriched[0])
    selected_ids = {int(item.get("_sourceIndex") or -1) for item in selected}
    if len(selected) < target_count:
        for item in sorted(enriched, key=lambda current: (-int(current.get("_keepScore") or 0), int(current.get("_sourceIndex") or 0))):
            source_index = int(item.get("_sourceIndex") or -1)
            if source_index in selected_ids:
                continue
            selected.append(item)
            selected_ids.add(source_index)
            if len(selected) >= target_count:
                break
    selected = sorted(selected, key=lambda item: (-int(item.get("_keepScore") or 0), int(item.get("_sourceIndex") or 0)))[:max_slides]
    selected = sorted(selected, key=lambda item: int(item.get("_sourceIndex") or 0))
    selected_ids = {int(item.get("_sourceIndex") or -1) for item in selected}
    dropped = [
        {
            "timeLabel": str(item.get("timeLabel") or ""),
            "role": str(item.get("_deckRole") or ""),
            "reason": "和已选页面角色重复，放到时间线保留。",
        }
        for item in enriched
        if int(item.get("_sourceIndex") or -1) not in selected_ids
    ]
    return selected, dropped, build_demo_deck_spine(selected, is_tutorial=is_tutorial, route_kind=route_kind)


def build_demo_deck_spine(slides_or_items: list[dict[str, Any]], *, is_tutorial: bool, route_kind: str = "opinion") -> str:
    roles = [str(item.get("role") or item.get("_deckRole") or "") for item in slides_or_items]
    if is_tutorial:
        if {"入口", "准备", "排错", "验收"}.intersection(roles):
            return "先交代卡点，再补准备条件，接着走排错，最后用结果验收。"
        return "先把入口说清楚，再顺着操作往下走，最后收成一套能照做的步骤。"
    if route_kind == "review":
        if {"场景", "功能", "结果", "门槛", "对比", "判断"}.intersection(roles):
            return "先说明适用场景，再跑核心功能，用结果和成本判断值不值得。"
        return "先还原真实使用，再把结果、门槛和选择标准讲清。"
    if route_kind == "demo":
        if {"场景", "设置", "验证", "限制", "判断"}.intersection(roles):
            return "先看使用场景，再把前提和结果走一遍，最后补上真正的门槛和判断。"
        return "先把这条演示放回真实场景，再决定它到底值不值得继续用。"
    if {"问题", "证据", "转折", "判断"}.intersection(roles):
        return "先把问题摆出来，再用证据和转折推进，最后落到一个可写判断。"
    return "先抓核心材料，再压成几页能讲清楚的材料。"


def recommended_demo_slide_limit(source_items: list[dict[str, Any]], *, is_tutorial: bool, route_kind: str = "opinion") -> int:
    if not source_items:
        return 3
    unique_frame_count = len({str(item.get("frameUrl") or "") for item in source_items if str(item.get("frameUrl") or "")})
    limit = min(6 if is_tutorial else 5, len(source_items))
    has_real_transcript = any(
        has_real_video_transcript_excerpt(str(item.get("transcriptExcerpt") or ""))
        for item in source_items
        if isinstance(item, dict)
    )
    if not has_real_transcript:
        limit = min(limit, 4)
    if route_kind in {"opinion", "interview"}:
        limit = min(limit, 4)
    if is_tutorial and has_real_transcript:
        if unique_frame_count >= 2:
            return min(limit, 5)
    if unique_frame_count <= 1:
        return min(limit, 3)
    if unique_frame_count == 2:
        return min(limit, 4 if is_tutorial else 3)
    if unique_frame_count == 3:
        return min(limit, 4 if has_real_transcript else 3)
    return limit


