            for field, limit in (
                ("action", 92),
                ("meaning", 92),
                ("speakerNote", 92),
                ("proof", 118),
                ("talkTrack", 92),
                ("audienceTakeaway", 92),
            ):
                value = normalize_space(str(slide.get(field) or ""))
