def infer_video_timeline_avoid(summary: str, transcript_text: str) -> str:
    text = f"{summary} {transcript_text}"
    if re.search(r"产品判断|未来|模型能力", text):
        return "不要写成“未来已来”这类空泛趋势句。"
    if re.search(r"终端|terminal|命令行|CLI", text, re.I):
        return "不要只说“界面不重要”，要说清为什么先选这个入口。"
    if re.search(r"git|bash|单测|测试|项目文件|团队记忆|工程任务", text, re.I):
        return "不要写成“提升效率”，要落到文件、命令、测试这些动作。"
    if re.search(r"上下文|门槛|开发者", text):
        return "不要把门槛说成玄学，要说明需要交出哪些项目上下文。"
    return "不要直接搬字幕，先改成一个有对象、有动作的判断。"


def strip_video_sentence_prefix(text: str, prefixes: list[str]) -> str:
    value = video_notes.compact_text(normalize_space(text), 140)
    for prefix in prefixes:
        if value.startswith(prefix):
            value = value[len(prefix) :].strip()
    return re.sub(r"[。；;]\s*$", "", value)


def codex_video_evidence_paragraph(payload: dict[str, Any]) -> dict[str, Any]:
    item = payload.get("timelineItem") if isinstance(payload.get("timelineItem"), dict) else payload
    angle = normalize_space(str(item.get("writingAngle") or "这段"))
    summary = normalize_space(str(item.get("summary") or ""))
    quote = strip_video_sentence_prefix(str(item.get("quoteCandidate") or summary), ["可引用："])
    value = strip_video_sentence_prefix(str(item.get("writingValue") or ""), ["可以写", "可以", "适合"])
    if "：" in value:
        value = value.split("：", 1)[1].strip() or value
    avoid = strip_video_sentence_prefix(str(item.get("avoidWriting") or ""), ["不要写成", "不要"])
    if not quote and not summary:
        raise ValueError("timelineItem requires quoteCandidate or summary")
    first = f"{quote or summary}。"
    second = f"重点是{value}。" if value else "先把谁在做、做了什么、结果怎样说清楚。"
    third = f"别写成{avoid}。" if avoid else ""
    if avoid.startswith(("把", "只", "直接")):
        third = f"别{avoid}。"
    paragraph = video_notes.compact_text(f"{angle}：{first}{second}{third}", 320)
    return {
        "status": "ok",
        "source": "codex-rule-backend",
        "paragraph": paragraph,
        "timeLabel": normalize_space(str(item.get("timeLabel") or "")),
        "writingAngle": angle,
    }


