def opinion_argument_templates(title: str, route_text: str = "") -> list[dict[str, str]]:
    combined = normalize_space(f"{title} {route_text}")
    if re.search(r"\binside\b.*\bwith\b|\bcreator\b|\binterview\b|\bfounder\b|访谈|对谈|专访|创始人|嘉宾", combined, re.I):
        return [
            {
                "role": "立场",
                "title": "先抓嘉宾的取舍",
                "pattern": r"founder|创始人|嘉宾|他说|她说|停止|stop|focus|聚焦|不做|取舍|选择",
                "summary": "先抓住嘉宾真正做出的取舍，而不是复述他讲了哪些功能。",
                "value": "访谈最有价值的不是信息量，而是说话的人在什么压力下选择了什么。",
                "quote": "先听他放弃了什么，再判断他为什么这么选。",
                "avoid": "不要把访谈写成嘉宾履历或功能清单。",
            },
            {
                "role": "用户证据",
                "title": "用户到底在意什么",
                "pattern": r"user|users|customer|customers|用户|客户|反馈|在意|care|留存|继续用|repeat",
                "summary": "把用户真正关心的结果单独拎出来。",
                "value": "这能证明判断不是嘉宾自说自话，而是来自真实使用压力。",
                "quote": "用户在意的不是功能多，而是今天能不能省下一步。",
                "avoid": "不要只写“用户反馈很好”，要写清他们到底在意什么。",
            },
            {
                "role": "成本",
                "title": "讲清被放弃的成本",
                "pattern": r"support cost|cost|成本|integration|integrations|集成|支持|维护|限制|代价|说不|no to",
                "summary": "把被放弃的功能、集成或增长动作背后的成本讲清楚。",
                "value": "这里让访谈从观点变成判断：每个选择都有维护成本。",
                "quote": "真正的产品判断，常常是知道什么先不做。",
                "avoid": "不要把取舍写成口号，要说清它省掉了什么成本。",
            },
            {
                "role": "结论",
                "title": "收成一个产品判断",
                "pattern": r"conclusion|maturity|成熟|default|defaults|默认|最后|结论|判断|fewer|less|可靠",
                "summary": "最后把访谈收成一个可复述的产品判断。",
                "value": "访谈材料最终要落到读者能带走的一句话。",
                "quote": "成熟不是按钮更多，而是默认更可靠。",
                "avoid": "不要用“很有启发”收尾，要给具体判断。",
            },
        ]
    return [
        {
            "role": "问题",
            "title": "先把问题摆出来",
            "pattern": r"问题|不是|不在|为什么|困境|误区|反而|越.+越|真正的问题",
            "summary": "先把这条视频要反驳或解释的问题说清楚。",
            "value": "观点视频不能先堆信息，必须先让观众知道争议在哪里。",
            "quote": "先说它在反驳什么，再说它相信什么。",
            "avoid": "不要开头就说“主要讲”，要把问题说具体。",
        },
        {
            "role": "证据",
            "title": "拿出支撑判断的证据",
            "pattern": r"证据|数据|案例|团队|用户|留下|试用|发现|观察|材料|事实",
            "summary": "把支撑判断的例子、数据或观察单独拎出来。",
            "value": "没有具体证据，观点拆解很容易变成一段空泛感想。",
            "quote": "判断要站住，先给一个可回看的证据。",
            "avoid": "不要只写观点，要给读者能核对的材料。",
        },
        {
            "role": "转折",
            "title": "讲清真正的转折",
            "pattern": r"但是|转折|反而|其实|限制|代价|成本|风险|问题在于|难点|卡住",
            "summary": "把表面现象和真正原因之间的转折讲出来。",
            "value": "这一页决定内容有没有洞察，而不是停在复述。",
            "quote": "真正的变化，往往藏在这个转折里。",
            "avoid": "不要写成二段式反转，要交代转折发生在哪里。",
        },
        {
            "role": "判断",
            "title": "最后落到一个判断",
            "pattern": r"所以|结论|判断|建议|我的判断|我觉得|门槛|标准|应该|最后",
            "summary": "最后把前面的材料收成一个读者能复述的明确判断。",
            "value": "观点视频的输出应该是一条可复述的判断，不是字幕摘要。",
            "quote": "最后要留下判断标准，不是留下热闹观点。",
            "avoid": "不要用“值得思考”收尾，要说清读者该怎么判断。",
        },
    ]


def build_opinion_argument_timeline(
    *,
    title: str,
    windows: list[list[dict[str, Any]]],
    frames: list[dict[str, Any]],
    video_embed: dict[str, Any],
    max_items: int,
) -> list[dict[str, Any]]:
    if not windows:
        return []
    window_texts = [
        normalize_space(" ".join(str(item.get("text") or "") for item in chunk))
        for chunk in windows
    ]
    selected: list[tuple[int, dict[str, str]]] = []
    used_windows: set[int] = set()
    route_text = " ".join(window_texts)
    for template in opinion_argument_templates(title, route_text):
        matches = [
            (index, text)
            for index, text in enumerate(window_texts)
            if index not in used_windows and re.search(template["pattern"], text, re.I)
        ]
        if not matches:
            continue
        chosen_index = matches[0][0]
        selected.append((chosen_index, template))
        used_windows.add(chosen_index)
        if len(selected) >= max_items:
            break
    eligible_backfill_indexes = [
        index
        for index, text in enumerate(window_texts)
        if index not in used_windows
        and (
            video_slide_has_raw_evidence(text, route_kind="opinion")
            or ascii_word_count(text) >= 8
            or cjk_char_count(text) >= 16
        )
    ]
    if len(selected) + len(eligible_backfill_indexes) < 3:
        return []
    target_count = min(max_items, max(4, len(selected))) if len(windows) >= 4 else min(max_items, len(windows))
    if len(selected) < target_count:
        for index in eligible_backfill_indexes:
            text = window_texts[index]
            if not video_slide_has_raw_evidence(text, route_kind="opinion") and ascii_word_count(text) < 8 and cjk_char_count(text) < 16:
                continue
            selected.append(
                (
                    index,
                    {
                        "role": "证据",
                        "title": infer_public_talk_slide_title(text, index)
                        if public_talk_video_context(f"{title} {text}")
                        else specific_video_material_title(text, role="证据", index=index, route_kind="interview")
                        or "补一条关键材料",
                        "summary": video_notes.compact_text(clean_video_sentence_head(text), 96),
                        "value": video_notes.compact_text(specific_video_slide_line(text, text, route_kind="interview", max_len=92) or text, 92),
                        "quote": video_notes.compact_text(clean_video_sentence_head(text), 72),
                        "avoid": "不要把这一段写成泛泛观点，要保留原话里的对象、动作或限制。",
                        "pattern": "",
                    },
                )
            )
            used_windows.add(index)
            if len(selected) >= target_count:
                break
    selected.sort(key=lambda pair: pair[0])
    timeline: list[dict[str, Any]] = []
    for source_index, template in selected[:max_items]:
        chunk = windows[source_index]
        start = float(chunk[0].get("start") or 0)
        last = chunk[-1]
        end = float(last.get("start") or start) + float(last.get("duration") or 0)
        frame = nearest_video_frame(frames, start)
        transcript_excerpt = video_notes.compact_text(
            clean_video_sentence_head(window_texts[source_index]) or template["summary"],
            118,
        )
        real_summary = specific_video_slide_line(
            transcript_excerpt,
            window_texts[source_index],
            route_kind="opinion",
            max_len=118,
        )
        timeline.append(
            {
                "start": start,
                "end": end,
                "timeLabel": video_notes.format_timestamp(start),
                "transcriptExcerpt": transcript_excerpt,
                "summary": real_summary or template["summary"],
                "writingValue": template["value"],
                "writingAngle": template["role"],
                "quoteCandidate": real_summary or transcript_excerpt or template["quote"],
                "avoidWriting": template["avoid"],
                "frameUrl": normalize_video_asset_url(str(frame.get("url") or "")) if frame else "",
                "frameLabel": frame.get("label") if frame else "",
                "watchAtUrl": build_video_watch_at_url(video_embed, start),
                "evidenceMode": "subtitle-led",
                "operationTitle": template["title"],
            }
        )
    return timeline


def build_video_timeline(
    *,
    result: dict[str, Any],
    info_payload: dict[str, Any],
    frames: list[dict[str, Any]],
    video_embed: dict[str, Any],
    window_seconds: int = 120,
    max_items: int = 8,
) -> list[dict[str, Any]]:
    segments = resolve_video_transcript_segments(result, info_payload)
    analysis = info_payload.get("analysis") or {}
    title = normalize_space(str(info_payload.get("title") or result.get("title") or ""))
    summary_candidates = [
        normalize_space(str(item))
        for key in ("content_outline", "talking_points", "repurpose_angles")
        for item in analysis.get(key) or []
        if normalize_space(str(item))
    ]
    if not summary_candidates and normalize_space(str(analysis.get("summary") or "")):
        summary_candidates.append(normalize_space(str(analysis.get("summary") or "")))
    if not segments:
        fallback_source = normalize_space(
            " ".join(
                str(value or "")
                for value in (
                    result.get("title"),
                    info_payload.get("description_preview") or info_payload.get("description"),
                    analysis.get("summary"),
                    analysis.get("core_claim"),
                )
            )
        )
        fallback_frames = frames[:max_items] if frames else []
        if not fallback_frames and video_embed.get("thumbnailUrl"):
            fallback_frames = [
                {
                    "timestamp": 0,
                    "label": "封面",
                    "url": str(video_embed.get("thumbnailUrl") or ""),
                }
            ]
        if not fallback_frames and not summary_candidates and not fallback_source:
            return []
        items = fallback_frames or [{"timestamp": 0, "label": "00:00", "url": ""}]
        timeline: list[dict[str, Any]] = []
        route_kind = classify_video_route_kind(title, fallback_source)
        is_tutorial = route_kind == "tutorial"
        for index, frame in enumerate(items[:max_items]):
            start = float(frame.get("timestamp") or index * window_seconds)
            visual_only_card = build_visual_only_timeline_card(index, route_kind, fallback_source, title)
            summary = visual_only_card.get("summary") or (
                summary_candidates[min(index, len(summary_candidates) - 1)]
                if summary_candidates
                else video_notes.compact_text(fallback_source, 120)
            )
            summary = summary or "这段没有拿到字幕，只能先按画面和视频描述整理。"
            transcript_excerpt = "未拿到字幕；先用截图、标题和描述做材料线索。"
            timeline.append(
                {
                    "start": start,
                    "end": start + window_seconds,
                    "timeLabel": video_notes.format_timestamp(start),
                    "transcriptExcerpt": transcript_excerpt,
                    "summary": video_notes.compact_text(summary, 130),
                    "writingValue": visual_only_card.get("writingValue") or "可以先按画面和标题写一个材料判断，但需要人工回看确认。",
                    "writingAngle": visual_only_card.get("writingAngle") or "画面线索",
                    "quoteCandidate": video_notes.compact_text(visual_only_card.get("quoteCandidate") or summary, 72),
                    "avoidWriting": "不要把这段当成逐字字幕；没有字幕时要标明需要回看核对。",
                    "frameUrl": normalize_video_asset_url(str(frame.get("url") or "")),
                    "frameLabel": frame.get("label") or video_notes.format_timestamp(start),
                    "watchAtUrl": build_video_watch_at_url(video_embed, start),
                    "evidenceMode": "visual-only",
                }
            )
        return timeline

    last_segment = segments[-1]
    total_end = float(last_segment.get("start") or 0) + float(last_segment.get("duration") or 0)
    route_preview = " ".join(str(item.get("text") or "") for item in segments[:8])
    route_kind = classify_video_route_kind(title, route_preview)
    is_tutorial = route_kind == "tutorial"
    is_caption_demo = route_kind == "demo" and looks_like_caption_demo(
        " ".join(str(item.get("text") or "") for item in segments[: min(len(segments), 80)])
    )
    min_window_seconds = (
        45
        if is_caption_demo
        else 50
        if route_kind == "review"
        else 75
        if is_tutorial
        else 60
        if route_kind in {"opinion", "interview"}
        else window_seconds
    )
    preview_notes = " ".join(str(item or "") for item in info_payload.get("transcript_notes") or [])
    is_short_preview = (
        len(segments) >= 24
        and total_end <= 180
        and re.search(r"preview|first-\d+s|前\s*\d+\s*秒", preview_notes, re.I)
    )
    if is_short_preview:
        target_windows = min(4, max_items, max(2, int(len(segments) / 12)))
        chapter_seconds = max(30, int(total_end / max(1, target_windows)) or 30)
    else:
        if is_caption_demo:
            target_windows = min(max_items, max(3, min(5, int(total_end / 45) + 1)))
            chapter_seconds = max(35, int(total_end / max(1, target_windows)) or 45)
        else:
            chapter_seconds = max(min_window_seconds, int(total_end / max(1, max_items)) or min_window_seconds)
    windows: list[list[dict[str, Any]]] = []
    current: list[dict[str, Any]] = []
    current_start = float(segments[0].get("start") or 0)
    for item in segments:
        start = float(item.get("start") or 0)
        if current and start - current_start >= chapter_seconds:
            windows.append(current)
            current = []
            current_start = start
        current.append(item)
    if current:
        windows.append(current)

    if is_tutorial:
        tutorial_templates = (
            tutorial_operation_templates()
            if connection_tutorial_context(f"{title} {route_preview}")
            else general_tool_tutorial_operation_templates(title)
        )
        operation_timeline = build_tutorial_operation_timeline(
            windows=windows,
            frames=frames,
            video_embed=video_embed,
            max_items=max_items,
            templates=tutorial_templates,
        )
        if operation_timeline:
            return operation_timeline
    if route_kind == "review":
        review_timeline = build_review_evaluation_timeline(
            windows=windows,
            frames=frames,
            video_embed=video_embed,
            max_items=max_items,
        )
        if review_timeline:
            return review_timeline
    if route_kind in {"opinion", "interview"}:
        opinion_timeline = build_opinion_argument_timeline(
            title=title,
            windows=windows,
            frames=frames,
            video_embed=video_embed,
            max_items=max_items,
        )
        if opinion_timeline:
            return opinion_timeline

    timeline: list[dict[str, Any]] = []
    for index, chunk in enumerate(windows[:max_items]):
        start = float(chunk[0].get("start") or 0)
        last = chunk[-1]
        end = float(last.get("start") or start) + float(last.get("duration") or 0)
        text = normalize_space(" ".join(str(item.get("text") or "") for item in chunk))
        frame = nearest_video_frame(frames, start)
        candidate_index = min(index, max(0, len(summary_candidates) - 1))
        summary_hint = usable_video_material_field(
            summary_candidates[candidate_index] if summary_candidates else "",
            role="summary",
        )
        if is_caption_demo:
            summary = caption_demo_chunk_summary(text, index)
        else:
            summary = summarize_video_timeline_chunk(
                summary_hint,
                text,
                index=index,
                is_tutorial=is_tutorial,
                route_kind=route_kind,
            )
        summary = video_notes.compact_text(summary, 130)
        timeline.append(
            {
                "start": start,
                "end": end,
                "timeLabel": video_notes.format_timestamp(start),
                "transcriptExcerpt": build_video_transcript_excerpt(text, index=index, is_tutorial=is_tutorial),
                "summary": summary,
                "writingValue": infer_video_timeline_writing_value(summary, text, index, route_kind=route_kind),
                "writingAngle": infer_video_timeline_angle(summary, text, index, route_kind=route_kind),
                "quoteCandidate": extract_video_timeline_quote(summary, text),
                "avoidWriting": infer_video_timeline_avoid(summary, text),
                "frameUrl": normalize_video_asset_url(str(frame.get("url") or "")) if frame else "",
                "frameLabel": frame.get("label") if frame else "",
                "watchAtUrl": build_video_watch_at_url(video_embed, start),
                "evidenceMode": "subtitle-led",
            }
        )
    return timeline


def enrich_video_job_result(job_id: str, result: dict[str, Any]) -> dict[str, Any]:
    json_path = str(result.get("json_path") or "")
    info_payload: dict[str, Any] = {}
    if json_path and Path(json_path).exists():
        try:
            info_payload = json.loads(Path(json_path).read_text(encoding="utf-8"))
        except Exception:
            info_payload = {}
    analysis = info_payload.get("analysis") or {}
    visual_assets = info_payload.get("visual_assets") or []
    frame_assets = discover_cached_video_frame_assets(info_payload, json_path)
    frames = [
        {
            "timestamp": asset.get("timestamp"),
            "label": video_notes.describe_visual_asset(asset),
            "path": asset.get("path"),
            "url": workspace_file_url(str(asset.get("path") or "")) if asset.get("path") else "",
        }
        for asset in frame_assets
        if isinstance(asset, dict) and asset.get("type") == "frame"
    ]
    video_embed = build_video_embed(result, info_payload, frames)
    transcript_segments = resolve_video_transcript_segments(result, info_payload)
    transcript_source = result.get("transcript_source") or info_payload.get("transcript_source") or "none"
    if not transcript_segments:
        transcript_source = "none"
    timeline = build_video_timeline(
        result=result,
        info_payload=info_payload,
        frames=frames,
        video_embed=video_embed,
    )
    timeline = localize_video_timeline_copy(
        title=normalize_space(str(info_payload.get("title") or result.get("title") or "这条视频")),
        timeline=timeline,
    )
    timeline = clean_public_video_timeline(timeline)
    video_summary = build_video_summary_card(
        result=result,
        info_payload=info_payload,
        analysis=analysis,
        timeline=timeline,
    )
    video_summary = localize_video_summary_copy(
        title=normalize_space(str(info_payload.get("title") or result.get("title") or "这条视频")),
        card=video_summary,
    )
    video_summary = ensure_video_summary_bullets(
        card=video_summary,
        result=result,
        info_payload=info_payload,
        analysis=analysis,
        timeline=timeline,
    )
    video_summary = clean_public_video_summary(video_summary)
    raw_core_claim = analysis.get("core_claim") or result.get("core_claim") or ""
    output_core_claim = effective_video_core_claim(str(raw_core_claim), video_summary)
    summary_angles = video_summary_angles(video_summary)
    output_analysis = dict(analysis)
    if output_core_claim:
        output_analysis["core_claim"] = output_core_claim
    raw_angles = [
        normalize_space(str(item))
        for item in analysis.get("repurpose_angles") or result.get("repurpose_angles") or []
        if normalize_space(str(item))
    ]
    usable_angles = [
        item
        for item in raw_angles
        if not low_signal_video_material_copy(item) and not generic_video_core_claim(item)
    ]
    output_analysis["repurpose_angles"] = (usable_angles or summary_angles)[:3]
    writing_cards = build_video_writing_cards(result, info_payload, output_analysis)
    writing_pack = build_video_writing_pack(
        result=result,
        info_payload=info_payload,
        analysis=output_analysis,
        timeline=timeline,
        writing_cards=writing_cards,
    )
    editorial = dict(output_analysis.get("editorial_decision") or {})
    if output_core_claim and generic_video_core_claim(str(editorial.get("brief") or "")):
        editorial["brief"] = ""
    if not editorial.get("brief"):
        bullets = "\n".join(f"- {item}" for item in video_summary.get("bullets") or [])
        editorial["brief"] = "\n".join(
            part
            for part in (
                f"题目：{info_payload.get('title') or result.get('title') or ''}",
                "",
                f"核心判断：{output_core_claim}" if output_core_claim else "",
                "",
                "可用材料：",
                bullets,
                "",
                f"写作落点：{video_summary.get('takeaway') or ''}",
            )
            if part is not None
        ).strip()
    output_analysis["editorial_decision"] = editorial
    source_info_payload = dict(info_payload)
    source_info_payload["analysis"] = output_analysis
    summary_key_points = [
        normalize_video_material_copy(str(item or ""), role="bullet")
        for item in video_summary.get("bullets") or []
        if normalize_video_material_copy(str(item or ""), role="bullet")
    ]
    if summary_key_points:
        source_info_payload["key_points"] = summary_key_points
    source_pack, source_pack_path = build_video_source_pack(result, source_info_payload)
    transcript_quality = assess_video_transcript_quality(
        transcript_source=transcript_source,
        transcript_segments=transcript_segments,
        timeline=timeline,
        visual_notes=info_payload.get("visual_notes") or [],
    )
    download_policy = info_payload.get("download_policy") if isinstance(info_payload.get("download_policy"), dict) else {}
    if not download_policy.get("status"):
        download_policy = infer_saved_download_policy_from_local_embed(
            video_embed,
            platform=str(info_payload.get("platform") or result.get("platform") or ""),
            required=True,
            auth=str(info_payload.get("auth") or ""),
        )
    demo_deck = build_video_demo_deck(
        title=normalize_space(str(info_payload.get("title") or result.get("title") or "这条视频")),
        video_summary=video_summary_with_frame_candidates(video_summary, frames),
        timeline=timeline,
        video_embed=video_embed,
        visual_notes=info_payload.get("visual_notes") or [],
        transcript_quality=transcript_quality,
    )
    demo_deck = clean_public_video_demo_deck(demo_deck)
    material_acceptance = build_video_material_acceptance(
        video_embed=video_embed,
        frames=frames,
        transcript_quality=transcript_quality,
        demo_deck=demo_deck,
        timeline=timeline,
    )
    material_state = build_video_material_state(
        video_embed=video_embed,
        frames=frames,
        transcript_quality=transcript_quality,
        demo_deck=demo_deck,
        timeline=timeline,
        download_policy=download_policy,
    )
    return {
        "auth": info_payload.get("auth") or "unknown",
        "platform": info_payload.get("platform") or "unknown",
        "downloadPolicy": download_policy,
        "transcriptSource": transcript_source,
        "transcriptSegments": transcript_segments,
        "transcriptQuality": transcript_quality,
        "materialAcceptance": material_acceptance,
        "materialState": material_state,
        "captionFiles": [Path(path).name for path in info_payload.get("caption_files") or []],
        "captionSelectionVersion": VIDEO_CAPTION_SELECTION_VERSION,
        "visualNotes": info_payload.get("visual_notes") or [],
        "transcriptNotes": info_payload.get("transcript_notes") or [],
        "coreClaim": output_core_claim,
        "videoSummary": video_summary,
        "videoSummaryVersion": VIDEO_SUMMARY_VERSION,
        "demoDeck": demo_deck,
        "demoDeckVersion": DEMO_DECK_VERSION,
        "angles": output_analysis.get("repurpose_angles") or [],
        "writingCards": writing_cards,
        "writingCardsVersion": 3,
        "writingPack": writing_pack,
        "writingPackVersion": 4,
        "videoTimelineVersion": VIDEO_TIMELINE_VERSION,
        "editorialDecision": editorial,
        "finalTake": result.get("final_take") or "",
        "frames": frames,
        "videoEmbed": video_embed,
        "timeline": timeline,
        "sourcePackMarkdown": source_pack,
        "sourcePackPath": source_pack_path,
        "sourcePackUrl": workspace_file_url(source_pack_path),
    }


def rebuild_video_job_summary(job_id: str, record: dict[str, Any]) -> dict[str, Any]:
    result = dict(record.get("result") or {})
    if record.get("url") and not result.get("url"):
        result["url"] = record.get("url")
    if record.get("title") and not result.get("title"):
        result["title"] = record.get("title")
    result_transcript_source = normalize_space(str(result.get("transcript_source") or ""))
    record_transcript_source = normalize_space(str(record.get("transcriptSource") or record.get("transcript_source") or ""))
    transcript_source = result_transcript_source or record_transcript_source
    if transcript_source and transcript_source != "none":
        result["transcript_source"] = transcript_source
        transcript_markdown = str(result.get("transcript_markdown") or record.get("transcriptMarkdown") or "")
        if transcript_markdown:
            result["transcript_markdown"] = transcript_markdown
    else:
        result.pop("transcript_source", None)
        result.pop("transcript_markdown", None)
        transcript_source = "none"
    existing_summary = record.get("summary") if isinstance(record.get("summary"), dict) else {}
    summary = preserve_local_video_material(existing_summary, enrich_video_job_result(job_id, result))
    notes = list(summary.get("transcriptNotes") or [])
    for note in existing_summary.get("transcriptNotes") or []:
        note_text = normalize_space(str(note))
        if note_text and note_text not in notes:
            notes.append(note_text)
    summary["transcriptNotes"] = notes
    if transcript_source and transcript_source != "none":
        summary["transcriptSource"] = transcript_source
    return summary


def launch_video_analysis_job(payload: dict[str, Any]) -> dict[str, Any]:
    url = normalize_space(str(payload.get("url", "")))
    if not url:
        raise ValueError("url is required")
    if not is_supported_video_analysis_url(url):
        raise ValueError("当前只支持 YouTube 和 B站链接。")
    tenant_id = normalize_video_analysis_tenant_id(payload.get("tenantId") or payload.get("ownerId") or DEFAULT_VIDEO_ANALYSIS_TENANT_ID)
    max_active_jobs = max(1, int(os.environ.get("MAX_ACTIVE_VIDEO_ANALYSIS_JOBS", str(DEFAULT_MAX_ACTIVE_VIDEO_ANALYSIS_JOBS))))
    active_jobs = active_video_analysis_job_ids()
    if len(active_jobs) >= max_active_jobs:
        raise VideoAnalysisCapacityError(f"当前已有 {len(active_jobs)} 个视频任务在处理，最多同时 {max_active_jobs} 个。等一个完成后再试。")

    analysis_backend = normalize_space(str(payload.get("analysisBackend", "rules"))) or "rules"
    if analysis_backend not in video_notes.SUPPORTED_RULES_BACKENDS:
        raise ValueError("unsupported analysis backend")

    try:
        requested_max_frames = int(payload.get("maxFrames") or 2)
    except (TypeError, ValueError):
        requested_max_frames = 2
    max_frames = max(1, min(requested_max_frames, MAX_VIDEO_ANALYSIS_FRAMES))
    try:
        requested_frame_interval = int(payload.get("frameIntervalSeconds") or 600)
    except (TypeError, ValueError):
        requested_frame_interval = 600
    frame_interval_seconds = max(30, min(requested_frame_interval, MAX_VIDEO_ANALYSIS_FRAME_INTERVAL_SECONDS))
    target_frame_seconds = [
        seconds
        for seconds in video_notes.normalize_target_frame_seconds(payload.get("targetFrameSeconds"), max_frames)
        if seconds <= MAX_VIDEO_ANALYSIS_FRAME_TARGET_SECONDS
    ][:max_frames]
    cookie_source = normalize_space(str(payload.get("cookiesFromBrowser") or payload.get("cookies_from_browser") or "none")).lower()
    if cookie_source in {"", "0", "false", "off", "no"}:
        cookie_source = "none"
    allowed_cookie_sources = {"none", "chrome", "chromium", "safari", "firefox", "edge", "brave", "opera", "vivaldi"}
    if cookie_source not in allowed_cookie_sources:
        raise ValueError("unsupported browser cookie source")

    job_id = f"video_{dt.datetime.now().strftime('%Y%m%d_%H%M%S')}_{uuid.uuid4().hex[:8]}"
    job_record: dict[str, Any] = {
        "id": job_id,
        "url": url,
        "tenantId": tenant_id,
        "ownerScope": "single-user-local" if tenant_id == DEFAULT_VIDEO_ANALYSIS_TENANT_ID else "named-local-tenant",
        "tenantIsolation": {
            "mode": "local-file-record",
            "publicSaasReady": False,
        },
        "status": "queued",
        "stage": "queued",
        "message": "等待开始",
        "createdAt": utc_now(),
        "updatedAt": utc_now(),
        "analysisBackend": analysis_backend,
        "extractFrames": True,
        "frameIntervalSeconds": frame_interval_seconds,
        "maxFrames": max_frames,
        "targetFrameSeconds": target_frame_seconds,
        "budgetPolicy": {
            "maxActiveJobs": max_active_jobs,
            "maxFrames": MAX_VIDEO_ANALYSIS_FRAMES,
            "maxFrameIntervalSeconds": MAX_VIDEO_ANALYSIS_FRAME_INTERVAL_SECONDS,
            "maxFrameTargetSeconds": MAX_VIDEO_ANALYSIS_FRAME_TARGET_SECONDS,
            "timeoutSeconds": DEFAULT_VIDEO_ANALYSIS_JOB_TIMEOUT_SECONDS,
            "requiresLocalVideoWhenRequested": True,
        },
        "qualityRefetch": bool(payload.get("qualityRefetch", False)),
        "requireLocalVideo": bool(payload.get("requireLocalVideo", False)),
        "disableVideoParser": bool(payload.get("disableVideoParser", False)),
        "disableWhisperFallback": bool(payload.get("disableWhisperFallback", False)),
        "includeComments": bool(payload.get("includeComments", False)),
        "skipRewrites": bool(payload.get("skipRewrites", False)),
        "cookiesFromBrowser": cookie_source,
        "events": [],
    }
    if job_record["requireLocalVideo"]:
        previous = previous_complete_video_job_for_url(url, job_id)
        if previous and not should_refresh_cached_video_transcript(previous, cookie_source):
            try:
                cached_record = build_cached_video_job_record_from_previous(
                    job_record,
                    previous,
                    reason="同一链接已有本地视频缓存",
                    cookies_from_browser=cookie_source,
                    message="已使用本地缓存",
                    event_message="提交时命中本地缓存",
                )
                write_video_job(job_id, cached_record)
                return read_video_job(job_id)
            except Exception:
                pass
        elif previous:
            job_record["cacheRefreshReason"] = "同一链接已有缓存，但旧字幕需要刷新；本次带登录态重新取字幕。"
    write_video_job(job_id, job_record)

    def run() -> None:
        def update(stage: str, message: str, extra: dict[str, Any] | None = None) -> None:
            current = read_video_job(job_id)
            event = {"at": utc_now(), "stage": stage, "message": message, "extra": extra or {}}
            current["status"] = "running"
            current["stage"] = stage
            current["message"] = message
            current["updatedAt"] = utc_now()
            current.setdefault("events", []).append(event)
            if extra:
                for key, value in extra.items():
                    current[key] = value
            write_video_job(job_id, current)

        try:
            update("fetch", "开始抓取视频资料")
            args = SimpleNamespace(
                output_dir=str(video_notes.DEFAULT_OUTPUT),
                langs="zh.*,zh-Hans,zh-Hant,zh,en.*",
                cookies_file=None,
                cookies_from_browser=str(job_record.get("cookiesFromBrowser") or "none"),
                disable_video_parser=bool(job_record.get("disableVideoParser", False)),
                disable_whisper_fallback=bool(job_record.get("disableWhisperFallback", False)),
                disable_transcript_fallbacks=False,
                include_comments=bool(job_record.get("includeComments", False)),
                analysis_backend=job_record.get("analysisBackend", "rules"),
                extract_frames=True,
                frame_interval_seconds=int(job_record.get("frameIntervalSeconds") or 600),
                max_frames=int(job_record.get("maxFrames") or 2),
                target_frame_seconds=job_record.get("targetFrameSeconds") or "",
                require_local_video=bool(job_record.get("requireLocalVideo", False)),
                skip_rewrites=bool(job_record.get("skipRewrites", False)),
            )
            result = video_notes.process_url(args, url, progress_callback=update)
            enriched = enrich_video_job_result(job_id, result)
            if bool(job_record.get("qualityRefetch", False)):
                deck = enriched.get("demoDeck") if isinstance(enriched.get("demoDeck"), dict) else {}
                evidence = deck.get("evidenceStatus") if isinstance(deck.get("evidenceStatus"), dict) else {}
                if evidence.get("frameExtractionFailed"):
                    previous = previous_complete_video_job_for_url(url, job_id)
                    previous_summary = previous.get("summary") if isinstance(previous, dict) and isinstance(previous.get("summary"), dict) else {}
                    previous_timeline = previous_summary.get("timeline") if isinstance(previous_summary.get("timeline"), list) else []
                    previous_video_summary = previous_summary.get("videoSummary") if isinstance(previous_summary.get("videoSummary"), dict) else {}
                    previous_video_embed = previous_summary.get("videoEmbed") if isinstance(previous_summary.get("videoEmbed"), dict) else {}
                    if previous_timeline and previous_video_summary and previous_video_embed:
                        failed_visual_notes = enriched.get("visualNotes") or []
                        fallback_deck = build_video_demo_deck(
                            title=normalize_space(
                                str(
                                    previous_video_summary.get("headline")
                                    or previous.get("result", {}).get("title")
                                    or result.get("title")
                                    or "这条视频"
                                )
                            ),
                            video_summary=video_summary_with_frame_candidates(previous_video_summary, previous_summary.get("frames")),
                            timeline=previous_timeline,
                            video_embed=previous_video_embed,
                            visual_notes=failed_visual_notes,
                            transcript_quality=previous_summary.get("transcriptQuality") if isinstance(previous_summary.get("transcriptQuality"), dict) else {},
                        )
                        enriched = {
                            **previous_summary,
                            "visualNotes": failed_visual_notes,
                            "transcriptNotes": enriched.get("transcriptNotes") or previous_summary.get("transcriptNotes") or [],
                            "demoDeck": fallback_deck,
                            "demoDeckVersion": DEMO_DECK_VERSION,
                            "frameRefetchFallbackJobId": previous.get("id"),
                            "frameRefetchFailed": True,
                        }
            final = read_video_job(job_id)
            final["status"] = "done"
            final["stage"] = "done"
            final["message"] = "分析完成"
            final["updatedAt"] = utc_now()
            final["result"] = result
            final["files"] = extract_job_result_files(result)
            if enriched.get("sourcePackPath"):
                final["files"]["source_pack_path"] = enriched["sourcePackPath"]
            final["summary"] = enriched
            note_path = result.get("note_path")
            rewrites_path = result.get("rewrites_path")
            transcript_md_path = result.get("transcript_md_path")
            if note_path:
                final["noteMarkdown"] = read_text_file_if_exists(str(note_path))
            if transcript_md_path:
                final["transcriptMarkdown"] = read_text_file_if_exists(str(transcript_md_path))
            if rewrites_path:
                final["rewritesMarkdown"] = read_text_file_if_exists(str(rewrites_path))
            final = apply_cached_video_transcript_fallback(job_id, final)
            final["summary"] = rebuild_video_job_summary(job_id, final)
            final = apply_cached_video_evidence_fallback(job_id, final)
            final_summary = final.get("summary") if isinstance(final.get("summary"), dict) else {}
            if bool(job_record.get("requireLocalVideo", False)):
                require_local_video_embed(final_summary)
            normalize_required_video_source_status(final_summary)
            final["summary"] = final_summary
            final["transcriptSource"] = final["summary"].get("transcriptSource") or final.get("transcriptSource")
            final["transcript_source"] = final["transcriptSource"] or final.get("transcript_source")
            final["timeline"] = final["summary"].get("timeline") or final.get("timeline") or []
            write_video_job(job_id, final)
        except Exception as exc:
            previous = previous_complete_video_job_for_url(url, job_id)
            if (
                bool(job_record.get("requireLocalVideo", False))
                and previous
                and not should_refresh_cached_video_transcript(previous, str(job_record.get("cookiesFromBrowser") or ""))
            ):
                try:
                    cached = build_cached_video_job_record_from_previous(
                        read_video_job(job_id),
                        previous,
                        reason=str(exc),
                        cookies_from_browser=str(job_record.get("cookiesFromBrowser") or ""),
                        event_message=f"下载失败，已复用本地缓存：{str(exc)[:180]}",
                    )
                    write_video_job(job_id, cached)
                    return
                except Exception:
                    pass
            failed = read_video_job(job_id)
            public_message = public_video_job_error_message(exc)
            debug_message = debug_exception_message(exc)
            failed["status"] = "error"
            failed["stage"] = "error"
            failed["message"] = public_message
            failed["error"] = debug_message
            failed["failure"] = build_video_failure_diagnosis(
                url=url,
                message=public_message,
                error=debug_message,
                cookies_from_browser=str(failed.get("cookiesFromBrowser") or ""),
            )
            failed["updatedAt"] = utc_now()
            failed.setdefault("events", []).append({"at": utc_now(), "stage": "error", "message": public_message, "extra": {"detail": debug_message}})
            write_video_job(job_id, failed)

    threading.Thread(target=run, daemon=True).start()
    return read_video_job(job_id)


def document_path(document_id: str) -> Path:
    safe_id = slugify(document_id, fallback=f"doc-{uuid.uuid4().hex[:8]}")
    return DOCUMENT_DIR / f"{safe_id}.json"


def topic_archive_path(topic_id: str) -> Path:
    safe_id = slugify(topic_id, fallback=f"topic-{uuid.uuid4().hex[:8]}")
    return TOPIC_ARCHIVE_DIR / f"{safe_id}.json"


TOPIC_ARCHIVE_PLACEHOLDER_TITLES = {"主稿", "正文", "未命名稿件", "当前主题稿"}
TOPIC_ARCHIVE_PLACEHOLDER_TEXTS = {"主稿", "正文", "主稿\n\n正文", "未命名稿件", ""}


def is_placeholder_topic_archive_snapshot(entry: dict[str, Any]) -> bool:
    title = normalize_space(str(entry.get("title", "")))
    text = normalize_space(str(entry.get("contentText", "")))
    return title in TOPIC_ARCHIVE_PLACEHOLDER_TITLES and (
        text in TOPIC_ARCHIVE_PLACEHOLDER_TEXTS or len(text) <= 12
    )


def current_document_title(topic_id: str) -> str:
    doc_path = document_path(topic_id)
    if not doc_path.exists():
        return ""
    try:
        record = json.loads(doc_path.read_text(encoding="utf-8"))
    except Exception:
        return ""
    title = normalize_space(str(record.get("title", "")))
    return "" if title in TOPIC_ARCHIVE_PLACEHOLDER_TITLES else title


def best_topic_archive_title(topic_id: str, archive: dict[str, Any]) -> str:
    current_title = current_document_title(topic_id)
    if current_title:
        return current_title
    for entry in archive.get("entries", []):
        title = normalize_space(str(entry.get("title", "")))
        if title and title not in TOPIC_ARCHIVE_PLACEHOLDER_TITLES:
            return title
    title = normalize_space(str(archive.get("title", "")))
    if title and title not in TOPIC_ARCHIVE_PLACEHOLDER_TITLES:
        return title
    return "当前主题稿"


def clean_topic_archive_entries(entries: list[Any]) -> list[dict[str, Any]]:
    cleaned: list[dict[str, Any]] = []
    seen: set[tuple[str, str]] = set()
    def sort_key(entry: dict[str, Any]) -> tuple[int, float]:
        current_rank = 1 if str(entry.get("changeSummary", "")) == "当前保存版" else 0
        raw_value = str(entry.get("updatedAt", ""))
        try:
            parsed = dt.datetime.fromisoformat(raw_value)
            timestamp = parsed.timestamp()
        except Exception:
            timestamp = 0.0
        return (current_rank, timestamp)

    for raw_entry in sorted(entries, key=lambda item: sort_key(item) if isinstance(item, dict) else "", reverse=True):
        if not isinstance(raw_entry, dict):
            continue
        if is_placeholder_topic_archive_snapshot(raw_entry):
            continue
        title = normalize_space(str(raw_entry.get("title", "")))
        text = normalize_space(str(raw_entry.get("contentText", "")))
        key = (title, text)
        if key in seen:
            continue
        seen.add(key)
        cleaned.append(raw_entry)
        if len(cleaned) >= TOPIC_ARCHIVE_LIMIT:
            break
    return cleaned


def document_record_to_archive_entry(topic_id: str, record: dict[str, Any], *, source_path: Path, current: bool = False) -> dict[str, Any]:
    content_text = resolved_record_content_text(record)
    title = normalize_space(str(record.get("title", ""))) or "未命名稿件"
    updated_at = str(record.get("updated_at", "") or record.get("created_at", "") or utc_now())
    return {
        "archiveId": f"document_{source_path.stem}",
        "documentId": topic_id,
        "title": title,
        "updatedAt": updated_at,
        "contentHtml": str(record.get("content_html", "")).strip(),
        "contentText": content_text,
        "charCount": len(content_text),
        "changeSummary": "当前保存版" if current else f"备份：{source_path.name.split('.before_', 1)[-1].removesuffix('.json')[:42]}",
        "styleProofSummary": record.get("style_proof_summary")
        or build_topic_archive_style_snapshot(record.get("style_proof")),
    }


def related_document_archive_entries(topic_id: str) -> list[dict[str, Any]]:
    entries: list[dict[str, Any]] = []
    current_path = document_path(topic_id)
    candidate_paths = []
    if current_path.exists():
        candidate_paths.append((current_path, True))
    safe_id = slugify(topic_id, fallback=topic_id)
    for path in sorted(DOCUMENT_DIR.glob(f"{safe_id}.before_*.json")):
        candidate_paths.append((path, False))
    for path, current in candidate_paths:
        try:
            record = json.loads(path.read_text(encoding="utf-8"))
        except Exception:
            continue
        if normalize_space(str(record.get("document_id", topic_id))) != topic_id:
            continue
        entry = document_record_to_archive_entry(topic_id, record, source_path=path, current=current)
        if not is_placeholder_topic_archive_snapshot(entry):
            entries.append(entry)
    return entries


def summarize_topic_archive_change(previous_text: str, current_text: str) -> str:
    previous = normalize_space(previous_text)
    current = normalize_space(current_text)
    if not previous:
        return "首次存档"
    if previous == current:
        return "内容未变化"

    old_paragraphs = [normalize_space(item) for item in previous_text.splitlines() if normalize_space(item)]
    new_paragraphs = [normalize_space(item) for item in current_text.splitlines() if normalize_space(item)]
    old_set = set(old_paragraphs)
    for paragraph in new_paragraphs:
        if paragraph not in old_set:
            return f"新增/修改：{paragraph[:90]}"

    delta = len(current) - len(previous)
    if delta > 0:
        return f"正文增加 {delta} 字"
    if delta < 0:
        return f"正文减少 {abs(delta)} 字"
    return "正文有局部调整"


def build_topic_archive_style_snapshot(style_proof: dict[str, Any] | None) -> dict[str, Any]:
    if not isinstance(style_proof, dict):
        return {}
    counts = style_proof.get("memoryCounts") if isinstance(style_proof.get("memoryCounts"), dict) else {}
    focus = style_proof.get("focus") if isinstance(style_proof.get("focus"), dict) else {}
    effectiveness = style_proof.get("effectiveness") if isinstance(style_proof.get("effectiveness"), dict) else {}
    used_count = int(counts.get("usedThisRun") or counts.get("related") or 0)
    banned_count = int(counts.get("currentBannedFindings") or 0)
    summary_line = f"偏好未生效 · 引用 {used_count} / 踩禁 {banned_count}" if banned_count > 0 else f"偏好 {used_count} / 踩禁 0"
    approval_line = normalize_space(str(focus.get("approvalLine", "")))
    rewrite_line = normalize_space(str(focus.get("rewriteLine", "")))
    rule_family_line = normalize_space(str(focus.get("ruleFamilyLine", "")))
    hard_ban_line = normalize_space(str(focus.get("hardBanLine", "")))
    approval_patterns = focus.get("approvalPatterns") if isinstance(focus.get("approvalPatterns"), list) else []
    rewrite_moves = focus.get("rewriteMoves") if isinstance(focus.get("rewriteMoves"), list) else []
    focus_parts: list[str] = []
    if approval_patterns:
        approval_labels = [normalize_space(str(item.get("label", ""))) for item in approval_patterns[:2] if isinstance(item, dict)]
        approval_labels = [item for item in approval_labels if item]
        if approval_labels:
            focus_parts.append(f"喜欢：{' / '.join(approval_labels)}")
    elif approval_line and approval_line != "暂无稳定喜欢模式。":
        focus_parts.append(f"喜欢：{approval_line}")
    if rewrite_moves:
        rewrite_labels = [normalize_space(str(item.get("label", ""))) for item in rewrite_moves[:2] if isinstance(item, dict)]
        rewrite_labels = [item for item in rewrite_labels if item]
        if rewrite_labels:
            focus_parts.append(f"改法：{' / '.join(rewrite_labels)}")
    elif rewrite_line and rewrite_line != "暂无稳定改法。":
        focus_parts.append(f"改法：{rewrite_line}")
    if not focus_parts and rule_family_line and rule_family_line != "暂无沉淀规则。":
        focus_parts.append(f"规则：{rule_family_line}")
    if not focus_parts and hard_ban_line and hard_ban_line != "暂无稳定硬禁结构。":
        focus_parts.append(f"避开：{hard_ban_line}")
    return {
        "status": normalize_space(str(style_proof.get("status", ""))) or "unknown",
        "summaryLine": summary_line,
        "focusLine": " · ".join(focus_parts[:2]),
        "usedThisRun": used_count,
        "currentBannedFindings": banned_count,
        "effectLabel": normalize_space(str(effectiveness.get("label", ""))),
    }


def load_topic_archive(topic_id: str) -> dict[str, Any]:
    ensure_document_dirs()
    path = topic_archive_path(topic_id)
    if not path.exists():
        doc_path = document_path(topic_id)
        if doc_path.exists():
            try:
                record = json.loads(doc_path.read_text(encoding="utf-8"))
                content_text = resolved_record_content_text(record)
                title = normalize_space(str(record.get("title", ""))) or "未命名稿件"
                entry = {
                    "archiveId": f"archive_initial_{uuid.uuid4().hex[:6]}",
                    "documentId": topic_id,
                    "title": title,
                    "updatedAt": record.get("updated_at", utc_now()),
                    "contentHtml": str(record.get("content_html", "")).strip(),
                    "contentText": content_text,
                    "charCount": len(content_text),
                    "changeSummary": "当前保存版",
                    "styleProofSummary": record.get("style_proof_summary")
                    or build_topic_archive_style_snapshot(record.get("style_proof")),
                }
                archive = {
                    "topicId": topic_id,
                    "documentId": topic_id,
                    "title": title,
                    "updatedAt": entry["updatedAt"],
                    "entries": [entry],
                    "path": str(path),
                }
                path.write_text(json.dumps(archive, ensure_ascii=False, indent=2) + "\n", encoding="utf-8")
                return archive
            except Exception:
                pass
        return {"topicId": topic_id, "entries": [], "path": str(path)}
    try:
        archive = json.loads(path.read_text(encoding="utf-8"))
    except Exception:
        archive = {"topicId": topic_id, "entries": []}
    archive["topicId"] = normalize_space(str(archive.get("topicId", topic_id))) or topic_id
    archive["entries"] = clean_topic_archive_entries(
        [*list(archive.get("entries", [])), *related_document_archive_entries(topic_id)]
    )
    archive["title"] = best_topic_archive_title(topic_id, archive)
    archive["documentId"] = topic_id
    archive["path"] = str(path)
    return archive


def append_topic_archive_snapshot(record: dict[str, Any]) -> dict[str, Any]:
    topic_id = normalize_space(str(record.get("document_id", ""))) or slugify(str(record.get("title", "")), fallback=f"topic-{uuid.uuid4().hex[:8]}")
    archive = load_topic_archive(topic_id)
    entries = list(archive.get("entries", []))
    content_text = resolved_record_content_text(record)
    content_html = str(record.get("content_html", "")).strip()
    title = normalize_space(str(record.get("title", ""))) or "未命名稿件"
    if is_placeholder_topic_archive_snapshot({"title": title, "contentText": content_text}):
        return archive
    newest = entries[0] if entries else {}
    latest_style_summary = record.get("style_proof_summary") or build_topic_archive_style_snapshot(record.get("style_proof"))
    if (
        normalize_space(str(newest.get("contentText", ""))) == normalize_space(content_text)
        and normalize_space(str(newest.get("title", ""))) == title
    ):
        if latest_style_summary and newest.get("styleProofSummary") != latest_style_summary:
            refreshed_entry = dict(newest)
            refreshed_entry["styleProofSummary"] = latest_style_summary
            refreshed_entry["updatedAt"] = record.get("updated_at", refreshed_entry.get("updatedAt", utc_now()))
            archive = {
                "topicId": topic_id,
                "documentId": topic_id,
                "title": title,
                "updatedAt": refreshed_entry["updatedAt"],
                "entries": [refreshed_entry, *entries[1:]][:TOPIC_ARCHIVE_LIMIT],
            }
            path = topic_archive_path(topic_id)
            path.write_text(json.dumps(archive, ensure_ascii=False, indent=2) + "\n", encoding="utf-8")
            archive["path"] = str(path)
        return archive
    entry = {
        "archiveId": f"archive_{dt.datetime.now().strftime('%Y%m%d_%H%M%S')}_{uuid.uuid4().hex[:6]}",
        "documentId": topic_id,
        "title": title,
        "updatedAt": record.get("updated_at", utc_now()),
        "contentHtml": content_html,
        "contentText": content_text,
        "charCount": len(content_text),
        "changeSummary": summarize_topic_archive_change(str(newest.get("contentText", "")), content_text),
        "styleProofSummary": latest_style_summary,
    }
    archive = {
        "topicId": topic_id,
        "documentId": topic_id,
        "title": title,
        "updatedAt": entry["updatedAt"],
        "entries": [entry, *entries][:TOPIC_ARCHIVE_LIMIT],
    }
    path = topic_archive_path(topic_id)
    path.write_text(json.dumps(archive, ensure_ascii=False, indent=2) + "\n", encoding="utf-8")
    archive["path"] = str(path)
    return archive


