def normalize_document_type(value: str) -> str:
    lowered = normalize_space(value).lower()
    if lowered in FORMAL_DOCUMENT_TYPE_ALIASES:
        return DOCUMENT_TYPE_FORMAL
    if lowered in EXPERIMENT_DOCUMENT_TYPE_ALIASES:
        return DOCUMENT_TYPE_EXPERIMENT
    return ""


def document_type_label(document_type: str) -> str:
    normalized = normalize_document_type(document_type)
    if normalized == DOCUMENT_TYPE_EXPERIMENT:
        return "实验稿"
    return "正式稿"


def infer_document_type(document_id: str, title: str, existing_type: str = "") -> str:
    normalized_existing = normalize_document_type(existing_type)
    if normalized_existing:
        return normalized_existing
    haystack = f"{document_id} {title}".lower()
    if any(keyword in haystack for keyword in EXPERIMENT_DOCUMENT_KEYWORDS):
        return DOCUMENT_TYPE_EXPERIMENT
    if any(keyword in haystack for keyword in FORMAL_DOCUMENT_KEYWORDS):
        return DOCUMENT_TYPE_FORMAL
    return DOCUMENT_TYPE_FORMAL


def resolved_record_content_text(record: dict[str, Any]) -> str:
    stored_text = str(record.get("content_text", "")).strip()
    content_html = str(record.get("content_html", "")).strip()
    if not content_html:
        return stored_text
    rebuilt_text = html_to_text(content_html).strip()
    if not rebuilt_text:
        return stored_text
    stored_blocks = [block for block in re.split(r"\n\s*\n", stored_text) if normalize_space(block)]
    rebuilt_blocks = [block for block in re.split(r"\n\s*\n", rebuilt_text) if normalize_space(block)]
    stored_lines = [line for line in stored_text.splitlines() if normalize_space(line)]
    rebuilt_lines = [line for line in rebuilt_text.splitlines() if normalize_space(line)]
    if (
        not stored_text
        or len(rebuilt_blocks) > len(stored_blocks)
        or len(rebuilt_lines) > len(stored_lines)
    ):
        return rebuilt_text
    return stored_text


def public_document_record(record: dict[str, Any], fallback_document_id: str, path: Path) -> dict[str, Any]:
    document_id = record.get("document_id", fallback_document_id)
    title = record.get("title", "未命名稿件")
    document_type = infer_document_type(document_id, title, str(record.get("document_type", "")))
    content_text = resolved_record_content_text(record)
    metadata = record.get("metadata")
    if not isinstance(metadata, dict):
        metadata = {}
    return {
        "documentId": document_id,
        "title": title,
        "contentHtml": record.get("content_html", ""),
        "contentText": content_text,
        "updatedAt": record.get("updated_at", ""),
        "createdAt": record.get("created_at", ""),
        "documentType": document_type,
        "documentTypeLabel": document_type_label(document_type),
        "metadata": metadata,
        "path": str(path),
        "obsidian": topic_descriptor(str(document_id)),
    }


def canonical_topic_title(title: str) -> str:
    normalized = normalize_space(str(title or ""))
    normalized = re.sub(r"[。.!！?？]+$", "", normalized).strip()
    if not normalized:
        return ""
    if "｜" in normalized or "|" in normalized:
        base = re.split(r"[｜|]", normalized, maxsplit=1)[0].strip()
        if len(base) >= 8:
            return base
    return normalized


def document_topic_group_key(public: dict[str, Any]) -> str:
    title_key = canonical_topic_title(str(public.get("title", "")))
    if title_key:
        return title_key.lower()
    return normalize_space(str(public.get("documentId", ""))).lower()


def collapse_document_topics(records: list[dict[str, Any]]) -> list[dict[str, Any]]:
    grouped: dict[str, dict[str, Any]] = {}
    counts: dict[str, int] = {}
    for item in records:
        key = document_topic_group_key(item)
        if not key:
            key = str(item.get("documentId", ""))
        counts[key] = counts.get(key, 0) + 1
        existing = grouped.get(key)
        if existing is None or str(item.get("updatedAt", "")) > str(existing.get("updatedAt", "")):
            grouped[key] = dict(item)
    collapsed: list[dict[str, Any]] = []
    for key, item in grouped.items():
        version_count = counts.get(key, 1)
        item["topicGroupKey"] = key
        item["topicVersionCount"] = version_count
        item["collapsedTopic"] = version_count > 1
        collapsed.append(item)
    collapsed.sort(key=lambda item: item.get("updatedAt", ""), reverse=True)
    collapsed.sort(key=lambda item: item.get("documentType") != DOCUMENT_TYPE_FORMAL)
    return collapsed


def html_to_text(html: str) -> str:
    text = re.sub(r"<br\s*/?>", "\n", html, flags=re.I)
    text = re.sub(r"</(p|div|h1|h2|h3|h4|li)>", "\n", text, flags=re.I)
    text = re.sub(r"<li[^>]*>", "• ", text, flags=re.I)
    text = re.sub(r"<[^>]+>", "", text)
    text = text.replace("&nbsp;", " ")
    text = re.sub(r"\n{3,}", "\n\n", text)
    return text.strip()


def html_to_markdown(html: str) -> str:
    markdown = html
    replacements = [
        (r"<h1[^>]*>(.*?)</h1>", r"# \1\n\n"),
        (r"<h2[^>]*>(.*?)</h2>", r"## \1\n\n"),
        (r"<h3[^>]*>(.*?)</h3>", r"### \1\n\n"),
        (r"<p[^>]*>(.*?)</p>", r"\1\n\n"),
        (r"<div[^>]*>(.*?)</div>", r"\1\n\n"),
        (r"<strong[^>]*>(.*?)</strong>", r"**\1**"),
        (r"<b[^>]*>(.*?)</b>", r"**\1**"),
        (r"<em[^>]*>(.*?)</em>", r"*\1*"),
        (r"<i[^>]*>(.*?)</i>", r"*\1*"),
        (r"<li[^>]*>(.*?)</li>", r"- \1\n"),
        (r"<ul[^>]*>", ""),
        (r"</ul>", "\n"),
        (r"<ol[^>]*>", ""),
        (r"</ol>", "\n"),
        (r"<br\s*/?>", "\n"),
    ]
    for pattern, replacement in replacements:
        markdown = re.sub(pattern, replacement, markdown, flags=re.I | re.S)
    markdown = re.sub(r"<[^>]+>", "", markdown)
    markdown = markdown.replace("&nbsp;", " ")
    markdown = re.sub(r"\n{3,}", "\n\n", markdown)
    return markdown.strip() + "\n"


def text_to_markdown(text: str) -> str:
    body = str(text or "").strip()
    return f"{body}\n" if body else ""


def build_obsidian_version_entries(entries: list[dict[str, Any]]) -> list[dict[str, Any]]:
    rendered: list[dict[str, Any]] = []
    for entry in entries:
        content_html = str(entry.get("contentHtml", "")).strip()
        content_text = str(entry.get("contentText", "")).strip()
        rendered.append(
            {
                "archiveId": str(entry.get("archiveId", "")).strip(),
                "title": str(entry.get("title", "")).strip(),
                "updatedAt": str(entry.get("updatedAt", "")).strip(),
                "changeSummary": str(entry.get("changeSummary", "")).strip(),
                "charCount": int(entry.get("charCount") or 0),
                "styleProofSummary": entry.get("styleProofSummary") if isinstance(entry.get("styleProofSummary"), dict) else {},
                "contentMarkdown": html_to_markdown(content_html) if content_html else text_to_markdown(content_text),
            }
        )
    return rendered


def sync_saved_document_to_obsidian(record: dict[str, Any], archive: dict[str, Any]) -> dict[str, str]:
    return sync_topic_document(
        topic_id=str(record.get("document_id", "")).strip(),
        title=normalize_space(str(record.get("title", ""))) or "未命名稿件",
        document_type_label=document_type_label(str(record.get("document_type", ""))),
        updated_at=str(record.get("updated_at", "")).strip() or utc_now(),
        workspace_document_path=str(document_path(str(record.get("document_id", "")))),
        topic_archive_path=str(archive.get("path", "")),
        content_markdown=html_to_markdown(str(record.get("content_html", "")).strip())
        if str(record.get("content_html", "")).strip()
        else text_to_markdown(str(record.get("content_text", ""))),
        version_entries=build_obsidian_version_entries(list(archive.get("entries", []))),
    )


def sync_document_id_to_obsidian(document_id: str) -> dict[str, str]:
    doc_path = document_path(document_id)
    if not doc_path.exists():
        raise FileNotFoundError(f"document not found: {document_id}")
    record = json.loads(doc_path.read_text(encoding="utf-8"))
    archive = load_topic_archive(document_id)
    return sync_saved_document_to_obsidian(record, archive)


def article_text_to_html(title: str, body: str) -> str:
    parts: list[str] = [f"<h2>{html.escape(normalize_space(title) or '未命名稿件')}</h2>"]
    for block in re.split(r"\n\s*\n", body.strip()):
        paragraph = normalize_space(block.replace("\n", " "))
        if not paragraph:
            continue
        parts.append(f"<p>{html.escape(paragraph)}</p>")
    return "\n".join(parts)


