    replace_exact("维护一次，规则能复用一百次。", "维护一次，后面的稿子就能继续调用同一条规则。", "移除无来源复用次数。")
    replace_regex(r"确认[\"“”]?四十分钟[\"“”]?有内部测试记录支撑，?没编[。！？!?；;]?", "只检查候选有没有使用材料外的说法。", "移除无来源内部测试记录。")
    replace_regex(r"[^。！？!?；;\n]{0,30}(语气|声音|话|说法)[^。！？!?；;\n]{0,20}(变重|很重|说得很重|沉重)[^。！？!?；;\n]{0,40}[。！？!?；;]?", "", "移除空泛语气旁白。")
