            ("key-points", ("第一", "第二", "一个", "两个", "关键", "论点", "发现", "观点"), "缺可复述的关键点"),
            ("boundary", ("不能推出", "边界", "局限", "样本", "口径", "不能说明", "不等于"), "缺材料边界或不能推出什么"),
            ("reader-meaning", ("普通人", "你", "我们", "使用", "观察", "判断", "焦虑", "行动"), "缺和读者有关的后果"),
            ("author-choice", ("我的判断", "我会", "我更", "该重视", "先别", "不必", "取舍"), "缺作者取舍"),
